-- Poems batch 406
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-172','卜算子','向子諲','宋','宋词','song-ci','卜算子','[]','胶胶扰扰中，本体元来静。',52,'宋词/ci.song.2000.json','["胶胶扰扰中，本体元来静。", "一段澄明绝点埃，世事如泡影。", "歇即是菩提，此语须三省。", "古道无人著脚行，禾黍秋风冷。"]'),
('song-ci-173','水调歌头','刘望之','宋','宋词','song-ci','水调歌头','[]','劝子一杯酒，清泪不须流。',114,'宋词/ci.song.2000.json','["劝子一杯酒，清泪不须流。", "人间千古，俯仰如梦说扬州。", "何况楚王台畔，为雨为云无限，人事付轻沤。", "聚散随来去，天地有虚舟。", "谪仙人，解金龟，换美酒。", "载与君游，流水曲觞且赓酬。", "麾盖飞迎过霭，江滨响振歌喉，拚醉又何求。", "三万六千日，日日此优游。"]'),
('song-ci-174','渔父词・渔父','法常','宋','宋词','song-ci','渔父词・渔父','[]','此事楞严常露布。',72,'宋词/ci.song.2000.json','["此事楞严常露布。", "梅华雪月交光处。", "一笑寥寥空万古。", "风瓯语。", "迥然银汉横天宇。", "蝶梦南华方栩栩。", "斑斑谁跨丰干虎。", "而今忘却来时路。", "江山暮。", "天涯目送鸿飞去。"]'),
('song-ci-175','念奴娇','陆淞','宋','宋词','song-ci','念奴娇','[]','黄橙紫蟹，映金壶潋滟，新醅浮绿。',120,'宋词/ci.song.2000.json','["黄橙紫蟹，映金壶潋滟，新醅浮绿。", "共赏西楼今夜月，极目云无一粟。", "挥麈高谈，倚栏长啸，下视鳞鳞屋。", "轰然何处，瑞龙声喷蕲竹。", "何况露白风清，银河澈汉，仿佛如悬瀑。", "此景古今如有价，岂惜明珠千斛。", "灏气盈襟，冷风入袖，只欲骑鸿鹄。", "广寒宫殿，看人颜似冰玉。"]'),
('song-ci-176','瑞鹤仙','陆淞','宋','宋词','song-ci','瑞鹤仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','脸霞红印枕。',127,'宋词/ci.song.2000.json','["脸霞红印枕。", "睡觉来、冠儿还是不整。", "屏间麝煤冷。", "但眉峰压翠，泪珠弹粉。", "堂深昼永。", "燕交飞、风帘露井。", "恨无人，与说相思，近日带围宽尽。", "重省。", "残灯朱幌，淡月纱窗，那时风景。", "阳台路迥。", "云雨梦，便无准。", "待归来，先指花梢教看，却把心期细问。", "问因循、过了青春，怎生意稳。"]'),
('song-ci-177','卜算子','卓世清','宋','宋词','song-ci','卜算子','[]','流水一湾西。',52,'宋词/ci.song.2000.json','["流水一湾西。", "晚坐孤亭静。", "不见高人跨鹤归，风竹摇清影。", "往古与来今，休用重重省。", "十里梅花雪正晴，月挂遥山冷。"]'),
('song-ci-178','浣溪沙','李结','宋','宋词','song-ci','浣溪沙','[]','花圃萦回曲径通。',48,'宋词/ci.song.2000.json','["花圃萦回曲径通。", "小亭风卷绣帘重。", "秋千闲倚画桥东。", "双蝶舞馀红便旋，交莺啼处绿葱珑。", "远山眉黛晚来浓。"]'),
('song-ci-179','西江月','李结','宋','宋词','song-ci','西江月','[]','若将花卉论行藏。',15,'宋词/ci.song.2000.json','["若将花卉论行藏。", "盍在凌烟阁上。"]'),
('song-ci-180','水调歌头','向滈','宋','宋词','song-ci','水调歌头','[]','短棹舣湍石，华月满汀洲。',114,'宋词/ci.song.2000.json','["短棹舣湍石，华月满汀洲。", "应知孤客无寐，特地照离忧。", "谁念姮娥单枕，寂寞广寒宫殿，亦自□□□。", "□□□□□，□□□□□。", "□怜我，尘满袖，雪盈头。", "两乡千里萦恨，何事不归休。", "遥想闺中今夜，夜久寒生玉臂，犹自倚高楼。", "别泪入湘水，归梦绕鄜州。"]'),
('song-ci-181','念奴娇','向','宋','宋词','song-ci','念奴娇','[]','霜威凄紧，政悲风摇落，千山群木。',120,'宋词/ci.song.2000.json','["霜威凄紧，政悲风摇落，千山群木。", "十里清香方盛赏，岩桂娇黄姹绿。", "九畹衰丛，东篱落蕊，到此成粗俗。", "孤标高远，淡然还媚幽独。", "憔悴诗老多情，问佳人底事，幽居空谷。", "日暮天寒垂翠袖，愁倚萧萧修竹。", "林下神情，月边风露，不向雕栏曲。", "殷勤惟有，篆烟留得馀馥。"]'),
('song-ci-182','满庭芳','向','宋','宋词','song-ci','满庭芳','[]','玉粉匀梅，曲尘浮柳，画檐迟日融融。',118,'宋词/ci.song.2000.json','["玉粉匀梅，曲尘浮柳，画檐迟日融融。", "金猊喷麝，庭户转香风。", "好是闲居戏彩，寿觞举、和满春容。", "须知道，闺门孕秀，佳气在帘栊。", "无穷。", "观盛事，年年此会，拚醉金锺。", "又何须、西池高宴仙宫。", "尽把乔松□寿，兼大国、秦虢重封。", "那堪更，门阑多喜，女婿近乘龙。"]'),
('song-ci-183','青玉案','向','宋','宋词','song-ci','青玉案','[]','别时抆泪花无语。',80,'宋词/ci.song.2000.json','["别时抆泪花无语。", "但一味、教郎住。", "此日扁舟游远浦。", "雨晴云树。", "月斜烟树。", "目断家何许。", "红笺不寄相思句。", "人在潇湘雁回处。", "屈指归期秋已暮。", "万千里路。", "两三头绪。", "恨不飞将去。"]'),
('song-ci-184','青玉案','向','宋','宋词','song-ci','青玉案','[]','多情赋得相思分。',84,'宋词/ci.song.2000.json','["多情赋得相思分。", "便揽断、愁和闷。", "万种千般说不尽。", "吃他圈柜，被他拖逗，便佛也、须教恨。", "传消寄息无凭信。", "水远山遥怎生奔。", "梦也而今难得近。", "伊还知道，为伊成病，便死也、谁能问。"]'),
('song-ci-185','小重山','向','宋','宋词','song-ci','小重山','[]','翡翠林梢青黛山。',70,'宋词/ci.song.2000.json','["翡翠林梢青黛山。", "小楼新罨画，卷珠帘。", "碧纱窗外水挪蓝。", "凭栏处，相对玉纤纤。", "人散酒阑珊。", "夜长都睡皱，唾花衫。", "一弯残月下风檐。", "凌波去，罗袜步蹁跹。"]'),
('song-ci-186','踏莎行','向','宋','宋词','song-ci','踏莎行','["\u94b1\u5858\u6c5f"]','万水千山，两头三绪。',68,'宋词/ci.song.2000.json','["万水千山，两头三绪。", "凭高望断迢迢路。", "钱塘江上客归迟，落花流水青春暮。", "步步金莲，朝朝琼树。", "目前都是伤心处。", "飞鸿过尽没书来，梦魂依旧阳台雨。"]'),
('song-ci-187','蝶恋花','向','宋','宋词','song-ci','蝶恋花','[]','费尽东君无限巧。',70,'宋词/ci.song.2000.json','["费尽东君无限巧。", "玉减香销，回首令人老。", "梦绕岭头归未到。", "角声吹断江天晓。", "燕子来时春正好。", "寸寸柔肠，休问愁多少。", "从此欢心还草草。", "凭栏一任桃花笑。"]'),
('song-ci-188','临江仙','向','宋','宋词','song-ci','临江仙','[]','瘦损东阳缘底事，离愁别恨难禁。',70,'宋词/ci.song.2000.json','["瘦损东阳缘底事，离愁别恨难禁。", "夜长谁共拥孤衾。", "来时青鬓在，今已二毛侵。", "流水青山依旧是，兰桡往事空寻。", "一番风雨又春深。", "桃花都落尽，赢得是清阴。"]'),
('song-ci-189','临江仙','向','宋','宋词','song-ci','临江仙','[]','乱后此身何计是，翠微深处柴扉。',70,'宋词/ci.song.2000.json','["乱后此身何计是，翠微深处柴扉。", "即今双鬓已如丝。", "虚名将底用，真意在鸱夷。", "治国无谋归去好，衡门犹可栖迟。", "不妨沈醉典春衣。", "人生行乐耳，须富贵何时。"]'),
('song-ci-190','武陵春','向','宋','宋词','song-ci','武陵春','[]','长记酒醒人散后，风月满江楼。',56,'宋词/ci.song.2000.json','["长记酒醒人散后，风月满江楼。", "楼外烟波万顷秋。", "高槛冷飕飕。", "想见云鬟香雾湿，斜坠玉搔头。", "两处相思一样愁。", "休更照鄜州。"]'),
('song-ci-191','阮郎归','向','宋','宋词','song-ci','阮郎归','[]','隔篱疏影照横塘。',56,'宋词/ci.song.2000.json','["隔篱疏影照横塘。", "东风吹暗香。", "陇头归路指苍茫。", "江南春兴长。", "扃小院，静回廊。", "有人凭短墙。", "角声惊梦月横窗。", "此时能断肠。"]'),
('song-ci-192','南乡子','向','宋','宋词','song-ci','南乡子','[]','临水窗儿。',64,'宋词/ci.song.2000.json','["临水窗儿。", "与卷珠帘看画眉。", "雨浴红衣惊起后，争知。", "水远山长各自飞。", "受尽孤凄。", "极目风烟说与谁。", "直是为他憔悴损，寻思。", "怎得心肠一似伊。"]'),
('song-ci-193','西江月','向','宋','宋词','song-ci','西江月','[]','流水断桥衰草，西风落日清笳。',58,'宋词/ci.song.2000.json','["流水断桥衰草，西风落日清笳。", "往来赢得鬓边华。", "此去征鞍休跨。", "烟溆绿深陂筱，霜篱红老江花。", "青山尽处是侬家。", "拟唤渔舟东下。"]'),
('song-ci-194','西江月','向','宋','宋词','song-ci','西江月','[]','门柳疏疏映日，井桐策策翻秋。',58,'宋词/ci.song.2000.json','["门柳疏疏映日，井桐策策翻秋。", "萧条不似那时游。", "只有山光依旧。", "别久犹牵去梦，怀多还惹新愁。", "吹箫人在雁回州。", "不管沈郎消瘦。"]'),
('song-ci-195','西江月','向','宋','宋词','song-ci','西江月','[]','竹寺青灯永夜，江城黄叶高秋。',58,'宋词/ci.song.2000.json','["竹寺青灯永夜，江城黄叶高秋。", "当时文物尽交游。", "更为笛声怀旧。", "牢落一生羁思，风流万斛诗愁。", "强邀从事到青州。", "酒病绵绵越瘦。"]'),
('song-ci-196','西江月','向','宋','宋词','song-ci','西江月','[]','抵死漫生要见，偷方觅便求欢。',58,'宋词/ci.song.2000.json','["抵死漫生要见，偷方觅便求欢。", "十分赢得带围宽。", "划地如今难恋。", "枕畔水沈烟尽，床头银蜡烧残。", "鸳衾不觉夜深寒。", "记取有人肠断。"]'),
('song-ci-197','西江月','向','宋','宋词','song-ci','西江月','[]','别后千思万想，眼前一日三秋。',58,'宋词/ci.song.2000.json','["别后千思万想，眼前一日三秋。", "小街栏槛记追游。", "料得新妆依旧。", "自笑非常蒂殢，为他无限闲愁。", "莫将离恨寄鄜州。", "闻道腰肢愈瘦。"]'),
('song-ci-198','虞美人','向','宋','宋词','song-ci','虞美人','[]','酒阑敧枕新凉夜。',66,'宋词/ci.song.2000.json','["酒阑敧枕新凉夜。", "断尽人肠也。", "西风吹起许多愁。", "不道沈腰潘鬓、不禁秋。", "如今病也无人管。", "真个难消遣。", "东邻一笑直千金。", "争奈茂陵情分、在文君。"]'),
('song-ci-199','虞美人','向','宋','宋词','song-ci','虞美人','[]','宝梳半脱文窗里。',66,'宋词/ci.song.2000.json','["宝梳半脱文窗里。", "玉软因谁醉。", "锦鸳应是懒熏香。", "□我水村孤酌、减疏狂。", "此时纵有千金笑。", "情味如伊少。", "带围宽尽莫教知。", "嫌怕为侬成病、似前时。"]'),
('song-ci-200','南歌子','向','宋','宋词','song-ci','南歌子','[]','路尽湘江水，人行瘴雾间。',62,'宋词/ci.song.2000.json','["路尽湘江水，人行瘴雾间。", "昏昏西日度严关。", "天外一簪初见、岭南山。", "北雁连书断，新霜点鬓斑。", "此时休问几时还。", "准拟桂林佳处、过春残。"]'),
('song-ci-201','点绛唇','向','宋','宋词','song-ci','点绛唇','[]','屈指新冬，肃霜天气重阳后。',50,'宋词/ci.song.2000.json','["屈指新冬，肃霜天气重阳后。", "授衣时候。", "兰菊香盈袖。", "此日生申，维岳锺神秀。", "倾名酎。", "篆添金兽。", "共祝如椿寿。"]'),
('song-ci-202','减字木兰花','向','宋','宋词','song-ci','减字木兰花','[]','多情被恼。',52,'宋词/ci.song.2000.json','["多情被恼。", "枉了东君无限巧。", "真个愁人。", "一片轻飞减却春。", "阑干凭暖。", "目断彩云肠也断。", "两岸青山。", "隐隐孤舟浪接天。"]'),
('song-ci-203','朝中措','向','宋','宋词','song-ci','朝中措','[]','平生此地几经过。',57,'宋词/ci.song.2000.json','["平生此地几经过。", "家近奈情何。", "长记月斜风劲，小舟犹渡烟波。", "而今老大，欢消意减，只有愁多。", "不似旧时心性，夜长听彻渔歌。"]'),
('song-ci-204','忆秦娥','向','宋','宋词','song-ci','忆秦娥','[]','秋萧索。',56,'宋词/ci.song.2000.json','["秋萧索。", "别来先自情怀恶。", "情怀恶。", "日斜庭院，月明帘幕。", "轻离却似於人薄。", "而今休更思量著。", "思量著。", "肝肠空断，水云辽邈。"]'),
('song-ci-205','摊破丑奴儿・采桑子','向滈','宋','宋词','song-ci','摊破丑奴儿・采桑子','[]','自笑好痴迷。',82,'宋词/ci.song.2000.json','["自笑好痴迷。", "只为俺、忒�沙�儿。", "近来都得傍人道，帖儿上面，言儿语子，那底都是虚脾。", "楼上等多时。", "两地里、人马都饥。", "低低说与当直底，轿儿抬转，喝声靠里，看俺麽、裸而归。"]'),
('song-ci-206','好事近','向','宋','宋词','song-ci','好事近','[]','清晓渡横江，江上月寒霜白。',53,'宋词/ci.song.2000.json','["清晓渡横江，江上月寒霜白。", "寂寞断桥南畔，有一枝春色。", "玉肌孤瘦恰如伊，此际转相忆。", "且道这些烦恼，看几时休得。"]'),
('song-ci-207','点绛唇','向','宋','宋词','song-ci','点绛唇','[]','蕙怨兰愁，玉台羞对啼妆面。',50,'宋词/ci.song.2000.json','["蕙怨兰愁，玉台羞对啼妆面。", "懒匀香脸。", "不放眉峰展。", "幽恨谁知，锦字空传远。", "何时见。", "为郎肠断。", "不似郎情浅。"]'),
('song-ci-208','阮郎归','向','宋','宋词','song-ci','阮郎归','[]','湘南楼上好凭栏。',56,'宋词/ci.song.2000.json','["湘南楼上好凭栏。", "西风吹鼻酸。", "宦游何处不惊湍。", "白鸥盟已寒。", "空饮恨，废追欢。", "沈郎衣带宽。", "故人休放酒杯乾。", "而今行路难。"]'),
('song-ci-209','如梦令','向','宋','宋词','song-ci','如梦令','[]','旧恨新愁无际。',40,'宋词/ci.song.2000.json','["旧恨新愁无际。", "近水远山都是。", "西北有高楼，正为行藏独倚。", "留滞。", "留滞。", "家在吴头楚尾。"]'),
('song-ci-210','如梦令','向','宋','宋词','song-ci','如梦令','[]','梦断绿窗莺语。',40,'宋词/ci.song.2000.json','["梦断绿窗莺语。", "消遣客愁无处。", "小槛俯青郊，恨满楚江南路。", "归去。", "归去。", "花落一川烟雨。"]'),
('song-ci-211','如梦令','向','宋','宋词','song-ci','如梦令','[]','直面雨轻风峭。',40,'宋词/ci.song.2000.json','["直面雨轻风峭。", "极目水空烟渺。", "家在武陵溪，无限壑讥峰诮。", "归好。", "归好。", "睡足一江春晓。"]'),
('song-ci-212','如梦令','向滈','宋','宋词','song-ci','如梦令','[]','楼上千峰翠巘。',40,'宋词/ci.song.2000.json','["楼上千峰翠巘。", "楼下一湾清浅。", "宝簟酒醒时，枕上月华如练。", "留恋。", "留恋。", "明日水村烟岸。"]'),
('song-ci-213','如梦令','向','宋','宋词','song-ci','如梦令','[]','杨柳千丝万缕。',40,'宋词/ci.song.2000.json','["杨柳千丝万缕。", "特地织成愁绪。", "休更唱阳关，便是渭城西路。", "归去。", "归去。", "红杏一腮春雨。"]'),
('song-ci-214','如梦令','向','宋','宋词','song-ci','如梦令','[]','野店几杯空酒。',40,'宋词/ci.song.2000.json','["野店几杯空酒。", "醉里两眉长皱。", "已自不成眠，那更酒醒时候。", "知否。", "知否。", "直是为他消瘦。"]'),
('song-ci-215','如梦令','向滈','宋','宋词','song-ci','如梦令','[]','谁伴明窗独坐。',40,'宋词/ci.song.2000.json','["谁伴明窗独坐。", "和我影儿两个。", "灯烬欲眠时，影也把人抛躲。", "无那。", "无那。", "好个恓惶的我。"]'),
('song-ci-216','如梦令','向','宋','宋词','song-ci','如梦令','[]','厮守许多时价。',40,'宋词/ci.song.2000.json','["厮守许多时价。", "谁信一筹不画。", "相送到矾园，赢得泪珠如泻。", "挥洒。", "挥洒。", "将底江州司马。"]'),
('song-ci-217','长相思','向','宋','宋词','song-ci','长相思','[]','桃花堤。',44,'宋词/ci.song.2000.json','["桃花堤。", "柳花堤。", "芳草桥边花满溪。", "而今戎马嘶。", "千山西。", "万山西。", "归雁横云落日低。", "登楼望欲迷。"]'),
('song-ci-218','长相思','向','宋','宋词','song-ci','长相思','[]','行相思。',44,'宋词/ci.song.2000.json','["行相思。", "坐相思。", "两处相思各自知。", "相思更为谁。", "朝相思。", "暮相思。", "一日相思十二时。", "相思无尽期。"]'),
('song-ci-219','菩萨蛮','向','宋','宋词','song-ci','菩萨蛮','[]','小楼不放珠帘卷。',52,'宋词/ci.song.2000.json','["小楼不放珠帘卷。", "菱花羞照啼妆面。", "金鸭水沈烟。", "待君来共添。", "鹊声生暗喜。", "翠袖轮纤指。", "细细数归程。", "脸桃春色深。"]'),
('song-ci-220','菩萨蛮','向滈','宋','宋词','song-ci','菩萨蛮','[]','云屏月帐孤鸾恨。',52,'宋词/ci.song.2000.json','["云屏月帐孤鸾恨。", "香消玉减无人问。", "斜倚碧琅玕。", "萧萧生暮寒。", "低垂双翠袖。", "袖薄轻寒透。", "庭院欲黄昏。", "凝情空断魂。"]'),
('song-ci-221','清平乐','向','宋','宋词','song-ci','清平乐','[]','离愁万斛。',54,'宋词/ci.song.2000.json','["离愁万斛。", "春思难拘束。", "瘦尽玉肌清彻骨。", "蹙损两眉秀绿。", "画屏罗幌输君。", "文鳞锦翼尤勤。", "长记酒醒香冷，笑将髻子隈人。"]'),
('song-ci-222','卜算子','向','宋','宋词','song-ci','卜算子','[]','休逞一灵心，争甚闲言语。',52,'宋词/ci.song.2000.json','["休逞一灵心，争甚闲言语。", "十一年间并枕时，没个牵情处。", "四岁学言儿，七岁娇痴女。", "说与傍人也断肠，你自思量取。"]'),
('song-ci-223','念奴娇','程大昌','宋','宋词','song-ci','念奴娇','[]','冰容玉格，笑桃杏、非是闺帏装束。',121,'宋词/ci.song.2000.json','["冰容玉格，笑桃杏、非是闺帏装束。", "待要舒华那更管，朔气凝波僵木。", "五鬣山松，万年宫树，仅仅存馀绿。", "一枝寄赠，教渠知道春复。", "宁解车马成蹊，高标宜雪月，仍便溪谷。", "纵有知闻，谁办得、驾野凌寒秉烛。", "尽更荒闲，终难掩抑，风里香千斛。", "林坰兴尽，此时鼎味翻足。"]'),
('song-ci-224','浣溪沙','程大昌','宋','宋词','song-ci','浣溪沙','[]','乾处缁尘湿处泥。',48,'宋词/ci.song.2000.json','["乾处缁尘湿处泥。", "天嫌世路净无时。", "皓然岩谷总凝脂。", "清夜月明人访戴，玉山顶上玉舟移。", "一蓑渔画更能奇。"]'),
('song-ci-225','浣溪沙','程大昌','宋','宋词','song-ci','浣溪沙','[]','兽炭香红漫应时。',48,'宋词/ci.song.2000.json','["兽炭香红漫应时。", "遮寒姝丽自成围。", "销金暖帐四边垂。", "报道黑风飞柳絮，齐翻白雪侑羔卮。", "那家斟唱□□词。"]'),
('song-ci-226','浣溪沙','程大昌','宋','宋词','song-ci','浣溪沙','[]','翦水飞花也大奇。',48,'宋词/ci.song.2000.json','["翦水飞花也大奇。", "熬波出素料同机。", "会心一笑撒盐诗。", "谁拥醴酏夸岁瑞，恨无坚白怨朝曦。", "闭门高卧有人饥。"]'),
('song-ci-227','浣溪沙','程大昌','宋','宋词','song-ci','浣溪沙','[]','始待空冬岁不华。',48,'宋词/ci.song.2000.json','["始待空冬岁不华。", "还教呈瑞怨贫家。", "若为高下总无嗟。", "日照华檐晴后雨，风吹飞絮腊前花。", "天公何事不由他。"]'),
('song-ci-228','浣溪沙','程大昌','宋','宋词','song-ci','浣溪沙','[]','水递迢迢到日边。',48,'宋词/ci.song.2000.json','["水递迢迢到日边。", "清甘夸说与茶便。", "谁知绝品了非泉。", "旋挹天花融湩液，净无土脉污芳鲜。", "乞君风腋作飞仙。"]'),
('song-ci-229','万年欢','程大昌','宋','宋词','song-ci','万年欢','[]','岁岁梅花，向寿尊画阁，长报春起。',123,'宋词/ci.song.2000.json','["岁岁梅花，向寿尊画阁，长报春起。", "恰似今朝，分外香肥萼韡。", "杂佩珊珊就列，映蓝袂、宝薰擎跽。", "道这回、屋舍团栾，四时风月桃李。", "回头处、无限思。", "看秋前药裹，而今鼎匕。", "须把康强，收作玳筵欢喜。", "况是鬓云全绿，顶珈笄、笑陪星履。", "新年动、定拥新祺，有孙来捧醪醴。"]'),
('song-ci-230','汉宫春','程大昌','宋','宋词','song-ci','汉宫春','[]','万六千年，是仙椿日月，两度阳春。',118,'宋词/ci.song.2000.json','["万六千年，是仙椿日月，两度阳春。", "根柯不随物化，那有新陈。", "戏夸悠久，借时光、惊觉时人。", "道历管，阶蓂万换，悠然唤做逡巡。", "老我百无贪羡，羡天芳寿种，掩冉三辰。", "谢他流年甲子，已是重轮。", "人间春狭，只九旬、斗柄标寅。", "更拟向，椿枝倚数，十分取一为真。"]'),
('song-ci-231','好事近','程大昌','宋','宋词','song-ci','好事近','[]','日绎五千言，未说年龄可续。',53,'宋词/ci.song.2000.json','["日绎五千言，未说年龄可续。", "且得襟期萧散，远氛嚣宠辱。", "鬓须白尽秀眉生，来伴老眸绿。", "人道雪霜林里，有翠松鲜竹。"]'),
('song-ci-232','减字木兰花','程大昌','宋','宋词','song-ci','减字木兰花','[]','距春五日。',52,'宋词/ci.song.2000.json','["距春五日。", "吉语搀先来饮席。", "易卦占新。", "八八周轮又再轮。", "开年定好。", "定把笙歌更药裹。", "旧怕无孙。", "今已蓝袍拥绣荪。"]'),
('song-ci-233','卜算子','程大昌','宋','宋词','song-ci','卜算子','[]','春产不贪春，为厌春花泛。',52,'宋词/ci.song.2000.json','["春产不贪春，为厌春花泛。", "睡到深秋梦始回，素影翻春艳。", "意赏逐时新，旧事谁能占。", "解转春光入酒杯，萸菊谁云欠。"]'),
('song-ci-234','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','七十在前头，难言未老。',81,'宋词/ci.song.2000.json','["七十在前头，难言未老。", "只是中间有些好。", "鬒云虽瘦，未有一根华皓。", "都缘心地静，无忧恼。", "此际生朝，梅花献笑。", "似向天边得新报。", "孙枝秀雅，已挂恩袍春草。", "定从欢喜处，添年考。"]'),
('song-ci-235','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','池馆足名花，四时蔫馥。',81,'宋词/ci.song.2000.json','["池馆足名花，四时蔫馥。", "就里梅春春到速。", "周遭松竹，任是雪霜长绿。", "总堪供寿乐，翻新曲。", "别向心田，有般奇木。", "依约灵椿共标目。", "八千换历，才当一番春复。", "莫乱春起处，醅浮玉。"]'),
('song-ci-236','万年欢','程大昌','宋','宋词','song-ci','万年欢','[]','富寿康宁，要三般齐足，方是有福。',122,'宋词/ci.song.2000.json','["富寿康宁，要三般齐足，方是有福。", "献个新词，不是越夸搀祝。", "七十古稀今独。", "花钗底、髻云堆绿。", "那堪更、眼力过人，彩丝穿透珠曲。", "星辰履阶庭玉。", "对这般景趣，乐胜笙筑。", "更原孙枝衮衮，诜诜续续。", "解把诗书勤读。", "新丹桂、会生旧竹。", "十年外、又颂生朝，恁时别换腔局。"]'),
('song-ci-237','韵令','程大昌','宋','宋词','song-ci','韵令','[]','是男是女，都有官称。',94,'宋词/ci.song.2000.json','["是男是女，都有官称。", "孙儿仕也登。", "时新衣著，不待经营。", "寒时火柜，春里花亭。", "星辰上履，我只唤卿卿。", "寿开八秩，两鬓全青。", "颜红步武轻。", "定知前面，大有年龄。", "芝兰玉树，更愿充庭。", "为询王母，桃颗几时赪。"]'),
('song-ci-238','折丹桂','程大昌','宋','宋词','song-ci','折丹桂','[]','童年未晓君恩重。',60,'宋词/ci.song.2000.json','["童年未晓君恩重。", "教得能趋拱。", "重亲带笑酌天杯，听祝语、殷勤捧。", "青衫得挂尤光宠。", "桂是蟾宫种。", "诗书浓处便生枝，但只要、频浇壅。"]'),
('song-ci-239','水调歌头','程大昌','宋','宋词','song-ci','水调歌头','[]','绿净贯闤闠，夹岸是楼台。',114,'宋词/ci.song.2000.json','["绿净贯闤闠，夹岸是楼台。", "楼台分影倒卧，千丈郁崔嵬。", "此是化人奇变，能使山巅水底，对出两蓬莱。", "溪浒有仙观，苕霅信佳哉。", "水晶宫，谁著语，半嘲诙。", "世间那有，如许磊砢栋梁材。", "每遇天容全碧，仍更苹风不动，相与夜深来。", "饮子以明月，净洗旧尘埃。"]'),
('song-ci-240','临江仙','程大昌','宋','宋词','song-ci','临江仙','[]','遥认埙篪相应，为传珠贯累累。',69,'宋词/ci.song.2000.json','["遥认埙篪相应，为传珠贯累累。", "紫荆同本但殊枝。", "直须投老日，常似有亲时。", "子姓亦闻多慧性，贪书不是痴儿。", "朝家世世重诗书。", "一登龙虎榜，许并凤凰池。"]'),
('song-ci-241','临江仙','程大昌','宋','宋词','song-ci','临江仙','[]','抗步碧潭弥弥，五畲青髻累累。',69,'宋词/ci.song.2000.json','["抗步碧潭弥弥，五畲青髻累累。", "何年乔木倚筇枝。", "搜寻同队者，追说钓游时。", "今日昂藏称壮子，向来襁褓婴儿。", "年周甲子又重书。", "岂容藏老丑，照白有清池。"]'),
('song-ci-242','临江仙','程大昌','宋','宋词','song-ci','临江仙','[]','夹路传呼杳杳，垂腰印绶累累。',69,'宋词/ci.song.2000.json','["夹路传呼杳杳，垂腰印绶累累。", "万般荣贵出丹枝。", "遥知心乐处，椿畔桂当时。", "酒到芳春偏弄色，轻黄泛滟鹅儿。", "大为行乐使堪书。", "醉来花下卧，便是习家池。"]'),
('song-ci-243','好事近','程大昌','宋','宋词','song-ci','好事近','[]','绿鬓又红颜，谁道年周甲子。',53,'宋词/ci.song.2000.json','["绿鬓又红颜，谁道年周甲子。", "两婿□□蓝绶，那一儿何虑。", "只今卜筑水晶宫，归安好名义。", "金紫珈笄偕老，备长生福贵。"]'),
('song-ci-244','好事近','程大昌','宋','宋词','song-ci','好事近','[]','白屋到横金，已是蟠桃结子。',53,'宋词/ci.song.2000.json','["白屋到横金，已是蟠桃结子。", "更向仕途贪恋，是痴人呆虑。", "水晶宫里饭莼鲈，中菰第一义。", "留得鬓须迟白，是本来真贵。"]'),
('song-ci-245','浣溪沙','程大昌','宋','宋词','song-ci','浣溪沙','[]','物本无情人有情。',48,'宋词/ci.song.2000.json','["物本无情人有情。", "百般禽咮百般声。", "有人闻鹊不闻莺。", "我盏通神君信否，酒才著盏月随生。", "大家吸月当箫笙。"]'),
('song-ci-246','万年欢','程大昌','宋','宋词','song-ci','万年欢','[]','秋后花窠，放两枝三朵，来通芳信。',123,'宋词/ci.song.2000.json','["秋后花窠，放两枝三朵，来通芳信。", "诗眼惊观，谓是春光倒运。", "便即移尊就赏，更不惜、黄封赤印。", "何期道，青女专时，露华忽变霜阵。", "诗翁笑、但休问。", "那阳和有脚，骎骎日进。", "待得灰飞，梅畹果先骋俊。", "次后连天红紫，向东风、万般娇韵。", "恁时节，玉勒狨鞍，郊原莫论远近。"]'),
('song-ci-247','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','身寿又康强，谢天将并。',81,'宋词/ci.song.2000.json','["身寿又康强，谢天将并。", "耳目聪明行步壮。", "登高挥翰，不用瞠眉扶杖。", "华堂偕老处，儿孙王。", "只恨萍蓬，他乡浮荡。", "回首故山便惆怅。", "今年生日，忽似还家模样。", "当缘风絮韫，来赓唱。"]'),
('song-ci-248','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','画舸白苹洲，如归故里。',81,'宋词/ci.song.2000.json','["画舸白苹洲，如归故里。", "老幼欢迎僮婢喜。", "较量心事，岁岁春风弧矢。", "今年称寿处，尤欢美。", "嫁得黔娄，苦耽书史。", "文字流传曾贵纸。", "便同黼黻，何似实头龟紫。", "天公闻此语，应怜许。"]'),
('song-ci-249','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','变化属朝班，鲲鹏相并。',81,'宋词/ci.song.2000.json','["变化属朝班，鲲鹏相并。", "健翼垂云风用壮。", "扶摇得势，不藉仙人仙杖。", "旁观生意气，犹神王。", "此去汉庭，春光骀荡。", "亲见子虚不惆怅。", "鸢肩捷上，自有唐家格样。", "三台旬月里，堪歌唱。"]'),
('song-ci-250','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','中外受郊恩，三封纶告。',81,'宋词/ci.song.2000.json','["中外受郊恩，三封纶告。", "依并小君出称号。", "锦犀光艳，不比香薰脂膏。", "况从鸣瑟里，添花草。", "更愿天公，别施洪造。", "水长船高愈新好。", "恁时舞带，一任巧装百宝。", "曲终珠满地，从人扫。"]'),
('song-ci-251','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','措大做生朝，无他珍异。',81,'宋词/ci.song.2000.json','["措大做生朝，无他珍异。", "填个曲儿为鼓吹。", "古来龙马，曾献河图真数。", "羲黄缘得此，齐元气。", "我向如今，职名升赐。", "地在天宫正东序。", "当初真本，到此或容披觑。", "这回错综处，堪详叙。"]'),
('song-ci-252','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','七十有三番，挂弧门首。',81,'宋词/ci.song.2000.json','["七十有三番，挂弧门首。", "此事从来信希有。", "新来仕路，夸说一般高手。", "肯从清要地，抛簪绶。", "何许分花，伊谁送酒。", "得开口时且开口。", "无烦无恼，也没期程奔走。", "但能安此乐，夷然寿。"]'),
('song-ci-253','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','锦告侈脂封，煌煌家宝。',81,'宋词/ci.song.2000.json','["锦告侈脂封，煌煌家宝。", "偕老之人已华皓。", "绿云拥鬓，更没一根入老。", "但从和晬看，年堪考。", "叶是松苗，松为叶脑。", "禀得松神大都好。", "人人戴白，独我青青常保。", "只将平易处，为蓬岛。"]'),
('song-ci-254','感皇恩','程大昌','宋','宋词','song-ci','感皇恩','[]','一岁一生朝，一番老相。',81,'宋词/ci.song.2000.json','["一岁一生朝，一番老相。", "无欲无营亦无望。", "看经写字，且做闲中气象。", "闭门人阒静，心清旷。", "骨肉团栾，一杯相向。", "野蔌家肴竞来饷。", "真情直话，不用逢迎俯仰。", "从他人笑道，不时样。"]'),
('song-ci-255','好事近','程大昌','宋','宋词','song-ci','好事近','[]','桃柳旧根株，春到红蔫绿茁。',53,'宋词/ci.song.2000.json','["桃柳旧根株，春到红蔫绿茁。", "一似老年垂白，带少容黳发。", "浮家泛宅在他乡，难得会瓜葛。", "幸对此番乐饮，任宵分明发。"]'),
('song-ci-256','好事近','程大昌','宋','宋词','song-ci','好事近','[]','盥水结冰花，老眼於今重见。',53,'宋词/ci.song.2000.json','["盥水结冰花，老眼於今重见。", "一似琢成水玉，向冻盆游泛。", "天公作事有何难，要花花便现。", "且把重春留住，变苍黎容面。"]'),
('song-ci-257','好事近','程大昌','宋','宋词','song-ci','好事近','[]','腊月做生朝，只有南枝梅玉。',53,'宋词/ci.song.2000.json','["腊月做生朝，只有南枝梅玉。", "此外后生桃李，未舒英吐馥。", "后园别自出神奇，现双松双竹。", "报道前堂琴瑟，俱长生厚福。"]'),
('song-ci-258','水调歌头','范成大','宋','宋词','song-ci','水调歌头','[]','元日至人日，未有不阴时。',114,'宋词/ci.song.2000.json','["元日至人日，未有不阴时。", "新年叶气，无处人物不熙熙。", "万岁声从天下，一札恩随春到，光采动天鸡。", "寿域遍寰海，直过雪山西。", "忆曾预，宣玉册，捧金卮。", "如今万里，魂梦空绕五云飞。", "想见大庭宫馆，重起三山楼观，双指赭黄衣。", "此会古无有，何止古来稀。"]'),
('song-ci-259','浣溪沙','范成大','宋','宋词','song-ci','浣溪沙','[]','十里西畴熟稻香。',48,'宋词/ci.song.2000.json','["十里西畴熟稻香。", "槿花篱落竹丝长。", "垂垂山果挂青黄。", "浓雾知秋晨气润，薄云遮日午阴凉。", "不须飞盖护戎装。"]'),
('song-ci-260','破阵子','范成大','宋','宋词','song-ci','破阵子','[]','漂泊天隅佳节，追随花下群贤。',72,'宋词/ci.song.2000.json','["漂泊天隅佳节，追随花下群贤。", "只欠山阴修禊帖，却比兰亭有管弦。", "舞裙香未湔。", "泪竹斑中宿雨，折桐雪里蛮烟。", "唤起杜陵饥客恨，人在长安曲水边。", "碧云千叠山。"]'),
('song-ci-261','鹧鸪天','范成大','宋','宋词','song-ci','鹧鸪天','[]','楼观青红倚快晴。',64,'宋词/ci.song.2000.json','["楼观青红倚快晴。", "惊看陆地涌蓬瀛。", "南园花影笙歌地，东岭松风鼓角声。", "山绕水，水萦城。", "柳边沙外古今情。", "坐中更有挥豪客，一段风流画不成。"]'),
('song-ci-262','酹江月・念奴娇','范成大','宋','宋词','song-ci','酹江月・念奴娇','[]','浮生有几，叹欢娱常少，忧愁相属。',120,'宋词/ci.song.2000.json','["浮生有几，叹欢娱常少，忧愁相属。", "富贵功名皆由命，何必区区仆仆。", "燕蝠尘中，鸡虫影里，见了还追逐。", "山间林下，几人真个幽独。", "谁似当年严君，故人龙衮，独抱羊裘宿。", "试把渔竿都掉了，百种千般拘束。", "两岸烟林，半溪山影，此处无荣辱。", "荒台遗像，至今嗟咏不足。"]'),
('song-ci-263','水调歌头','范成大','宋','宋词','song-ci','水调歌头','[]','万里筹边处，形胜压坤维。',114,'宋词/ci.song.2000.json','["万里筹边处，形胜压坤维。", "恍然旧观重见，鸳瓦拂参旗。", "夜夜东山衔月，日日西山横雪，白羽弄空晖。", "人语半霄碧，惊倒路傍儿。", "分弓了，看剑罢，倚阑时。", "苍茫平楚无际，千古锁烟霏。", "野旷岷嶓江动，天阔崤函云拥，太白暝中低。", "老矣汉都护，却望玉关归。"]'),
('song-ci-264','木兰花慢','范成大','宋','宋词','song-ci','木兰花慢','[]','古人吾不见，君莫是、郑当时。',119,'宋词/ci.song.2000.json','["古人吾不见，君莫是、郑当时。", "更筑就山房，躬耕谷口，名动京师。", "诸公任他衮衮，与杜陵野老共襟期。", "有客至门先喜，得钱沽酒何疑。", "昔年连辔柳边归。", "陈迹恍难追。", "况种桃道士，看花才子，回首皆非。", "相逢故人问讯，道刘郎去久无诗。", "把作一场春梦，觉来莫要寻思。"]'),
('song-ci-265','贺新郎','游次公','宋','宋词','song-ci','贺新郎','[]','暖霭浮晴篽。',142,'宋词/ci.song.2000.json','["暖霭浮晴篽。", "锁垂杨、龙池罩阁，万丝千缕。", "池上晓光分宿雾，日近群芳易吐。", "寻并蒂、阑干凝伫。", "不信钗头飞凤去，但宝刀、被妾还留住。", "天一笑，万花妒。", "阿娇正好金屋贮。", "甚西风、易得萧疏，扇鸾尘土。", "一自昭阳扃玉户，墙角土花无数。", "况多病、情伤幽素。", "别殿时闻箫鼓奏，望红云、冉冉知何处。", "天尺五，去无路。"]'),
('song-ci-266','卜算子','游次公','宋','宋词','song-ci','卜算子','[]','风雨送人来，风雨留人住。',52,'宋词/ci.song.2000.json','["风雨送人来，风雨留人住。", "草草杯柈话别离，风雨催人去。", "泪眼不曾晴，眉黛愁还聚。", "明日相思莫上楼，楼上多风雨。"]'),
('song-ci-267','满江红','游次公','宋','宋词','song-ci','满江红','["\u6d1e\u5ead\u6e56"]','云接苍梧，山莽莽、春浮泽国。',115,'宋词/ci.song.2000.json','["云接苍梧，山莽莽、春浮泽国。", "江水涨、洞庭相近，渐近空阔。", "江燕飘飘身似梦，江花草草春如客。", "望渔春、樵市隔平林，寒烟色。", "方寸乱，成丝结。", "离别近，先愁绝。", "便满篷风雨，橹声孤急。", "白发论心湖海暮，清樽照影苍浪窄。", "看明年、天际下归舟，应先识。"]'),
('song-ci-268','贺新郎','游次公','宋','宋词','song-ci','贺新郎','[]','斗柄回秋律。',142,'宋词/ci.song.2000.json','["斗柄回秋律。", "素蟾飞、冰霜万里，满川金碧。", "得月偏多何处是，惟有桥南第一。", "正野迥、西风寒寂。", "丹桂婆娑疏影在，想微瑕、未累千金璧。", "河汉远，澹无迹。", "知君有句酬佳夕。", "尽高歌、胡床自倚，露漙珠溢。", "坐到参横星欲暗，隐隐天低似笠。", "但络纬、悲啼催织。", "吟咏凄凉翻有恨，谅知音、人远空追忆。", "谁为置，郑庄驿。"]'),
('song-ci-269','满江红','游次公','宋','宋词','song-ci','满江红','[]','一舸归来，何太晚、鬓丝如织。',115,'宋词/ci.song.2000.json','["一舸归来，何太晚、鬓丝如织。", "谩叹息、凄凉往事，尽成陈迹。", "山迫暮烟浮紫翠，溪摇寒浪翻金碧。", "看长虹、渴饮下青冥，危栏湿。", "谁可住，烟萝侧。", "俗士驾，当回勒。", "伴岩扃，须是碧云仙客。", "风月已供无尽藏，溪山更衍清凉国。", "恨谪仙、苏二不曾来，无人说。"]'),
('song-ci-270','满江红','赵老','宋','宋词','song-ci','满江红','[]','见说春时，新波涨、二川溶溢。',114,'宋词/ci.song.2000.json','["见说春时，新波涨、二川溶溢。", "今底事、沙痕犹褪，石渠悭碧。", "人意不须长作解，兴来便向杯中觅。", "纵茂林修竹记山阴，千年一。", "薰吹动，春工毕。", "桥上景，壶中日。", "况梅肥笋嫩，雨微鱼出。", "只恐延英催入觐，不教绿野长均逸。", "任多情、胡蝶满园飞，狂踪迹。"]'),
('song-ci-271','满江红','赵老','宋','宋词','song-ci','满江红','[]','西郭园林，湖光净、暮寒清溢。',115,'宋词/ci.song.2000.json','["西郭园林，湖光净、暮寒清溢。", "明月上，近环山翠，远摇天碧。", "粉泽兰膏违俗尚，岩花磴蔓从谁觅。", "问近来、铛脚许何人，吾其一。", "欢乐事，休教毕。", "经后夜，思前日。", "想无心不竞，水流云出。", "物外烟霞供啸咏，个中鱼鸟同休逸。", "又何须、浮海访三山，寻仙迹。"]'),
('song-ci-272','满江红','赵老','宋','宋词','song-ci','满江红','[]','潇洒星郎，吹绿鬓、胜游霞举。',115,'宋词/ci.song.2000.json','["潇洒星郎，吹绿鬓、胜游霞举。", "秋又半，月磨云翳，籁传风语。", "太一青黎光对射，中流荡漾莲舟舞。", "戏人间、今夜水精宫，前无古。", "吾家是，蓬山侣。", "歌舞袖，苹花渚。", "拟问津斜汉，乘槎南浦。", "谒帝通明今得便，素娥拍手心先许。", "笑画阑、三十六宫秋，花如土。"]'),
('song-ci-273','念奴娇','赵老','宋','宋词','song-ci','念奴娇','[]','冰蟾驾月，荡寒光、不见层波层碧。',120,'宋词/ci.song.2000.json','["冰蟾驾月，荡寒光、不见层波层碧。", "几岁中秋争得似，云卷秋声寂寂。", "多谢星郎，来陪贤令，快赏鳌峰极。", "广寒宫近，素娥不靳馀力。", "夜久露落琼浆，神京归路，有云翘前迹。", "当日仙人曾驭气，只学神交龟息。", "今夜清尊，一齐分付，稳是乘槎客。", "天津重到，霓裳何似闻笛。"]'),
('song-ci-274','水调歌头','赵老','宋','宋词','song-ci','水调歌头','[]','梅仙了无讼，拄笏看西山。',115,'宋词/ci.song.2000.json','["梅仙了无讼，拄笏看西山。", "山涵秋晓，水光磨荡有无间。", "自是灵襟空洞，更望风云吞吐，浩渺白鸥闲。", "高诵远游赋，独立桂香阑。", "谩常谈，如观水，要观澜。", "物情长在，人生何用苦求难。", "随我一觞一咏，任彼非元彼非白，唯放酒杯宽。", "富贵偿来事，天道管知还。"]'),
('song-ci-275','永遇乐','赵老','宋','宋词','song-ci','永遇乐','[]','香雪堆梅，绣丝蹙柳，仙馆春到。',128,'宋词/ci.song.2000.json','["香雪堆梅，绣丝蹙柳，仙馆春到。", "午夜华灯，烘春艳粉，月借今宵好。", "衮衣摇曳，簪缨闲绕，共祝大椿难老。", "望台躔、明星一点，冰壶表里相照。", "诞弥令节，欣欣物态，共喜重生周召。", "八鼎勋庸，九夷姓字，策杖孤鸿杳。", "鸦啼鹊噪，兰馨松茂，把酒共春一笑。", "管如今、盐梅再梦，夜铃命诏。"]'),
('song-ci-276','醉蓬莱','赵老','宋','宋词','song-ci','醉蓬莱','[]','听都人歌咏，便启金瓯，再登元老。',120,'宋词/ci.song.2000.json','["听都人歌咏，便启金瓯，再登元老。", "山色溪声，与春风齐到。", "补衮工夫，望梅心绪，见丹青重好。", "鹊噪晴空，灯迎诞节，槐堂欢笑。", "正是元宵，满天和气，璧月流光，雪消寒峭。", "今夜今年，表千年同照。", "万象森罗，一奁清莹，影山河多少。", "玉烛调新，彩眉常喜，寰瀛春晓。"]'),
('song-ci-277','醉蓬莱','赵老','宋','宋词','song-ci','醉蓬莱','[]','记青蛇感异，后日扶颠，太平人瑞。',120,'宋词/ci.song.2000.json','["记青蛇感异，后日扶颠，太平人瑞。", "壮岁弹冠，有经邦高志。", "晚上文墀，载严霜简，便云龙交际。", "紫极旋枢，金蝉映衮，乾坤开霁。", "底事当时，饮江胡马，一望云旗，倒戈投贽。", "此片丹心，几风声鹤唳。", "烟息尘收，水明山丽，只五湖相记。", "今夜华灯，火城信息，千年荣贵。"]'),
('song-ci-278','鹧鸪天','赵老','宋','宋词','song-ci','鹧鸪天','[]','堂上年时见烛花。',64,'宋词/ci.song.2000.json','["堂上年时见烛花。", "青毡还入旧时家。", "芝函瑞色回春早，绿野东风转岁华。", "催召传，稳铺沙。", "垒尊今日枣如瓜。", "诞辰更接传柑宴，莲炬通宵唤草麻。"]'),
('song-ci-279','鹧鸪天','赵磻老','宋','宋词','song-ci','鹧鸪天','[]','白日青天一旦明。',64,'宋词/ci.song.2000.json','["白日青天一旦明。", "旧时勋业此时情。", "延英再许裴公对，商鼎须调传说羹。", "千万载，辅宗祊。", "挚天八柱愈峥嵘。", "将军犁却龙庭后，岁傍鳌山奏太平。"]'),
('song-ci-280','生查子','赵老','宋','宋词','song-ci','生查子','[]','章甫不如人，翠绾垂杨缕。',48,'宋词/ci.song.2000.json','["章甫不如人，翠绾垂杨缕。", "纤手送来时，罗帕缄香雾。", "貂婵懒上头，渭水知何处。", "风月共垂竿，脱帽须亲付。"]'),
('song-ci-281','生查子','赵老','宋','宋词','song-ci','生查子','[]','朝路进贤归，厌听歌金缕。',48,'宋词/ci.song.2000.json','["朝路进贤归，厌听歌金缕。", "不念玉堂花，豹隐南山雾。", "漉酒未巾时，暑槛披风处。", "子夏不兼人，并与诗筒付。"]'),
('song-ci-282','生查子','赵老','宋','宋词','song-ci','生查子','[]','金门一免时，离绪纷如缕。',48,'宋词/ci.song.2000.json','["金门一免时，离绪纷如缕。", "想像切云高，晓日罗昏雾。", "峨冠补衮人，不是无心处。", "欲效贡公弹，衣钵知谁付。"]'),
('song-ci-283','生查子','赵老','宋','宋词','song-ci','生查子','[]','斜日下平川，楼角销霞缕。',48,'宋词/ci.song.2000.json','["斜日下平川，楼角销霞缕。", "摆尽浊尘缨，画栋萦非雾。", "平生许子穷，今到知音处。", "约伴玉簪游，好梦从天付。"]'),
('song-ci-284','南柯子・南歌子','赵老','宋','宋词','song-ci','南柯子・南歌子','[]','世上渊明酒，人间陆羽茶。',62,'宋词/ci.song.2000.json','["世上渊明酒，人间陆羽茶。", "东山无妓有莲花。", "隐隐仙家鸡犬、路非赊。", "积霭犹张幕，轻雷似卷车。", "要令长袖舞胡靴。", "须是檐头新霁、鹊查查。"]'),
('song-ci-285','南柯子・南歌子','赵老','宋','宋词','song-ci','南柯子・南歌子','[]','体质娟娟静，花纹细细装。',62,'宋词/ci.song.2000.json','["体质娟娟静，花纹细细装。", "翠筠初得试新忙。", "睡起鬓云撩乱、趣泉汤。", "多病心常捧，新词字带香。", "管教涂泽到云窗。", "办下谢君言语、巧如簧。"]'),
('song-ci-286','浣溪沙','赵磻老','宋','宋词','song-ci','浣溪沙','[]','懒画娥眉倦整冠。',48,'宋词/ci.song.2000.json','["懒画娥眉倦整冠。", "笋苞来点镜中鬟。", "承恩容易报恩难。", "鬒发未饶青箬笠，素鳞行簇水晶盘。", "流觞元自不相干。"]'),
('song-ci-287','浣溪沙','赵老','宋','宋词','song-ci','浣溪沙','[]','刘氏风流设此冠。',48,'宋词/ci.song.2000.json','["刘氏风流设此冠。", "今谁将去伴珠鬟。", "君家兄弟二俱难。", "驰去请观流汗马，钓时休等烂银盘。", "明朝吟咏有方干。"]'),
('song-ci-288','瑞鹧鸪','尤袤','宋','宋词','song-ci','瑞鹧鸪','[]','梁溪西畔小桥东。',64,'宋词/ci.song.2000.json','["梁溪西畔小桥东。", "落叶纷纷水映空。", "五夜客愁花片里，一年春事角声中。", "歌残玉树人何在，舞破山香曲未终。", "却忆孤山醉归路，马蹄香雪衬东风。"]'),
('song-ci-289','瑞鹧鸪','尤袤','宋','宋词','song-ci','瑞鹧鸪','[]','两行芳蕊傍溪阴。',64,'宋词/ci.song.2000.json','["两行芳蕊傍溪阴。", "一笑嫣然抵万金。", "火齐照林光灼灼，彤霞射水影沈沈。", "晓妆无力胭脂重，春醉方酣酒晕深。", "定自格高难著句，不应工部总无心。"]'),
('song-ci-290','阮郎归','赵','宋','宋词','song-ci','阮郎归','[]','留连春意晚花稠。',56,'宋词/ci.song.2000.json','["留连春意晚花稠。", "云疏雨未收。", "新荷池面叶齐抽。", "凉天醉碧楼。", "能达理，有何愁。", "心宽万事休。", "人生还似水中沤。", "金尊尽更酬。"]'),
('song-ci-291','忆少年','谢懋','宋','宋词','song-ci','忆少年','[]','池塘绿遍，王孙芳草，依依斜日。',56,'宋词/ci.song.2000.json','["池塘绿遍，王孙芳草，依依斜日。", "游丝卷晴昼，系东风无力。", "蝶趁幽香蜂酿蜜。", "秋千外、卧红堆碧。", "心情费消遣，更梨花寒食。"]'),
('song-ci-292','石州引・石州慢','谢懋','宋','宋词','song-ci','石州引・石州慢','[]','日脚斜明，秋色半阴，人意凄楚。',123,'宋词/ci.song.2000.json','["日脚斜明，秋色半阴，人意凄楚。", "飞雪特地凝愁，做弄晚来微雨。", "谁家别院，舞困几叶霜红，西风送客闻砧杵。", "鞭马出都门，正潮平洲渚。", "无语。", "匆匆短棹，满载离愁，片帆高举。", "京洛红尘，因念几年羁旅。", "浅颦轻笑，旧时风月逢迎，别来谁画双眉妩。", "回首一销凝，望归鸿容与。"]'),
('song-ci-293','洞仙歌','谢懋','宋','宋词','song-ci','洞仙歌','["\u957f\u6c5f"]','愁边雨细。',107,'宋词/ci.song.2000.json','["愁边雨细。", "漠漠天如醉。", "摇扬游丝晚风外。", "酿轻寒、和暝色，花柳难胜，春自老，谁管啼红敛翠。", "关情潜入夜，斜湿帘栊，几处挑灯耿无寐。", "念阳台、当日事，好伴云来，因个甚、不入襄王梦里。", "便添起、寒潮卷长江，又恐是离人，断肠清泪。"]'),
('song-ci-294','杏花天','谢懋','宋','宋词','song-ci','杏花天','[]','海棠枝上东风软。',64,'宋词/ci.song.2000.json','["海棠枝上东风软。", "荡霁色、烟光弄暖。", "双双燕子归来晚。", "零落红香过半。", "琵琶泪搵青衫浅。", "念事与、危肠易断。", "馀酲未解扶头懒。", "屏里潇湘梦远。"]'),
('song-ci-295','画堂春','谢懋','宋','宋词','song-ci','画堂春','[]','西风庭院雨垂垂。',54,'宋词/ci.song.2000.json','["西风庭院雨垂垂。", "黄花秋闰迟。", "已凉天气未寒时。", "才褪单衣。", "睡起枕痕犹在，鬓松钗压云低。", "玉奁重拂淡胭脂。", "情入双眉。"]'),
('song-ci-296','武陵春','谢懋','宋','宋词','song-ci','武陵春','[]','门掩东风人去后，愁损燕莺心。',56,'宋词/ci.song.2000.json','["门掩东风人去后，愁损燕莺心。", "一朵梅花淡有春。", "粉黛不忺匀。", "我亦青楼成倦客，风月强追寻。", "莫把恩情做弄成。", "容易学行云。"]'),
('song-ci-297','霜天晓角','谢懋','宋','宋词','song-ci','霜天晓角','[]','绿云剪叶。',54,'宋词/ci.song.2000.json','["绿云剪叶。", "低护黄金屑。", "占断花中声誉，香与韵、两清洁。", "胜绝。", "君听说。", "是他来处别。", "试看仙衣犹带，金庭露、玉阶月。"]'),
('song-ci-298','风流子','谢懋','宋','宋词','song-ci','风流子','[]','少年多行乐，方豪健、何处不嬉游。',135,'宋词/ci.song.2000.json','["少年多行乐，方豪健、何处不嬉游。", "记情逐艳波，暖香斜径，醉摇鞭影，扑絮青楼。", "难忘是，笑歌偏婉娩，乡号得温柔。", "娇雨娱云，旋宽衣带，剩风残月，都在眉头。", "一成憔悴损，人惊怪，空自引镜堪羞。", "谁念短封难托，征雁虚浮。", "念夜寒灯火，懒寻前梦，满窗风雨，供断闲愁。", "情到不堪言处，却悔风流。"]'),
('song-ci-299','念奴娇','谢懋','宋','宋词','song-ci','念奴娇','[]','霁天湛碧。',120,'宋词/ci.song.2000.json','["霁天湛碧。", "正新凉风露，冰壶清彻。", "河汉无声光练练，涌处银蟾孤绝。", "岩桂香飘，井梧影转，冷浸官袍洁。", "西厢往事，一帘清梦凄切。", "肠断楚峡云归，尊前无绪，知有愁如发。", "此夕常娥应也恨，冷落琼楼金阕。", "禁漏迢迢，边鸿杳杳，幽意凭谁决。", "阑干星斗，落梅三弄初阕。"]'),
('song-ci-300','鹊桥仙','谢懋','宋','宋词','song-ci','鹊桥仙','[]','钩帘借月，染云为幌，花面玉枝交映。',68,'宋词/ci.song.2000.json','["钩帘借月，染云为幌，花面玉枝交映。", "凉生河汉一天秋，问此会、今宵孰胜。", "铜壶尚滴，烛龙已驾，泪浥西风不尽。", "明朝乌鹊到人间，试说向、青楼薄幸。"]'),
('song-ci-301','解连环','谢懋','宋','宋词','song-ci','解连环','[]','雁空辽邈。',130,'宋词/ci.song.2000.json','["雁空辽邈。", "衬鱼鳞浪浅，护霜云薄。", "念故人、千里音尘，正山月朦胧，水村依约。", "见说瑶姬，拥十二、碧峰如削。", "倚孤芳澹伫，冷笑岁华，可堪寂寞。", "情多为谁瘦弱。", "爱吹芗弄粉，斜搴珠箔。", "自然林壑精神，想回首东风，万花羞落。", "梦绕南楼，对皓月、忍思量著。", "但销凝、夜阑酒醒，数声画角。"]'),
('song-ci-302','蓦山溪','谢懋','宋','宋词','song-ci','蓦山溪','[]','厌厌睡起，无限春情绪。',102,'宋词/ci.song.2000.json','["厌厌睡起，无限春情绪。", "柳色借轻烟，尚瘦怯、东风倦舞。", "海棠红皱，不奈晚来寒，帘半卷，日西沈，寂寞闲庭户。", "飞雪无据。", "化作冥濛雨。", "愁里见春来，又只恐、愁催春去。", "惜花人老，芳草梦凄迷，题欲遍，琐窗纱，总是伤春句。"]'),
('song-ci-303','风入松','谢懋','宋','宋词','song-ci','风入松','[]','老年长忆少年狂。',88,'宋词/ci.song.2000.json','["老年长忆少年狂。", "宿粉栖香。", "自怜独得东君意，有三年、窥宋东墙。", "笑无落花红影，醉眠芳草斜阳。", "事随春梦去悠扬。", "休去思量。", "近来眼底无姚魏，有谁更、管领年芳。", "换得河阳衰鬓，一帘烟雨梅黄。"]'),
('song-ci-304','浪淘沙','谢懋','宋','宋词','song-ci','浪淘沙','[]','黄道雨初乾。',64,'宋词/ci.song.2000.json','["黄道雨初乾。", "霁霭空蟠。", "东风杨柳碧毵毵。", "燕子不归花有恨，小院春寒。", "倦客亦何堪。", "尘满征衫。", "明朝野水几重山。", "归梦已随芳草绿，先到江南。"]'),
('song-ci-305','相见欢','王质','宋','宋词','song-ci','相见欢','[]','霜花零落全稀。',45,'宋词/ci.song.2000.json','["霜花零落全稀。", "不成飞。", "寒水溶溶漾漾、软琉璃。", "红未涌，青已露，白都晞。", "□□□□沙暖、戏凫鷖。"]'),
('song-ci-306','长相思','王质','宋','宋词','song-ci','长相思','[]','红疏疏，紫疏疏。',44,'宋词/ci.song.2000.json','["红疏疏，紫疏疏。", "可惜飘零著地铺。", "春残心转孤。", "莺相呼。", "燕相呼。", "楼下垂杨遮得乌。", "倚阑人已无。"]'),
('song-ci-307','长相思','王质','宋','宋词','song-ci','长相思','[]','山青青。',44,'宋词/ci.song.2000.json','["山青青。", "水青青。", "两岸萧萧芦荻林。", "水深村又深。", "风泠泠。", "露泠泠。", "一叶扁舟深处横。", "垂杨鸥不惊。"]'),
('song-ci-308','生查子','王质','宋','宋词','song-ci','生查子','[]','见汝小溪湾，修竹连疏影。',48,'宋词/ci.song.2000.json','["见汝小溪湾，修竹连疏影。", "林杪动风声，惊下毵毵粉。", "见汝大江郊，高浪摇枯本。", "飞雪密封枝，直到斜阳醒。"]'),
('song-ci-309','杨柳枝','王质','宋','宋词','song-ci','杨柳枝','[]','惯得娇云赶不开。',48,'宋词/ci.song.2000.json','["惯得娇云赶不开。", "去还来。", "淡光无可照楼台。", "且停杯。", "薄雨疏疏时几点，洒浮埃。", "卖花未上担儿抬。", "听他催。"]'),
('song-ci-310','浣溪沙','王质','宋','宋词','song-ci','浣溪沙','[]','何药能医肠九回。',48,'宋词/ci.song.2000.json','["何药能医肠九回。", "榴莲不似蜀当归。", "却簪征帽解戎衣。", "泪下猿声巴峡里，眼荒鸥碛楚江涯。", "梦魂只傍故人飞。"]'),
('song-ci-311','浣溪沙','王质','宋','宋词','song-ci','浣溪沙','[]','梦到江南梦却回。',48,'宋词/ci.song.2000.json','["梦到江南梦却回。", "梦归何处得身归。", "故溪渌净看凫衣。", "下到瞿唐春欲杪，桃花香浪渺无涯。", "三台回望五云飞。"]'),
('song-ci-312','浣溪沙','王质','宋','宋词','song-ci','浣溪沙','[]','征雁年来得几回。',48,'宋词/ci.song.2000.json','["征雁年来得几回。", "春风无雁带书归。", "故应春瘦减春衣。", "花柳伤心经岁月，江湖无梦失津涯。", "到家无树不红飞。"]'),
('song-ci-313','浣溪沙','王质','宋','宋词','song-ci','浣溪沙','[]','细雨萧萧变作秋。',48,'宋词/ci.song.2000.json','["细雨萧萧变作秋。", "晚风杨柳冷飕飕。", "无言有泪洒西楼。", "眼共云山昏惨惨，心随烟水去悠悠。", "一蓑一笠任孤舟。"]'),
('song-ci-314','清平乐','王质','宋','宋词','song-ci','清平乐','[]','江沙带湿。',54,'宋词/ci.song.2000.json','["江沙带湿。", "莎露和烟泣。", "落日欲低红未入。", "悄悄暮峰凝立。", "疏林秀色荒寒。", "频频驻骑回看。", "应是梧桐影下，秋风蹙碎眉山。"]'),
('song-ci-315','清平乐','王质','宋','宋词','song-ci','清平乐','[]','断桥流水。',54,'宋词/ci.song.2000.json','["断桥流水。", "香满扶疏里。", "忽见一枝明眼底。", "人在山腰水尾。", "梨花应梦纷纷。", "征鸿叫断行云。", "不见绿毛么凤，一方明月中庭。"]'),
('song-ci-316','清平乐','王质','宋','宋词','song-ci','清平乐','[]','从来清瘦。',54,'宋词/ci.song.2000.json','["从来清瘦。", "更被春僝僽。", "瘦得花身无可有。", "莫放隔帘风透。", "一枝相映孤灯。", "灯明不似花明。", "细看横斜影下，如闻溪水泠泠。"]'),
('song-ci-317','眼儿媚','王质','宋','宋词','song-ci','眼儿媚','[]','雨润梨花雪未乾。',58,'宋词/ci.song.2000.json','["雨润梨花雪未乾。", "犹自有春寒。", "不如且住，清明寒食，数日之间。", "想君行尽嘉陵水，我已下江南。", "想看万里，时须片纸，各报平安。"]'),
('song-ci-318','西江月','王质','宋','宋词','song-ci','西江月','[]','月斧修成腻玉，风斤琢碎轻冰。',58,'宋词/ci.song.2000.json','["月斧修成腻玉，风斤琢碎轻冰。", "主人无那寿杯深。", "倩取花来唤醒。", "舞罢绣裀凤蹙，饮阑画阁香凝。", "试将花蕊数层层。", "犹比长年不尽。"]'),
('song-ci-319','西江月','王质','宋','宋词','song-ci','西江月','[]','轻蜡细凝蜂蜜，薄罗深压鹅黄。',58,'宋词/ci.song.2000.json','["轻蜡细凝蜂蜜，薄罗深压鹅黄。", "玉容纵不似何郎。", "也在百花头上。", "试看眉间一点，全如瓶里孤芳。", "明年此日趁鹓行。", "记取今朝胜赏。"]'),
('song-ci-320','西江月','王质','宋','宋词','song-ci','西江月','[]','蹙蹙红中烟润，梢梢翠尾风斜。',58,'宋词/ci.song.2000.json','["蹙蹙红中烟润，梢梢翠尾风斜。", "闲轩幽树少啼鸦。", "此处最宜君画。", "望眼不知天阔，归心常恨山遮。", "见君江浦到芦花。", "意在琵琶亭下。"]'),
('song-ci-321','西江月','王质','宋','宋词','song-ci','西江月','[]','璧水桥边此客，金銮坡上何人。',58,'宋词/ci.song.2000.json','["璧水桥边此客，金銮坡上何人。", "沙场老马事无成。", "泪湿青莹夹镜。", "袖手烟霏小景，回头石岭空城。", "乾坤遗恨渺难平。", "目断塞鸿孤影。"]'),
('song-ci-322','滴滴金','王质','宋','宋词','song-ci','滴滴金','[]','阴阴湿雾霜无汁。',60,'宋词/ci.song.2000.json','["阴阴湿雾霜无汁。", "江气逼、树声滴。", "荒林只见夕阳入。", "谁唤晚烟集。", "渔翁犹把钓竿执。", "蓑共笠、时时葺。", "风刚浪猛早收拾。", "天外暮云黑。"]'),
('song-ci-323','燕归来・喜迁莺','王质','宋','宋词','song-ci','燕归来・喜迁莺','[]','拂拂春风入马啼。',60,'宋词/ci.song.2000.json','["拂拂春风入马啼。", "□驻绿杨堤。", "绿杨堤上乳莺啼。", "声声怨、怨春归。", "而今一似花流水，纵迹任东西。", "利成名逐在何时。", "早赢得、两分飞。"]'),
('song-ci-324','青门引・青门饮','王质','宋','宋词','song-ci','青门引・青门饮','[]','寻遍江南麓。',61,'宋词/ci.song.2000.json','["寻遍江南麓。", "只有斑斑野菊。", "梅花不遇我心悲，一枝得见，便是一年足。", "微香来自横冈竹。", "飞度寒溪曲。", "落路寻人借问，谢他指向深深谷。"]'),
('song-ci-325','鹧鸪天','王质','宋','宋词','song-ci','鹧鸪天','[]','空响萧萧似见呼。',64,'宋词/ci.song.2000.json','["空响萧萧似见呼。", "溪昏树暗觉神孤。", "微茫山路才通足，行到山深路亦无。", "寻草浅，拣林疏。", "虽疏无奈野藤粗。", "春衫不管藤搊碎，可惜教花著地铺。"]'),
('song-ci-326','鹧鸪天','王质','宋','宋词','song-ci','鹧鸪天','[]','一只船儿任意飞。',64,'宋词/ci.song.2000.json','["一只船儿任意飞。", "眼前不管是和非。", "鱼儿得了浑闲事，未得鱼儿未肯归。", "全似懒，又如痴。", "这些快活有谁知。", "华堂只见灯花好，不见波平月上时。"]'),
('song-ci-327','一斛珠','王质','宋','宋词','song-ci','一斛珠','[]','风流太守。',67,'宋词/ci.song.2000.json','["风流太守。", "未春先试回春手。", "天寒修竹斜阳后。", "翠袖中间，忽有人红袖。", "天香国色浓如酒。", "且教青女休僝僽。", "梅花元是群花首。", "细细商量，只怕梅花瘦。"]'),
('song-ci-328','一斛珠','王质','宋','宋词','song-ci','一斛珠','[]','寒江凝碧。',67,'宋词/ci.song.2000.json','["寒江凝碧。", "是谁翦作梨花出。", "花心犹带江痕湿。", "轻注香腮，却是桃花色。", "飞来飞去何曾密。", "疏疏全似新相识。", "横吹小弄梅花笛。", "看你飘零，不似江南客。"]'),
('song-ci-329','一斛珠','王质','宋','宋词','song-ci','一斛珠','[]','平塘玉立。',67,'宋词/ci.song.2000.json','["平塘玉立。", "薄罗飞起层层碧。", "人心不似花心密。", "待要相逢，未必相逢得。", "袜尘不动何曾湿。", "芙蓉桥上曾相识。", "橹声摇去江声急。", "西北高楼，回首浮云隔。"]'),
('song-ci-330','怨春郎','王质','宋','宋词','song-ci','怨春郎','[]','芦花已老。',65,'宋词/ci.song.2000.json','["芦花已老。", "蓼花已老。", "江腹冲风，山头残照。", "暮烟不辨栖鸥。", "识归舟。", "归舟照顾新洲阁。", "惊波恶。", "别拣深湾泊。", "南津北泺，水村总没人家。", "莽平沙。"]'),
('song-ci-331','虞美人','王质','宋','宋词','song-ci','虞美人','[]','绿阴夹岸人家住。',66,'宋词/ci.song.2000.json','["绿阴夹岸人家住。", "桥上人来去。", "行舟远远唤相应。", "全似孤烟斜日、出阊门。", "浪花拂拂侵沙觜。", "直到垂杨底。", "吴江虽有晚潮回。", "未比合江亭下、水如飞。"]'),
('song-ci-332','虞美人','王质','宋','宋词','song-ci','虞美人','[]','翠阴融尽毵毵雪。',66,'宋词/ci.song.2000.json','["翠阴融尽毵毵雪。", "惨淡花明灭。", "嫩沙拂拂涨痕添。", "想见故溪、绿到草堂前。", "夕阳红透樱桃粒。", "掩映深沈碧。", "成都事事似江南。", "只是香衾、两处受春寒。"]'),
('song-ci-333','临江仙','王质','宋','宋词','song-ci','临江仙','[]','缥缈青宵云一握，太清群玉光中。',70,'宋词/ci.song.2000.json','["缥缈青宵云一握，太清群玉光中。", "钧天声里拂香风。", "紫皇低接手，稳步上层空。", "雀扇徐开鸾影转，日高舞动蛟龙。", "双瞻御座立昭容。", "回班趋复道，环佩响丁东。"]'),
('song-ci-334','临江仙','王质','宋','宋词','song-ci','临江仙','[]','千顷翠围遮绿净，菱花影落波中。',70,'宋词/ci.song.2000.json','["千顷翠围遮绿净，菱花影落波中。", "看看红锦漾清风。", "此时催入觐，烟浪拍云空。", "伫见觚棱栖宝爵，旌旗全仗飞龙。", "赭黄一点现真容。", "御麻宣未毕，云镜上天东。"]'),
('song-ci-335','临江仙','王质','宋','宋词','song-ci','临江仙','[]','曲水流觞修禊事，祓除洗净春愁。',70,'宋词/ci.song.2000.json','["曲水流觞修禊事，祓除洗净春愁。", "举尊再拜寿君侯。", "只今虚鼎足，好去作班头。", "自古相门还出相，春旗小驻南州。", "云孙将绍祖风流。", "他时如见忆，江汉一渔舟。"]'),
('song-ci-336','临江仙','王质','宋','宋词','song-ci','临江仙','[]','八字山头来较晚，彩云未散南楼。',70,'宋词/ci.song.2000.json','["八字山头来较晚，彩云未散南楼。", "夕阳千丈映帘钩。", "君侯如欲老，江水莫教流。", "扇底清歌尘不动，胡床明月清秋。", "天浆为浪玉为舟。", "酒阑君便起。", "归去立班头。"]'),
('song-ci-337','定风波','王质','宋','宋词','song-ci','定风波','[]','曲曲阑干曲曲池。',73,'宋词/ci.song.2000.json','["曲曲阑干曲曲池。", "万红缭绕锦相围。", "花到黄昏思欲睡。", "休睡。", "眼前都是好相知。", "银烛转添花转好，人在，花深深处更相宜。", "似此好花须爱惜。", "休惜。", "鬓边消得两三枝。"]'),
('song-ci-338','定风波','王质','宋','宋词','song-ci','定风波','[]','问讯山东窦长卿。',73,'宋词/ci.song.2000.json','["问讯山东窦长卿。", "苍苍云外且垂纶。", "流水落花都莫问，等取，榆林沙月静边尘。", "江面不如杯面阔，卷起，五湖烟浪入清尊。", "醉倒投床君且睡，却怕，挑灯看剑忽伤神。"]'),
('song-ci-339','定风波','王质','宋','宋词','song-ci','定风波','[]','白璧黄金爵上卿。',73,'宋词/ci.song.2000.json','["白璧黄金爵上卿。", "紫宸殿下拜丝纶。", "才出龙门开虎帐，但看，甲光如水夜如尘。", "古古今今男子事，摇动，芙蓉旗影入金尊。", "到得关河公事了，早去，白云堆里养精神。"]'),
('song-ci-340','苏幕遮','王质','宋','宋词','song-ci','苏幕遮','[]','水风轻，吹不皱。',76,'宋词/ci.song.2000.json','["水风轻，吹不皱。", "上下浮光，两镜光相就。", "云锦摇香吹散酒。", "细听清谈，玉屑津津嗽。", "明月前，斜阳后。", "竹露秋声，拂拂寒生袖。", "掇取湖山聊入手。", "紫阁黄扉，到了终须有。"]'),
('song-ci-341','苏幕遮','王质','宋','宋词','song-ci','苏幕遮','[]','驿尘飞，天意紧。',77,'宋词/ci.song.2000.json','["驿尘飞，天意紧。", "香雪芝封，犹带吴泥润。", "昨夜宝奁开玉镜。", "一点西风，便觉寒秋近。", "白苹洲，红蓼径。", "风露凄清，快促黄金镫。", "叠叠重重听好信。", "掷了碧油幢，更掷双堂印。"]'),
('song-ci-342','南歌子','张孝祥','宋','宋词','song-ci','南歌子','[]','人物羲皇上，诗名沈谢间。',62,'宋词/ci.song.2000.json','["人物羲皇上，诗名沈谢间。", "漫郎元自谩为官。", "醉眼瞢腾、只拟看湘山。", "小隐今成趣，邻翁独往还。", "野堂梅柳尚春寒。", "且趁华灯、频泛酒船宽。"]'),
('song-ci-343','霜天晓角','张孝祥','宋','宋词','song-ci','霜天晓角','[]','柳丝无力。',53,'宋词/ci.song.2000.json','["柳丝无力。", "冉冉萦愁碧。", "系我船儿不住，楚江上、晚风急。", "棹歌休怨抑。", "有人离恨极。", "说与归期不远，刚不信、泪偷滴。"]'),
('song-ci-344','生查子','张孝祥','宋','宋词','song-ci','生查子','[]','远山眉黛横，媚柳开青眼。',48,'宋词/ci.song.2000.json','["远山眉黛横，媚柳开青眼。", "楼阁断霞明，帘幕春寒浅。", "杯延玉漏迟，烛怕金刀剪。", "明月忽飞来，花影和帘卷。"]'),
('song-ci-345','长相思','张孝祥','宋','宋词','song-ci','长相思','[]','小楼重。',44,'宋词/ci.song.2000.json','["小楼重。", "下帘栊。", "万点芳心绿间红。", "秋千图画中。", "草茸茸。", "柳松松。", "细卷玻璃水面风。", "春寒依旧浓。"]'),
('song-ci-346','忆秦娥','张孝祥','宋','宋词','song-ci','忆秦娥','[]','元宵节。',56,'宋词/ci.song.2000.json','["元宵节。", "凤楼相对鳌山结。", "鳌山结。", "香尘随步，柳梢微月。", "多情又把珠帘揭。", "游人不放笙歌歇。", "笙歌歇。", "晓烟轻散，帝城宫阕。"]'),
('song-ci-347','苍梧谣・归字谣','张孝祥','宋','宋词','song-ci','苍梧谣・归字谣','[]','归。',20,'宋词/ci.song.2000.json','["归。", "十万人家儿样啼。", "公归去，何日是来时。"]'),
('song-ci-348','苍梧谣・归字谣','张孝祥','宋','宋词','song-ci','苍梧谣・归字谣','[]','归。',20,'宋词/ci.song.2000.json','["归。", "猎猎薰风飐绣旗。", "拦教住，重举送行杯。"]'),
('song-ci-349','苍梧谣・归字谣','张孝祥','宋','宋词','song-ci','苍梧谣・归字谣','[]','归。',20,'宋词/ci.song.2000.json','["归。", "数得宣麻拜相时。", "秋前后，公衮更莱衣。"]'),
('song-ci-350','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','天上掌纶手，阃外折冲才。',114,'宋词/ci.song.2000.json','["天上掌纶手，阃外折冲才。", "发踪指示，平荡全楚息氛埃。", "缓带轻裘多暇，燕寝森严兵卫，香篆几徘徊。", "襦绔见歌咏，桃李藉栽培。", "紫泥封，天笔润，日边来。", "趣装入觐，行矣归去作盐梅。", "祖帐不须遮道，看取眉间一点，喜气入尊罍。", "此去沙堤路，平步上三台。"]'),
('song-ci-351','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','[]','客里送行客，常苦不胜情。',114,'宋词/ci.song.2000.json','["客里送行客，常苦不胜情。", "见公秣马东去，底事却欣欣。", "不为青毡俯拾，自是公家旧物，何必更关心。", "且喜谢安石，重起为苍生。", "圣天子，方侧席，选豪英。", "日边仍有知己，应剡荐章间。", "好把文经武略，换取碧幢红旆，谈笑扫胡尘。", "勋业在此举，莫厌短长亭。"]'),
('song-ci-352','木兰花・玉楼春','张孝祥','宋','宋词','song-ci','木兰花・玉楼春','[]','拥貔貅万骑，聚千里、铁衣寒。',124,'宋词/ci.song.2000.json','["拥貔貅万骑，聚千里、铁衣寒。", "正玉帐连云，油幢映日，飞箭天山。", "锦城起方面重，对筹壶、尽日雅歌闲。", "休遣沙场虏骑，尚馀匹马空还。", "那看。", "更值春残。", "斟绿醑、对朱颜。", "正宿雨催红，和风换翠，梅小香悭。", "牙旗渐西去也，望梁州、故垒暮云间。", "休使佳人敛黛，断肠低唱阳关。"]'),
('song-ci-353','雨中花・夜行船','张孝祥','宋','宋词','song-ci','雨中花・夜行船','[]','一舸凌风，斗酒酹江，翩然乘兴东游。',119,'宋词/ci.song.2000.json','["一舸凌风，斗酒酹江，翩然乘兴东游。", "欲吐平生孤愤，壮气横秋。", "浩荡锦囊诗卷，从容玉帐兵筹。", "有当时桥下，取履仙翁，谈笑同舟。", "先贤济世，偶耳功名，事成岂为封留。", "何况我、君恩深重，欲报无由。", "长望东南气王，从教西北云浮。", "断鸿万里，不堪回首，赤县神州。"]'),
('song-ci-354','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','可意黄花人不知。',64,'宋词/ci.song.2000.json','["可意黄花人不知。", "黄花标格世间稀。", "园葵裛露迎朝日，槛菊迎霜媚夕霏。", "芍药好，是金丝。", "绿藤红刺引蔷薇。", "姚家别有神仙品，似着天香染御衣。"]'),
('song-ci-355','眼儿媚','张孝祥','宋','宋词','song-ci','眼儿媚','[]','晓来江上荻花秋。',58,'宋词/ci.song.2000.json','["晓来江上荻花秋。", "做弄个离愁。", "半竿残日，两行珠泪，一叶扁舟。", "须知此去应难遇，直待醉方休。", "如今眼底，明朝心上，后日眉头。"]'),
('song-ci-356','虞美人','张孝祥','宋','宋词','song-ci','虞美人','[]','清宫初入韶华管。',66,'宋词/ci.song.2000.json','["清宫初入韶华管。", "宫叶秋声满。", "满庭芳草月婵娟。", "想见明朝喜色、动天颜。", "持杯满劝龙头客。", "荣遇时难得。", "词源三峡泻瞿塘。", "便是醉中空去、也无妨。"]'),
('song-ci-357','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','史君家枕吴波碧。',52,'宋词/ci.song.2000.json','["史君家枕吴波碧。", "朱门铺手摇双戟。", "也到岭边州。", "真成汗漫游。", "归期应不远。", "趁得东江暖。", "翁媪雪垂肩。", "双双平地仙。"]'),
('song-ci-358','临江仙','张孝祥','宋','宋词','song-ci','临江仙','[]','罨画楼前初立马，隔帘笑语相亲。',70,'宋词/ci.song.2000.json','["罨画楼前初立马，隔帘笑语相亲。", "铅华洗尽见天真。", "衫儿轻罩雾，髻子直梳云。", "翠叶银丝簪末利，樱桃澹住香唇。", "见人不语解留人。", "数杯愁里酒，两眼醉时春。"]'),
('song-ci-359','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','我是临川旧史君。',48,'宋词/ci.song.2000.json','["我是临川旧史君。", "而今欲作岭南人。", "重来辽鹤事犹新。", "去路政长仍酷暑，主公交契更情亲。", "横秋阁上晚风匀。"]'),
('song-ci-360','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','康乐亭前种此君。',48,'宋词/ci.song.2000.json','["康乐亭前种此君。", "重来风月苦留人。", "儿童竹马笑谈新。", "今代孟士仍好客，政成归去眷方新。", "十眉环坐晚妆匀。"]'),
('song-ci-361','西江月','张孝祥','宋','宋词','song-ci','西江月','["\u897f\u6e56"]','十里轻红自笑，两山浓翠相呼。',58,'宋词/ci.song.2000.json','["十里轻红自笑，两山浓翠相呼。", "意行着脚到精庐。", "借我绳床小住。", "解饮不妨文字，无心更狎鸥鱼。", "一声长啸暮烟孤。", "袖手西湖归去。"]'),
('song-ci-362','忆秦娥','张孝祥','宋','宋词','song-ci','忆秦娥','[]','天一角。',56,'宋词/ci.song.2000.json','["天一角。", "南枝向我情如昨。", "情如昨。", "水寒烟淡，雾轻云薄。", "吹花嚼蕊愁无托。", "年华冉冉惊离索。", "惊离索。", "倩春留住，莫教摇落。"]'),
('song-ci-363','浣溪沙','张孝祥','宋','宋词','song-ci','浣溪沙','[]','湓浦从君已十年。',48,'宋词/ci.song.2000.json','["湓浦从君已十年。", "京江仍许借归船。", "相逢此地有因缘。", "十万貔貅环武帐，三千珠翠入歌筵。", "功成去作地行仙。"]'),
('song-ci-364','柳梢青','张孝祥','宋','宋词','song-ci','柳梢青','[]','碧云风月无多。',58,'宋词/ci.song.2000.json','["碧云风月无多。", "莫被名缰利锁。", "白玉为车，黄金作印，不恋休呵。", "争如对酒当歌。", "人是人非恁麽。", "年少甘罗，老成吕望，必竟如何。"]'),
('song-ci-365','卜算子','张孝祥','宋','宋词','song-ci','卜算子','[]','万里去担簦，谁识新丰旅。',52,'宋词/ci.song.2000.json','["万里去担簦，谁识新丰旅。", "好事些儿说与郎，奴是姮娥侣。", "若到广寒宫，但道奴传语。", "待我仙郎折桂枝，拣个高枝与。"]'),
('song-ci-366','柳梢青','张孝祥','宋','宋词','song-ci','柳梢青','[]','草底蛩吟。',61,'宋词/ci.song.2000.json','["草底蛩吟。", "烟横水际，月澹松阴。", "荷动香浓，竹深凉早，销尽烦襟。", "发稀浑不胜簪。", "更客里、吴霜暗侵。", "富贵功名，本来无意，何况如今。"]'),
('song-ci-367','瑞鹧鸪','张孝祥','宋','宋词','song-ci','瑞鹧鸪','[]','香佩潜分紫绣囊。',64,'宋词/ci.song.2000.json','["香佩潜分紫绣囊。", "野塘波急折鸳鸯。", "春风灞岸空回首，落日西陵更断肠。", "雪下哦诗怜谢女，花间为令胜潘郎。", "从今千里同明月，再约圜时拜夜香。"]'),
('song-ci-368','青玉案','张孝祥','宋','宋词','song-ci','青玉案','[]','相春堂上闻莺语。',80,'宋词/ci.song.2000.json','["相春堂上闻莺语。", "正花柳、芳菲处。", "有底尊前欢且舞。", "满堂宾客，紫泥丹诏，衮衮烟霄路。", "君王天纵资仁武。", "要尺箠、平骄虏。", "思得英雄亲驾驭。", "将军行矣，九重虚宁，谈笑清寰宇。"]'),
('song-ci-369','念奴娇','张孝祥','宋','宋词','song-ci','念奴娇','[]','海云四敛，太清楼、极目一天秋色。',120,'宋词/ci.song.2000.json','["海云四敛，太清楼、极目一天秋色。", "明月飞来云雾尽，城郭山川历历。", "良夜悠悠，西风袅袅，银汉冰轮侧。", "云霓三弄，广寒宫殿长笛。", "偏照紫府瑶台，香笼玉座，翠霭迷南北。", "天上人间凝望处，应有乘风归客。", "露滴金盘，凉生玉宇，满地新霜白。", "壶中清赏，画檐高挂虚碧。"]'),
('song-ci-370','念奴娇','张孝祥','宋','宋词','song-ci','念奴娇','[]','风帆更起，望一天秋色，离愁无数。',120,'宋词/ci.song.2000.json','["风帆更起，望一天秋色，离愁无数。", "明日重阳尊酒里，谁与黄花为主。", "别岸风烟，孤舟灯火，今夕知何处。", "不如江月，照伊清夜同去。", "船过采石江边，望夫山下，酌水应怀古。", "德耀归来虽富贵，忍弃平生荆布。", "默想音容，遥怜儿女，独立衡皋暮。", "桐乡君子，念予憔悴如许。"]'),
('song-ci-371','蓦山溪','张孝祥','宋','宋词','song-ci','蓦山溪','[]','雄风豪雨，时节清明近。',102,'宋词/ci.song.2000.json','["雄风豪雨，时节清明近。", "帘幕起轻寒，暖红炉、笑翻灰烬。", "阴藏迟日，欲验几多长，绣工慵，围棋倦，香篆频销印。", "茂林芳径，绿变红添润。", "桃杏意酣酣，占前头、一番花信。", "华堂尊酒，但作艳阳歌，禽声喜，流云尽，明日春游俊。"]'),
('song-ci-372','拾翠羽','张孝祥','宋','宋词','song-ci','拾翠羽','[]','春入园林，花信总诸迟速。',84,'宋词/ci.song.2000.json','["春入园林，花信总诸迟速。", "听鸣禽、稍迁乔木。", "夭桃弄色，海棠芬馥。", "风雨霁，芳径草心频绿。", "禊事才过，相次禁烟追逐。", "想千岁、楚人遗俗。", "青旗沽酒，各家炊熟。", "良夜游，明月胜烧花烛。"]'),
('song-ci-373','蝶恋花','张孝祥','宋','宋词','song-ci','蝶恋花','[]','烂烂明霞红日暮。',70,'宋词/ci.song.2000.json','["烂烂明霞红日暮。", "艳艳轻云，皓月光初吐。", "倾国倾城恨无语。", "彩鸾祥凤来还去。", "爱花常为花留住。", "今岁风光，又是前春处。", "醉倒扶归也休诉。", "习池人笑山翁语。"]'),
('song-ci-374','渔家傲','张孝祥','宋','宋词','song-ci','渔家傲','[]','红白莲房生一处。',72,'宋词/ci.song.2000.json','["红白莲房生一处。", "雪肌霞艳难为喻。", "当是神仙来紫府。", "双禀赋。", "人间相见犹相妒。", "清雨轻烟凝态度。", "风标公子来幽鹭。", "欲遣微波传尺素。", "歌曲误。", "醉中自有周郎顾。"]'),
('song-ci-375','夜游宫','张孝祥','宋','宋词','song-ci','夜游宫','[]','听话危亭句景。',71,'宋词/ci.song.2000.json','["听话危亭句景。", "芳郊迥、草长川永。", "不待崇冈与峻岭。", "倚栏杆，望无穷，心已领。", "万事浮云影。", "最旷阔、鹭闲鸥静。", "好是炎天烟雨醒。", "柳阴浓，芰荷香，风日冷。"]'),
('song-ci-376','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','桃换肌肤菊换妆。',64,'宋词/ci.song.2000.json','["桃换肌肤菊换妆。", "只疑春色到重阳。", "偷将天上千年艳，染却人间九日黄。", "新艳冶，旧风光。", "东篱分付武陵香。", "尊前醉眼空相顾，错认陶潜是阮郎。"]'),
('song-ci-377','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','人物风流册府仙。',64,'宋词/ci.song.2000.json','["人物风流册府仙。", "谁教落魄到穷边。", "独班未引甘泉伏，三峡先寻上水船。", "斟楚酒，扣湘弦。", "竹枝歌里意凄然。", "明时合下清猿泪，闲日须题采凤笺。"]'),
('song-ci-378','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','落霞残照横西阁。',52,'宋词/ci.song.2000.json','["落霞残照横西阁。", "阁西横照残霞落。", "波浅戏鱼多。", "多鱼戏浅波。", "手携行客酒。", "酒客行携手。", "肠断九歌长。", "长歌九断肠。"]'),
('song-ci-379','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','渚莲红乱风翻雨。',52,'宋词/ci.song.2000.json','["渚莲红乱风翻雨。", "雨翻风乱红莲渚。", "深处宿幽禽。", "禽幽宿处深。", "澹妆秋水鉴。", "鉴水秋妆澹。", "明月思情人。", "情人思月明。"]'),
('song-ci-380','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','晚花残雨风帘卷。',52,'宋词/ci.song.2000.json','["晚花残雨风帘卷。", "卷帘风雨残花晚。", "双燕语虚窗。", "窗虚语燕双。", "睡醒风惬意。", "意惬风醒睡。", "谁与话情诗。", "诗情话与谁。"]'),
('song-ci-381','菩萨蛮','张孝祥','宋','宋词','song-ci','菩萨蛮','[]','白头人笑花间客。',52,'宋词/ci.song.2000.json','["白头人笑花间客。", "客间花笑人头白。", "年去似流川。", "川流似去年。", "老羞何事好。", "好事何羞老。", "红袖舞香风。", "风香舞袖红。"]'),
('song-ci-382','南歌子','张孝祥','宋','宋词','song-ci','南歌子','[]','路尽湘江水，人行瘴雾间。',62,'宋词/ci.song.2000.json','["路尽湘江水，人行瘴雾间。", "昏昏西北度严关。", "天外一簪初见、岭南山。", "北雁连书断，秋霜点鬓斑。", "此行休问几时还。", "唯拟桂林佳处、过春残。"]'),
('song-ci-383','燕归梁','张孝祥','宋','宋词','song-ci','燕归梁','[]','风柳摇丝花缠枝。',59,'宋词/ci.song.2000.json','["风柳摇丝花缠枝。", "满目韶辉。", "离鸿过尽百劳飞。", "都不似、燕来归。", "旧来王谢堂前地，情分独依依。", "画梁雕拱启朱扉。", "看双舞、羽人衣。"]'),
('song-ci-384','卜算子','张孝祥','宋','宋词','song-ci','卜算子','[]','风生杜若洲，日暮垂杨浦。',52,'宋词/ci.song.2000.json','["风生杜若洲，日暮垂杨浦。", "行到田田乱叶边，不见凌波女。", "独自倚危栏，欲向荷花语。", "无奈荷花不应人，背立啼红雨。"]'),
('song-ci-385','点绛唇','张孝祥','宋','宋词','song-ci','点绛唇','[]','秩秩宾筵，玉潭春涨玻璃满。',50,'宋词/ci.song.2000.json','["秩秩宾筵，玉潭春涨玻璃满。", "旆霞风卷。", "可但长安远。", "夏木成阴，路袅薰风转。", "空留恋。", "细吹银管。", "别意随声缓。"]'),
('song-ci-386','水调歌头','张孝祥','宋','宋词','song-ci','水调歌头','["\u5cb3\u9633\u697c"]','湖海倦游客，江汉有归舟。',114,'宋词/ci.song.2000.json','["湖海倦游客，江汉有归舟。", "西风千里，送我今夜岳阳楼。", "日落君山云气，春到沅湘草木，远思渺难收。", "徙倚栏杆久，缺月挂帘钩。", "雄三楚，吞七泽，隘九州。", "人间好处，何处更似此楼头。", "欲吊沈累无所，但有渔儿樵子，哀此写离忧。", "回首叫虞舜，杜若满芳洲。"]'),
('song-ci-387','锦园春','张孝祥','宋','宋词','song-ci','锦园春','[]','醉痕潮玉。',56,'宋词/ci.song.2000.json','["醉痕潮玉。", "爱柔英未吐，露花如簇。", "绝艳矜春，分流芳金谷。", "风梳雨沐。", "偏只欠、夜阑清淑。", "杜老情疏，黄州恨冷，谁怜幽独。"]'),
('song-ci-388','天仙子','张孝祥','宋','宋词','song-ci','天仙子','[]','三月灞桥烟共雨。',80,'宋词/ci.song.2000.json','["三月灞桥烟共雨。", "拂拂依依飞到处。", "雪逑轻扬弄精神，扑不住。", "留不住。", "常系柔肠千万缕。", "只恐舞风无定据。", "容易著人容易去。", "肯将心绪向才郎，待拟处。", "终须与。", "作个罗帏收拾取。"]'),
('song-ci-389','鹧鸪天','张孝祥','宋','宋词','song-ci','鹧鸪天','[]','日日青楼醉梦中。',64,'宋词/ci.song.2000.json','["日日青楼醉梦中。", "不知楼外已春浓。", "杏花未遇疏疏雨，杨柳初摇短短风。", "扶画鹢，跃花骢。", "涌金门外小桥东。", "行行又入笙歌里，人在珠帘第几重。"]'),
('song-ci-390','风入松','张孝祥','宋','宋词','song-ci','风入松','[]','玉妃孤艳照冰霜。',86,'宋词/ci.song.2000.json','["玉妃孤艳照冰霜。", "初试道家妆。", "素衣嫌怕姮娥妒，染成宫样鹅黄。", "宫额娇涂飞燕，缕金愁立秋娘。", "湘罗百濯蹙香囊。", "蜜露缀琼芳。", "蔷薇水蘸檀心紫，郁金薰染浓香。", "萼绿轻移云袜，华清低舞霓裳。"]'),
('song-ci-391','瑞鹧鸪','郭世模','宋','宋词','song-ci','瑞鹧鸪','[]','倾城一笑得留人。',64,'宋词/ci.song.2000.json','["倾城一笑得留人。", "舞罢娇娥敛黛愁。", "明月宝鞲金洛臂，翠琼花珥碧搔头。", "晴云片雪腰支袅，晚吹微波眼色秋。", "清露亭皋芳草绿，轻绡软挂玉帘钩。"]'),
('song-ci-392','瑞鹤仙','郭世模','宋','宋词','song-ci','瑞鹤仙','[]','云阶连月地。',127,'宋词/ci.song.2000.json','["云阶连月地。", "记旧游、身在温柔乡里。", "花阴透窗绮。", "罗衾拥残梦，流莺惊起。", "银瓶水沸。", "待梳妆、屏风共倚。", "看情眉恨眼，宿粉剩香，乱愁无际。", "长记。", "多情消减，宋玉连墙，茂陵同里。", "离怀似水。", "天涯路，叹愁悴。", "想鸳机织锦，鸾台窥镜，秦丝幽怨未已。", "好归去、共把琴书，倚娇扶醉。"]'),
('song-ci-393','朝中措','郭世模','宋','宋词','song-ci','朝中措','[]','青灯听雨夜荒凉。',57,'宋词/ci.song.2000.json','["青灯听雨夜荒凉。", "归梦苦难长。", "坐想玉奁鸳锦，空馀臂粉衣香。", "枕边共语，窗前执手，帘外啼妆。", "也是平生薄幸，须还几度思量。"]'),
('song-ci-394','南歌子','郭世模','宋','宋词','song-ci','南歌子','[]','玉盏浮琼蚁，金奁吐翠虬。',62,'宋词/ci.song.2000.json','["玉盏浮琼蚁，金奁吐翠虬。", "醉乡归路接温柔。", "暗卜幽期低约、笑藏阄。", "索去眉先锁，将言泪已流。", "小窗移火更迟留。", "自剔灯花油涴、玉搔头。"]'),
('song-ci-395','念奴娇','郭世模','宋','宋词','song-ci','念奴娇','[]','光风转蕙，泛崇兰、漠漠满城飞絮。',120,'宋词/ci.song.2000.json','["光风转蕙，泛崇兰、漠漠满城飞絮。", "金谷楼危山共远，几点亭亭烟树。", "枝上残花，胭脂满地，乱落如红雨。", "青春将暮，玉箫声在何处。", "无端天与娉婷，帘钩鹦鹉，梦断闻残语。", "玉骨瘦来无一把，手挹罗衣看取。", "江北江南，灵均去后，谁采苹花与。", "香销云散，断魂分付潮去。"]'),
('song-ci-396','浣溪沙','郭世模','宋','宋词','song-ci','浣溪沙','[]','几点胭脂印指红。',48,'宋词/ci.song.2000.json','["几点胭脂印指红。", "一双蛾绿敛眉浓。", "夜寒绡帐烛花融。", "剩炷龙涎熏骨冷，旋调银液镇心忪。", "整鬟羞顾半娇慵。"]'),
('song-ci-397','木兰花・玉楼春','黄仁荣','宋','宋词','song-ci','木兰花・玉楼春','[]','监郡风流欢洽。',7,'宋词/ci.song.2000.json','["监郡风流欢洽。"]'),
('song-ci-398','失调名','许左之','宋','宋词','song-ci','失调名','[]','谁知花有主。',24,'宋词/ci.song.2000.json','["谁知花有主。", "误入花深处。", "放直下、酒杯乾、便归去。"]'),
('song-ci-399','失调名','许左之','宋','宋词','song-ci','失调名','[]','忆你当初，惜我不去。',20,'宋词/ci.song.2000.json','["忆你当初，惜我不去。", "伤我如今，留你不住。"]'),
('song-ci-400','念奴娇','黄谈','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','午风清暑，过西湖隐约，曾游堤路。',120,'宋词/ci.song.2000.json','["午风清暑，过西湖隐约，曾游堤路。", "云径烟扉人境绝，真是珠宫玄圃。", "倦倚阑干，笑呼艇子，同入荷花去。", "一杯相属，恍然身在何许。", "休怪梦入巫云，凌波罗袜，我在迷湘浦。", "缥缈惊鸿飞燕举，却怨严城钟鼓。", "百斛明珠，千金骏马，豪气今犹故。", "归来清晓，幅巾犹带香露。"]'),
('song-ci-401','水调歌头','张','宋','宋词','song-ci','水调歌头','[]','雪月两相映，水石互悲鸣。',112,'宋词/ci.song.2000.json','["雪月两相映，水石互悲鸣。", "不知岩上枯木，今夜若为情。", "应见尘中胶扰，便道山间空旷，与麽了平生。", "与麽平生了，□水不流行。", "起披衣，瞻碧汉，露华清。", "寥寥千载，此事本分明。", "若向乾坤识易，便信行藏无间，处处总圆成。", "记取渊冰语，莫错定盘星。"]'),
('song-ci-402','水龙吟','阎苍舒','宋','宋词','song-ci','水龙吟','[]','少年闻说京华，上元景色烘晴昼。',126,'宋词/ci.song.2000.json','["少年闻说京华，上元景色烘晴昼。", "朱轮画毂，雕鞍玉勒，九衢争骤。", "春满鳌山，夜沈陆海，一天星斗。", "正红球过了，鸣鞘声断，迥鸾驭、钧天奏。", "谁料此生亲到，十五年、都城如旧。", "而今但有，伤心烟雾，萦愁杨柳。", "宝箓宫前，绛霄楼下，不堪回首。", "愿皇图早复，端门灯火，照人还又。"]'),
('song-ci-403','柳梢青','崔敦礼','宋','宋词','song-ci','柳梢青','[]','惊世文章，门户照人，外家衣钵。',61,'宋词/ci.song.2000.json','["惊世文章，门户照人，外家衣钵。", "多谢温存，相期宅相，此恩难说。", "今朝祝寿樽前，共拜舞、诸孙下列。", "但愿从今，一年强似，一年时节。"]'),
('song-ci-404','西江月','崔敦礼','宋','宋词','song-ci','西江月','[]','暖日江南梅柳，春风堂上笙歌。',58,'宋词/ci.song.2000.json','["暖日江南梅柳，春风堂上笙歌。", "满斟醽醁笑声哗。", "再拜千年寿嘏。", "清健非缘服玉，红颜不是苍霞。", "仙姿福禄自无涯。", "要看沧溟绿野。"]'),
('song-ci-405','鹧鸪天','崔敦礼','宋','宋词','song-ci','鹧鸪天','[]','本是瑶台月里仙。',64,'宋词/ci.song.2000.json','["本是瑶台月里仙。", "笑麾鸾鹤住人间。", "蟠桃一熟三千岁，剩对春风日月闲。", "缡绶结，彩衣斑。", "孙枝相应傍门阑。", "年年同上长生酒，得见沧溟几度乾。"]'),
('song-ci-406','鹧鸪天','崔敦礼','宋','宋词','song-ci','鹧鸪天','[]','王母瑶池景物鲜。',64,'宋词/ci.song.2000.json','["王母瑶池景物鲜。", "蟠桃华宝不知年。", "天教把定春风笑，来作人间长寿仙。", "披蕊芨，诵云篇。", "朝朝香火篆炉烟。", "只将清静为真乐，合住春秋岁八千。"]'),
('song-ci-407','念奴娇','崔敦礼','宋','宋词','song-ci','念奴娇','[]','吴松江畔，对烟波浩渺，相忘鸥鸟。',120,'宋词/ci.song.2000.json','["吴松江畔，对烟波浩渺，相忘鸥鸟。", "日日篮舆湖上路，十里珠帘惊笑。", "高下楼台，浅深溪坞，著此香山老。", "辋川图上，好风吹梦曾到。", "不用金谷繁华，碧城修竹，自比封君号。", "万壑千岩天付与，一洗寒酸郊岛。", "霖雨方思，烟尘未扫，合挽三江倒。", "功成名遂，却来依旧华表。"]'),
('song-ci-408','水调歌头','崔敦礼','宋','宋词','song-ci','水调歌头','["\u592a\u6e56"]','倚棹太湖畔，踏月上垂虹。',114,'宋词/ci.song.2000.json','["倚棹太湖畔，踏月上垂虹。", "银涛万顷无际，渺渺欲浮空。", "为问瀛洲何在，我欲骑鲸归去，挥手谢尘笼。", "未得世缘了，佳处且从容。", "饮湖光，披晓月，抹春风。", "平生豪气安用，江海兴无穷。", "身在冰壶千里，独倚朱栏一啸，惊起睡中龙。", "此乐岂多得，归去莫匆匆。"]'),
('song-ci-409','江城子','崔敦礼','宋','宋词','song-ci','江城子','[]','吴王台上雨初晴。',86,'宋词/ci.song.2000.json','["吴王台上雨初晴。", "远烟横。", "柳如云。", "门外西风，催踏马啼尘。", "声断阳关人去□，遮落日，向西秦。", "不教容易纵归程。", "语酸辛。", "黯消魂。", "且共一尊，相属莫辞频。", "后夜月明千里隔，君忆我，我思君。"]'),
('song-ci-410','诉衷情','陈造','宋','宋词','song-ci','诉衷情','[]','今朝人自藕州来。',54,'宋词/ci.song.2000.json','["今朝人自藕州来。", "花意尚迟迥。", "几时画船同载，云锦照樽罍。", "铃斋外，已全开。", "是谁催，诗仙住处，和气回春，羯鼓如雷。"]'),
('song-ci-411','蝶恋花','陈造','宋','宋词','song-ci','蝶恋花','[]','山立翠屏开几面。',70,'宋词/ci.song.2000.json','["山立翠屏开几面。", "画舸经行，蒲葺□□岸。", "想过溪门帆影转。", "湖光忽作浮天远。", "诗卷来时春晼晚。", "愁把钓游，佳处寻思遍。", "不许冷官人所贱。", "拘缠自叹冰蚕茧。"]'),
('song-ci-412','洞仙歌','陈造','宋','宋词','song-ci','洞仙歌','["\u897f\u6e56"]','蝶狂风闹，不到凝香地。',103,'宋词/ci.song.2000.json','["蝶狂风闹，不到凝香地。", "谁见飞琼巧梳洗。", "厌孤标冷艳，不入时宜，银烛底，酒沁冰肌未睡。", "东君怜索寞，分寄寒斋，闹耐残醒嗅芳蕊。", "费西湖东阁，多少诗愁，援采笔、重与江梅品第。", "算肯容、丹杏接仙游，又却要蕊宫，侍香扶醉。"]'),
('song-ci-413','水调歌头','陈造','宋','宋词','song-ci','水调歌头','[]','胜日探梅去，邂逅得奇观。',114,'宋词/ci.song.2000.json','["胜日探梅去，邂逅得奇观。", "南枝的皪，陡觉品俗又香悭。", "曾是瑶妃清瘦，帝与金丹换骨，酒韵上韶颜。", "百叠侈罗袂，小立耐春寒。", "凝香地，古仙伯，玉尘间。", "烦公持并三友，秀色更堪飡。", "定笑芙蓉骚客，认作东风桃杏，醉眼自相谩。", "相见落诗笔，字字漱龙阑。"]'),
('song-ci-414','菩萨蛮','陈造','宋','宋词','song-ci','菩萨蛮','[]','冰花的皪冰蟾下。',52,'宋词/ci.song.2000.json','["冰花的皪冰蟾下。", "松烟竹雾溪桥夜。", "斜倚小峰峦。", "依依同岁寒。", "生绡明粉墨。", "浅笑犹倾国。", "恰似野桥看。", "飘零只等闲。"]'),
('song-ci-415','虞美人','陈造','宋','宋词','song-ci','虞美人','[]','凝香仙伯莺花主。',66,'宋词/ci.song.2000.json','["凝香仙伯莺花主。", "雅意怜羁旅。", "略分春色便浓欢。", "街吏何妨日日、报平安。", "诗人一醉龙公妒。", "恰限今朝雨。", "关门独酌强伸眉。", "也胜栖栖腰铺、守风时。"]'),
('song-ci-416','鹧鸪天','陈造','宋','宋词','song-ci','鹧鸪天','[]','闲去街头赏大花。',64,'宋词/ci.song.2000.json','["闲去街头赏大花。", "翠帷珠幰护豪华。", "西真宴罢群仙醉，千尺黄云错紫霞。", "团粉黛，闹箫笳。", "使星躔处住灵槎。", "定知今夜游仙梦，不落西京姚魏家。"]'),
('song-ci-417','鹧鸪天','陈造','宋','宋词','song-ci','鹧鸪天','[]','遍赏扬州百种花。',64,'宋词/ci.song.2000.json','["遍赏扬州百种花。", "因循忘却鬓苍华。", "客闲惯刻分题烛，坐久还生醉眼霞。", "催掺鼓，趁鸣笳。", "未应回首问归槎。", "清明寒食风烟地，判到今春不著家。"]'),
('song-ci-418','鹧鸪天','陈造','宋','宋词','song-ci','鹧鸪天','[]','醉阅东风百种花。',64,'宋词/ci.song.2000.json','["醉阅东风百种花。", "醒来长悔误随车。", "须知绿幕黄帘底，别有春藏姚魏家。", "空想像，胜惊嗟。", "梦云从此漫天涯。", "二年得趁花前约，潘鬓缘愁恐更华。"]'),
('song-ci-419','江神子・江城子','陈造','宋','宋词','song-ci','江神子・江城子','[]','歌筵当日小蓬瀛。',86,'宋词/ci.song.2000.json','["歌筵当日小蓬瀛。", "晚妆明。", "识芳卿。", "挽袖新词，曾博遏云声。", "又侍仙翁灯夕饮，红雾底，沸箫笙。", "催人刻烛待诗成。", "捧雕觥。", "媚盈盈。", "不道醉魂，入夜已瞢腾。", "墨涴香罗回盼处，和笑道，太狂生。"]'),
('song-ci-420','鹧鸪天','黄定','宋','宋词','song-ci','鹧鸪天','[]','间世文章万选钱。',64,'宋词/ci.song.2000.json','["间世文章万选钱。", "清时平步八花砖。", "大开紫府瑶池宴，正是橙黄橘绿天。", "金烛里，玉堂前。", "翰林元是武夷仙。", "雍容草罢明堂诏，留取天香馥寿筵。"]'),
('song-ci-421','念奴娇','王自中','宋','宋词','song-ci','念奴娇','[]','扁舟夜泛，向子陵台下，偃帆收橹。',120,'宋词/ci.song.2000.json','["扁舟夜泛，向子陵台下，偃帆收橹。", "水阔风摇舟不定。", "依约月华新吐。", "细酌清泉，痛浇尘臆，唤起先生语。", "当年纶钓，为谁高卧烟渚。", "还念古往今来，功名可共，能几人光武。", "一旦星文惊四海，从此故人何许。", "到底轩裳，不如蓑笠，久矣心相与。", "天低云淡，浩然吾欲高举。"]'),
('song-ci-422','水调歌头','李处全','宋','宋词','song-ci','水调歌头','[]','金节照南国，画戟壮陪都。',114,'宋词/ci.song.2000.json','["金节照南国，画戟壮陪都。", "严谯古角霜晓，雄胜压全吴。", "葱倩采香古径，缥缈折梅新奏，春事早关渠。", "谁识使君意，行乐与民俱。", "披绣幌，薰宝篆，引琼酥。", "黄堂富暇，宾幕谈笑足欢娱。", "看取十行丹诏，遥指五云深处，归路接亨衢。", "玉佩映鸳缀，不老奉轩虞。"]'),
('song-ci-423','水调歌头','李处全','宋','宋词','song-ci','水调歌头','[]','上马趣携酒，送客古朱方。',114,'宋词/ci.song.2000.json','["上马趣携酒，送客古朱方。", "秋风斜日山际，低草见牛羊。", "酩酊不知更漏，但见横江白露，清映月如霜。", "平睨广寒殿，谁说路歧长。", "醉还醒，时起舞，念吾乡。", "江山尔尔，回首千载几兴亡。", "一笑书生事业，谁信管城居士，不换碧油幢。", "好在中冷水，击楫奏伊凉。"]'),
('song-ci-424','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','静乐堂中禅悦身。',64,'宋词/ci.song.2000.json','["静乐堂中禅悦身。", "相家庆袭两家春。", "瑶池云气冲霄鹤，兰砌风标瑞世麟。", "华屋邃，宝杯新。", "年年秋与月常明。", "笙箫且奏长生曲，宣劝还看送喜频。"]'),
('song-ci-425','忆秦娥','韩淲','宋','宋词','song-ci','忆秦娥','[]','香滴滴。',56,'宋词/ci.song.2000.json','["香滴滴。", "肌肤冰雪娇无力。", "娇无力。", "秋风凉冷，有谁消得。", "洗妆不奈云鬟侧。", "璧堂珠院空相忆。", "空相忆。", "轻颦浅笑，小梅标格。"]'),
('song-ci-426','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','熏风两节照稽山。',57,'宋词/ci.song.2000.json','["熏风两节照稽山。", "三百里湖间。", "镜上谁为贺老，棹船能伴官闲。", "今年寿日，不妨吟啸，还上清班。", "为寄长生新曲，齐眉想见酡颜。"]'),
('song-ci-427','醉落魄・一斛珠','韩淲','宋','宋词','song-ci','醉落魄・一斛珠','[]','风高木落。',67,'宋词/ci.song.2000.json','["风高木落。", "壮心万里空回薄。", "振衣待把尘埃濯。", "声里斜阳，孤起戍楼角。", "人生谁会谁为错。", "年来但觉多离索。", "黄花照地浑开却。", "华发如斯，同和醉落魄。"]'),
('song-ci-428','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','山林锺鼎似无同。',57,'宋词/ci.song.2000.json','["山林锺鼎似无同。", "舒卷有穷通。", "洗出壶中三峡，帝城赢得从容。", "黄流乱注，狂澜既倒，砥柱能东。", "此际诞弥杯酒，宜歌风虎云龙。"]'),
('song-ci-429','西江月','韩淲','宋','宋词','song-ci','西江月','[]','日日山迷水癖，年年书恼诗痴。',58,'宋词/ci.song.2000.json','["日日山迷水癖，年年书恼诗痴。", "寻思那里要他知。", "试比古人犹未。", "往往眼甜口苦，常常心是身非。", "如何则甚破他疑。", "只学今人足矣。"]'),
('song-ci-430','阮郎归','韩淲','宋','宋词','song-ci','阮郎归','[]','小楼秋霁碧阑干。',56,'宋词/ci.song.2000.json','["小楼秋霁碧阑干。", "中人初薄寒。", "霜风吹我到湖山。", "平林斜照残。", "空阔里，有无间。", "牵萝翠袖闲。", "篮舆兴尽却愁还。", "断肠歌未阑。"]'),
('song-ci-431','好事近','韩淲','宋','宋词','song-ci','好事近','[]','湖上有孤山，合把探梅词刻。',53,'宋词/ci.song.2000.json','["湖上有孤山，合把探梅词刻。", "清浅黄昏时候，冷疏枝寒色。", "窗前忽到又如何，一夜足相忆。", "信道收香藏白，报春风消息。"]'),
('song-ci-432','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','买得船儿去下湖。',48,'宋词/ci.song.2000.json','["买得船儿去下湖。", "这些天气近来无。", "清和风里绿阴初。", "酒不为渠闲放荡，诗应嫌我太粗疏。", "酒徒诗社复何如。"]'),
('song-ci-433','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','江上新凉入酒杯。',48,'宋词/ci.song.2000.json','["江上新凉入酒杯。", "瑞芝堂祝寿筵开。", "五楼百雉更崔嵬。", "劳来流离施菽麦，作成丰稔到田莱。", "便朝天去也徘徊。"]'),
('song-ci-434','醉桃源・阮郎归','韩淲','宋','宋词','song-ci','醉桃源・阮郎归','[]','残春风雨绕檐声。',56,'宋词/ci.song.2000.json','["残春风雨绕檐声。", "山空分外鸣。", "闲来落佩倒冠缨。", "尚馀亲旧情。", "人不见，句还成。", "又听求友莺。", "濯缨一曲可流行。", "何须观我生。"]'),
('song-ci-435','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','留得菖蒲酒一杯。',48,'宋词/ci.song.2000.json','["留得菖蒲酒一杯。", "与公今日寿筵开。", "灵山排闼送青来。", "须信南州高士后，持荷持节照苏台。", "瑞云深处是三台。"]'),
('song-ci-436','醉桃源・阮郎归','韩淲','宋','宋词','song-ci','醉桃源・阮郎归','[]','固穷斋里语吾生。',56,'宋词/ci.song.2000.json','["固穷斋里语吾生。", "言之必可行。", "扶疏夏木既啼莺。", "更逢鱼计成。", "多雅尚，少时情。", "沧浪渔父缨。", "高歌宁与俗争鸣。", "朱弦疏越声。"]'),
('song-ci-437','减字木兰花','韩淲','宋','宋词','song-ci','减字木兰花','[]','从心所欲。',52,'宋词/ci.song.2000.json','["从心所欲。", "高蹈祠官惟见独。", "其寿伊何。", "古井章泉水不波。", "腊前梅好。", "玉洁日光香耐老。", "才大三千。", "首首清诗得自编。"]'),
('song-ci-438','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','归来又喜山中约。',52,'宋词/ci.song.2000.json','["归来又喜山中约。", "菊枝桂树真宜酌。", "兴尽只观山。", "秋深方闭关。", "会须追雅步。", "策蹇或肩舆。", "少待必能治。", "膏肓泉石医。"]'),
('song-ci-439','百字令・念奴娇','韩淲','宋','宋词','song-ci','百字令・念奴娇','[]','园居好处，是古梅飞动、欺霜凌雪。',120,'宋词/ci.song.2000.json','["园居好处，是古梅飞动、欺霜凌雪。", "底问纷华桃李态，自倚天姿明洁。", "城外灵山，桥头玉水，多少佳风月。", "岁寒时候，南枝尤与清绝。", "几回唤酒寻诗，诗成小醉，絮帽浑敧侧。", "领略不辞身跌宕，一洗群儿啁哳。", "太始遗音，元和新样，到了都难说。", "草玄经在，对花何闷孤寂。"]'),
('song-ci-440','一翦梅','韩淲','宋','宋词','song-ci','一翦梅','[]','醉倒城中不过溪。',72,'宋词/ci.song.2000.json','["醉倒城中不过溪。", "溪外无尘，惟掩柴扉。", "水浮桥漾翠烟霏。", "一片闲情，能几人知。", "留饮君家絮帽敧。", "爆竹声中，万事如斯。", "梅催春动已熹微。", "尔既能来，我亦何疑。"]'),
('song-ci-441','贺新郎','韩淲','宋','宋词','song-ci','贺新郎','[]','又见年年雪。',142,'宋词/ci.song.2000.json','["又见年年雪。", "水浮桥、南岸幽处，周遭森列。", "横碧轩中空旧话，独钓寒江愁绝。", "更一段、冰霜高洁。", "忽得两篇强健曲，倚回风、洒急凭谁说。", "嗟巩雒，乃闽浙。", "何当醉酒扬雄宅。", "问避人避地，其如楚之舆接。", "览德已而歌凤去，千仞辉翔难蹑。", "我和句、却愁狂辄。", "折尽梅花伤岁暮，□撒盐、起絮分才劣。", "鸡犬静，涧篱�怼�"]'),
('song-ci-442','点绛唇','韩淲','宋','宋词','song-ci','点绛唇','[]','竹隐高深，夏凉日有清风度。',50,'宋词/ci.song.2000.json','["竹隐高深，夏凉日有清风度。", "苎衣绳屦。", "鹤发空相顾。", "翠扑流烟，又向溪翁去。", "青山路。", "要当同住。", "长占无尘处。"]'),
('song-ci-443','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','秋林只共秋风老。',52,'宋词/ci.song.2000.json','["秋林只共秋风老。", "秋山却笑秋吟少。", "恰恨有秋香。", "青岩秋夜凉。", "清秋须是酒。", "结客秋知否。", "醉笔写成秋。", "一秋无复愁。"]'),
('song-ci-444','祝英台近','韩淲','宋','宋词','song-ci','祝英台近','[]','海棠开，春已半，桃李又如许。',95,'宋词/ci.song.2000.json','["海棠开，春已半，桃李又如许。", "一朵梨花，院落阑干雨。", "不禁中酒情怀，爱闲懊恼，都忘却、旧题诗处。", "燕莺语。", "溪岸点点飞绵，杨柳无重数。", "带得愁来，莫恁空休去。", "断肠芳草天涯，行云荏苒，和好梦、有谁分付。"]'),
('song-ci-445','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','人已醉。',53,'宋词/ci.song.2000.json','["人已醉。", "溪北溪南春意。", "击鼓吹箫花落未。", "杏梅桃共李。", "水底鱼龙惊起。", "推枕月明千里。", "伊吕衰翁徒尔耳。", "我怀犹未是。"]'),
('song-ci-446','虞美人','韩淲','宋','宋词','song-ci','虞美人','[]','晓来一阵催花雨。',68,'宋词/ci.song.2000.json','["晓来一阵催花雨。", "正桃李、横塘处。", "笙歌帘幕燕莺喧。", "春在人间不老、谷城仙。", "潇湘图画迎千骑。", "襦裤欢声起。", "功名风虎庆云龙。", "更看万钉横带、系金狨。"]'),
('song-ci-447','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','水南何事兴偏浓。',56,'宋词/ci.song.2000.json','["水南何事兴偏浓。", "花草小园中。", "山气静分馀霭，泉声幽转流淙。", "午桥坐上英豪客，今昔为谁容。", "不是倚楼人在，登临无复携筇。"]'),
('song-ci-448','卜算子','韩淲','宋','宋词','song-ci','卜算子','[]','烟雨海棠花，春夜沈沈酌。',52,'宋词/ci.song.2000.json','["烟雨海棠花，春夜沈沈酌。", "寒食清明数日间，人也须行乐。", "不怕笛声长，只怕风儿恶。", "烛影红酣宝篆香，楼上黄昏角。"]'),
('song-ci-449','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','闲度日。',53,'宋词/ci.song.2000.json','["闲度日。", "愁里费人辞辟。", "榆火新烟还熟食。", "小墙花槛直。", "锦字玉徽清集。", "何用主人留客。", "相赏暂时谁画得。", "庞公非浪出。"]'),
('song-ci-450','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','锦瑟瑶琴续断弦。',48,'宋词/ci.song.2000.json','["锦瑟瑶琴续断弦。", "璧堂初过牡丹天。", "玉钩斜压小珠帘。", "睡鸭炉温吟散后，双鸳屏掩酒醒前。", "一番春事怨啼鹃。"]'),
('song-ci-451','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','丝丝柳色清愁织。',52,'宋词/ci.song.2000.json','["丝丝柳色清愁织。", "山城望断花溪碧。", "回首仲宣楼。", "登临无计愁。", "雨声吹海立。", "流转韶光急。", "九万有鹏程。", "沈香天上亭。"]'),
('song-ci-452','好事近','韩淲','宋','宋词','song-ci','好事近','[]','梅雨快晴风，苔竹定翻新箨。',53,'宋词/ci.song.2000.json','["梅雨快晴风，苔竹定翻新箨。", "相望得寻幽调，把陈言都略。", "大江东去更飞云，心事共回薄。", "彷佛散庵佳处，一声声猿鹤。"]'),
('song-ci-453','好事近','韩淲','宋','宋词','song-ci','好事近','[]','黄发享颐期，兄弟此时宜告。',53,'宋词/ci.song.2000.json','["黄发享颐期，兄弟此时宜告。", "见说对床夜雨，世间尘都扫。", "青毡堂外瑞峰高，云气拂晴昊。", "老大中原人物，在江湖乡保。"]'),
('song-ci-454','好事近','韩淲','宋','宋词','song-ci','好事近','[]','三叠古藤阴，自笑无能为役。',53,'宋词/ci.song.2000.json','["三叠古藤阴，自笑无能为役。", "千载和陶新曲，了非仙非释。", "影徒随我月徘徊，风叶露华湿。", "瓮下是成真逸，醉令人思毕。"]'),
('song-ci-455','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','霓裳霞佩淡丰容。',56,'宋词/ci.song.2000.json','["霓裳霞佩淡丰容。", "云冷露华浓。", "唤起石丁归去，冥冥仙仗崆峒。", "人间秋老花饶笑，清映小帘栊。", "记取五城深处，凤箫吹下天风。"]'),
('song-ci-456','水调歌头','韩淲','宋','宋词','song-ci','水调歌头','[]','新月已如许，我问带湖梅。',114,'宋词/ci.song.2000.json','["新月已如许，我问带湖梅。", "人闲题句，赢得浮潋酒盈杯。", "落拓豪英满坐，烂漫风骚连纸，天外凤凰来。", "只怕轻孤负，莫待巧安排。", "空翠滴，寒爽矣，晚佳哉。", "为君绝倒，折尽千树玉蓓堆。", "渺渺章泉好在，寂寂卢泉仙去，今古付尊罍。", "拍手见花木，放眼记莓苔。"]'),
('song-ci-457','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','看了香梅看瑞香。',64,'宋词/ci.song.2000.json','["看了香梅看瑞香。", "月桥花槛更云窗。", "不知是有春多少，玉水灵山醉几场。", "闲蝶梦，褪蜂黄。", "尽温柔处尽端相。", "珠帘十里扬州路，赢得潘郎两鬓霜。"]'),
('song-ci-458','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','今年是处梅花早。',52,'宋词/ci.song.2000.json','["今年是处梅花早。", "分明开到章泉好。", "兄弟寿杯同。", "暗香明月风。", "风流文物旧。", "春意枝枝透。", "儿侄定飞轩。", "衣冠与世传。"]'),
('song-ci-459','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','聚星亭下书堂水。',52,'宋词/ci.song.2000.json','["聚星亭下书堂水。", "冬来欲问梅花使。", "圭撮是何官。", "人间有底难。", "章泉词和去。", "交道元如故。", "转眼岁将穷。", "溪头鹤发翁。"]'),
('song-ci-460','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','年年羞插菊花游。',56,'宋词/ci.song.2000.json','["年年羞插菊花游。", "华发不禁秋。", "此日遨头寻胜，消除万斛清愁。", "湿云凉雨南台上，歌动玉溪流。", "俯仰人间今古，多情破帽飕飕。"]'),
('song-ci-461','点绛唇','韩淲','宋','宋词','song-ci','点绛唇','[]','银笔金花，断肠有句闲挥扫。',50,'宋词/ci.song.2000.json','["银笔金花，断肠有句闲挥扫。", "又还落了。", "梅片阳春小。", "古往今来，风味须才调。", "山林少。", "这些襟抱。", "输与江东老。"]'),
('song-ci-462','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','的皪南枝横县宇。',52,'宋词/ci.song.2000.json','["的皪南枝横县宇。", "空山无此新花吐。", "手种几多梅。", "迎霜今已开。", "簪屏聊隐几。", "诗与君应喜。", "更报晏斋翁。", "相将索笑同。"]'),
('song-ci-463','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','莫笑闲身老态多。',64,'宋词/ci.song.2000.json','["莫笑闲身老态多。", "避人避世欲如何。", "分明画出山阴道。", "太息吟成宁戚歌。", "穿木石，泛烟波。", "从前魑魅喜人过。", "灵山西畔高溪上，一棹归来舞短蓑。"]'),
('song-ci-464','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','系得船儿柳岸头。',48,'宋词/ci.song.2000.json','["系得船儿柳岸头。", "夹江灯火雨飕飕。", "寻诗家醉更绸缪。", "待腊未教寒事少，小春搀取暗香浮。", "夜长飞梦失清愁。"]'),
('song-ci-465','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','爱日回春一线长。',48,'宋词/ci.song.2000.json','["爱日回春一线长。", "氛氲谁忆御炉香。", "孤城岁晚卧沧江。", "花底千官迎淑气，湖阴十里写晴光。", "剩拼华发醉为乡。"]'),
('song-ci-466','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','春入疏弦调外声。',48,'宋词/ci.song.2000.json','["春入疏弦调外声。", "雪云初霁带湖清。", "屏温香软绮窗深。", "山倚虚窗情淡淡，水流清浅韵泠泠。", "断魂醒处梦难凭。"]'),
('song-ci-467','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','云外月。',53,'宋词/ci.song.2000.json','["云外月。", "画出一痕清绝。", "梅已飘零桃未发。", "带湖烟水阔。", "汀渚尚留微雪。", "不恨酒融歌歇。", "老我多情胶漫结。", "半醒空自说。"]'),
('song-ci-468','临江仙','韩淲','宋','宋词','song-ci','临江仙','[]','满眼春生梅柳意，山居清听风泉。',70,'宋词/ci.song.2000.json','["满眼春生梅柳意，山居清听风泉。", "又因初度说今年。", "华颠相望处，新曲忽来前。", "自笑一周闲甲子，何为佞佛贪仙。", "如翁辈行敢随肩。", "徒知言语妙，欢喜向谁传。"]'),
('song-ci-469','谒金门','韩淲','宋','宋词','song-ci','谒金门','[]','不怕醉。',53,'宋词/ci.song.2000.json','["不怕醉。", "记取吟边滋味。", "幽草绿阴花絮里。", "莺啼双燕起。", "老去是何乡里。", "漠漠吴头楚尾。", "一曲荒山清照水。", "殢渠杯酒旨。"]'),
('song-ci-470','霜天晓角','韩淲','宋','宋词','song-ci','霜天晓角','[]','雨收云薄。',53,'宋词/ci.song.2000.json','["雨收云薄。", "有底情怀恶。", "一段春风花事，吟得就、又忘却。", "海棠红未落。", "细细流霞酌。", "选甚蝇营狗苟，皆现定、有何错。"]'),
('song-ci-471','临江仙','韩淲','宋','宋词','song-ci','临江仙','[]','寒食清明春事好，公家霁月光风。',70,'宋词/ci.song.2000.json','["寒食清明春事好，公家霁月光风。", "年时犹记雨声中。", "州侯陈乐舞，法从酒杯同。", "坐上王杨虽自散，酴醿依旧香浓。", "待将诗易寿无穷。", "鸢飞鱼跃矣，风虎更云龙。"]'),
('song-ci-472','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','莫道庞公不入州。',64,'宋词/ci.song.2000.json','["莫道庞公不入州。", "为谁歌酒也迟留。", "襟期别乘真难事，领略同游岂易谋。", "他扰扰，自悠悠。", "香浮茉莉笑花头。", "一帘云影催诗雨，唤起佳人无限愁。"]'),
('song-ci-473','鹊桥仙','韩淲','宋','宋词','song-ci','鹊桥仙','[]','诗非漫与，酒非无算，都是悲秋兴在。',68,'宋词/ci.song.2000.json','["诗非漫与，酒非无算，都是悲秋兴在。", "与君觞咏欲如何，画不就、新凉境界。", "微云抹月，斜河回斗，隐隐奇奇怪怪。", "刚风九万舞瑶林，甚些少、人间利害。"]'),
('song-ci-474','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','闲里相看两鬓秋。',48,'宋词/ci.song.2000.json','["闲里相看两鬓秋。", "酒能沾醉雨能幽。", "吾庐何幸得翁留。", "世路尽教终易与，山林佳话恐难酬。", "人来人去亦知不。"]'),
('song-ci-475','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','分付心情作上元。',48,'宋词/ci.song.2000.json','["分付心情作上元。", "不知投老在林泉。", "谁将村酒劝觥船。", "月影静摇风柳外，霜华寒浸雪梅边。", "醉敧乌帽忽醒然。"]'),
('song-ci-476','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','老觉空生易得年。',48,'宋词/ci.song.2000.json','["老觉空生易得年。", "闲居那复问旌旃。", "一丘春静自回旋。", "翁善於人知美矣，我行於世转乖然。", "清词俾寿喜言传。"]'),
('song-ci-477','鹊桥仙','韩淲','宋','宋词','song-ci','鹊桥仙','[]','红梅已谢，杏花开也，一片海棠犹未。',68,'宋词/ci.song.2000.json','["红梅已谢，杏花开也，一片海棠犹未。", "春风吹我带湖烟，甚恰限、新晴天气。", "黄昏楼上，烛花影里，拼得那回滋味。", "暗尘弦索拂纤纤，梦留取、巫山十二。"]'),
('song-ci-478','生查子','韩淲','宋','宋词','song-ci','生查子','[]','晴色入青山，更见飞花晚。',48,'宋词/ci.song.2000.json','["晴色入青山，更见飞花晚。", "不是不登临，自是心情懒。", "试襞小红笺，与写天涯怨。", "杜宇一声春，楼下沧波远。"]'),
('song-ci-479','一翦梅','韩淲','宋','宋词','song-ci','一翦梅','[]','缥渺神仙云雾窗。',72,'宋词/ci.song.2000.json','["缥渺神仙云雾窗。", "说与苏州，未断人肠。", "带湖烟月堕苍茫。", "唤醒嫦娥，春笋纤长。", "马上琵琶半额妆。", "拨尽相思，十二巫阳。", "疏□清梦入潇湘。", "佩玉鸣鸾，吹下天香。"]'),
('song-ci-480','眼儿媚','韩淲','宋','宋词','song-ci','眼儿媚','[]','西溪回合小青苍。',58,'宋词/ci.song.2000.json','["西溪回合小青苍。", "梅雨弄残阳。", "意行陇亩，景分庭院，乳燕春长。", "酒深不用人歌啸，锄圃试商量。", "细晞菜甲，旋寻蔬笋，一梦黄粱。"]'),
('song-ci-481','水调歌头','韩淲','宋','宋词','song-ci','水调歌头','[]','一曲笙歌外，四座笑谈清。',114,'宋词/ci.song.2000.json','["一曲笙歌外，四座笑谈清。", "使君秋霁领客，别乘更宗英。", "想像亲闱称寿，写就通家情分，相与庆恩荣。", "劝动桂花发，香雾扑帘旌。", "功名事，台阁路，好同登。", "只今报政归诏，舆论正蜚声。", "以我文章学术，与国和平安靖，冠剑入明庭。", "应顾棠阴下，野老鬓星星。"]'),
('song-ci-482','鹧鸪天','韩淲','宋','宋词','song-ci','鹧鸪天','[]','云到春飞若素期。',64,'宋词/ci.song.2000.json','["云到春飞若素期。", "柳条吹送落梅枝。", "冰壶表里谁能赋，玉鉴圆明且屈卮。", "村舍北，郡楼西。", "治中风调只心知。", "不堪野老关门醉，想见山翁倒载时。"]'),
('song-ci-483','桃源忆故人','韩淲','宋','宋词','song-ci','桃源忆故人','[]','杏花雨里东风峭。',56,'宋词/ci.song.2000.json','["杏花雨里东风峭。", "不比寻常开了。", "枝上飞来多少。", "人与春将老。", "山城灯火笙箫杳。", "梦到十洲三岛。", "睡觉绮窗清晓。", "绿遍池塘草。"]'),
('song-ci-484','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','荆楚谁言镜听词。',48,'宋词/ci.song.2000.json','["荆楚谁言镜听词。", "烛花影动画檐低。", "烧灯天气醉为期。", "雨湿杏腮疑淡淡，风迷柳眼半僛僛。", "小山西路板桥西。"]'),
('song-ci-485','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','春来晴雨常相半。',52,'宋词/ci.song.2000.json','["春来晴雨常相半。", "水光风力花撩乱。", "山北与山南。", "行歌或再三。", "诵君诗过日。", "才大真盘屈。", "寿我敢言酬。", "相望亦饮不。"]'),
('song-ci-486','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','百花丛里试新妆。',48,'宋词/ci.song.2000.json','["百花丛里试新妆。", "不许巫山枉断肠。", "牡丹风扬曲声长。", "寒食清明闲节序，绮窗朱户少年场。", "燕泥香润落空梁。"]'),
('song-ci-487','虞美人','韩淲','宋','宋词','song-ci','虞美人','["\u897f\u6e56"]','西湖十里孤山路。',66,'宋词/ci.song.2000.json','["西湖十里孤山路。", "犹记荷花处。", "翠茎红蕊最关情。", "不是薰风、吹得晚来晴。", "而今老去丹青底。", "醉腻娇相倚。", "棹歌声缓采香归。", "如梦如酲、新月照涟漪。"]'),
('song-ci-488','虞美人','韩淲','宋','宋词','song-ci','虞美人','[]','送君报最登朝路。',66,'宋词/ci.song.2000.json','["送君报最登朝路。", "初整曹装处。", "又因杯酒见馀情。", "凉雨灵山阁上、月初晴。", "醺然领客襟怀底。", "消得阑干倚。", "风流别乘我依归。", "清誉冰溪棠荫、绿漪漪。"]'),
('song-ci-489','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','一番风月已平分。',57,'宋词/ci.song.2000.json','["一番风月已平分。", "留得玉溪云。", "蔼蔼宾僚如故，东楼北海清尊。", "荷香凉透，柳阴深锁，翠袂珠裙。", "□到九重城里，才华好觐吾君。"]'),
('song-ci-490','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','宋玉悲秋合反骚。',48,'宋词/ci.song.2000.json','["宋玉悲秋合反骚。", "陶潜把菊任持醪。", "山遥遥外水萧萧。", "梦不到时诗自在，兴难忘处恨全消。", "香沈沈里蕊飘飘。"]'),
('song-ci-491','朝中措','韩淲','宋','宋词','song-ci','朝中措','[]','君之竹隐是章泉。',57,'宋词/ci.song.2000.json','["君之竹隐是章泉。", "只要世家传。", "莫道闲诗浪句，风花雪月云烟。", "一杯我醉，百年人事，乾转坤旋。", "直与唤回兴替，羲皇留下遗编。"]'),
('song-ci-492','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','一抹青山拍岸溪。',48,'宋词/ci.song.2000.json','["一抹青山拍岸溪。", "麦云将过笋初齐。", "不知何处水流西。", "小阁路头吾欲醉，短蓬船尾客同携。", "酒边华发更题诗。"]'),
('song-ci-493','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','水绕孤村客路赊。',48,'宋词/ci.song.2000.json','["水绕孤村客路赊。", "一楼风雨角巾斜。", "举觞无复问煎茶。", "夜静曲声初喷竹，酒深烛影细吹花。", "明朝飞鹭起圆沙。"]'),
('song-ci-494','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','忆把兰桡系柳堤。',48,'宋词/ci.song.2000.json','["忆把兰桡系柳堤。", "斜风细雨一蓑衣。", "夕阳回照断霞飞。", "洛浦佩寒如隔日，高唐梦到又何时。", "背人挑□独心知。"]'),
('song-ci-495','水调歌头','韩淲','宋','宋词','song-ci','水调歌头','[]','玉水灵山地，燕寝亦书功。',114,'宋词/ci.song.2000.json','["玉水灵山地，燕寝亦书功。", "邦人耆老，诞弥佳节以词通。", "尔岂知吾恺悌，我乃因君谈笑，祝寿酒杯同。", "箫鼓少人会，歌舞为谁容。", "观坐客，惊野老，笔如风。", "个般酬唱，诏回应上玉华东。", "多少家传经济，留与孙谋持守，出处信何穷。", "唤起千年调，分付一车公。"]'),
('song-ci-496','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','人间多少闲风度。',52,'宋词/ci.song.2000.json','["人间多少闲风度。", "薄情失记相逢处。", "绿鬓画鸦儿。", "旧巢双燕栖。", "舞衫回素玉。", "檀板声何蹙。", "一抹晚霞飞。", "泪痕无脸啼。"]'),
('song-ci-497','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','彩笔新题字字香。',48,'宋词/ci.song.2000.json','["彩笔新题字字香。", "雁来时候燕空梁。", "芙蓉无处著秋光。", "人远山长言外意，曲传书恨醉时妆。", "倩谁闲寄水云乡。"]'),
('song-ci-498','菩萨蛮','韩淲','宋','宋词','song-ci','菩萨蛮','[]','晚云烘日枝南北。',52,'宋词/ci.song.2000.json','["晚云烘日枝南北。", "一杯未尽梅花曲。", "城郭小春回。", "暗香开未开。", "留连吾欲醉。", "醉眼红尘外。", "多少老心情。", "景清人亦清。"]'),
('song-ci-499','少年游','韩淲','宋','宋词','song-ci','少年游','[]','闲寻杯酒，清翻曲语，相与送残冬。',64,'宋词/ci.song.2000.json','["闲寻杯酒，清翻曲语，相与送残冬。", "天地推移，古今兴替，斯道岂雷同。", "明窗玉蜡梅枝好，人情淡、物华浓。", "个样风光，别般滋味，无梦听飞鸿。"]'),
('song-ci-500','蝶恋花','韩淲','宋','宋词','song-ci','蝶恋花','[]','未就丹砂须九转。',70,'宋词/ci.song.2000.json','["未就丹砂须九转。", "谁把新词，歌绕梁尘遍。", "拍拍韶华春意满。", "揆予初度文何健。", "恰是山花汀草远。", "独乐园林，不梦笙歌殿。", "灵气仙才非小见。", "霞杯漫道蟠桃献。"]'),
('song-ci-501','蝶恋花','韩淲','宋','宋词','song-ci','蝶恋花','[]','千叶香梅春在手。',70,'宋词/ci.song.2000.json','["千叶香梅春在手。", "日薄帘栊，花影遮前后。", "小立徐行还易久。", "微吟莫厌伤多久。", "拾翠流红弦管透。", "望断青青，休问行人柳。", "往事如云如梦否。", "连天芳草惊依旧。"]'),
('song-ci-502','点绛唇','韩淲','宋','宋词','song-ci','点绛唇','[]','南陌柔桑，粉墙低见谁家女。',50,'宋词/ci.song.2000.json','["南陌柔桑，粉墙低见谁家女。", "燕飞莺语。", "依约提篮去。", "老觉多情，梦也无分付。", "君知否。", "楚襄何处。", "一段阳台雨。"]'),
('song-ci-503','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','滴滴琼英发翠绡。',48,'宋词/ci.song.2000.json','["滴滴琼英发翠绡。", "江梅标韵木香娇。", "乍凉时候漏声遥。", "欲绾鬓丝妆未了，半回身分曲初招。", "霓裳依约梦魂飘。"]'),
('song-ci-504','浣溪沙','韩淲','宋','宋词','song-ci','浣溪沙','[]','雨阁云流小院秋。',48,'宋词/ci.song.2000.json','["雨阁云流小院秋。", "半醺凉意不关愁。", "一番相见一番休。", "淡伫乍持杯未浅，懒歌浑罢笑初收。", "主宾无处著绸缪。"]'),
('song-ci-505','摊破浣溪沙・山花子','韩淲','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','生与真妃姓氏同。',56,'宋词/ci.song.2000.json','["生与真妃姓氏同。", "家随西子苎萝东。", "谁道玉肌寒起粟，酒能红。", "火齐烧空来上苑，冰浆凝露在西宫。", "不似荔枝生处远，恨薰风。"]'),
('song-ci-506','瑞鹧鸪','李廷忠','宋','宋词','song-ci','瑞鹧鸪','[]','洛浦风光烂漫时。',64,'宋词/ci.song.2000.json','["洛浦风光烂漫时。", "千金开宴醉为期。", "花方著雨犹含笑，蝶不禁寒总是痴。", "香腮擎吐浓华艳，不随桃李竞春菲。", "东君自有回天力，看把花枝带月归。"]'),
('song-ci-507','生查子','李廷忠','宋','宋词','song-ci','生查子','[]','玉女翠帷熏，香粉开妆面。',48,'宋词/ci.song.2000.json','["玉女翠帷熏，香粉开妆面。", "不是占春迟，羞被群花见。", "纤手折柔条，绛雪飞千片。", "流入紫金卮，未许停歌扇。"]'),
('song-ci-508','水龙吟','李廷忠','宋','宋词','song-ci','水龙吟','[]','风流最数宣城，奇山秀水神仙府。',126,'宋词/ci.song.2000.json','["风流最数宣城，奇山秀水神仙府。", "琴高台畔，花姑坛上，鸾翔凤舞。", "春度玉墀，月升金掌，荣分铜虎。", "想少陵，知有异人间出，三百载、留佳句。", "岁岁椒盘柏斝，到明朝、又还重举。", "阳和散作，千岩瑞雪，两溪甘雨。", "汲取恩波，酿成禄酒，庆公初度。", "有东风传报，都人已为，筑沙堤路。"]'),
('song-ci-509','沁园春','李廷忠','宋','宋词','song-ci','沁园春','[]','幕府增辉，前度刘郎，又还到来。',139,'宋词/ci.song.2000.json','["幕府增辉，前度刘郎，又还到来。", "看芙蓉池畔，神凝秋水，绮罗丛里，欢动春雷。", "彩笔新题，金钗半醉，当日英雄安在哉。", "开筵处，是真仙福地，不著纤埃。", "堪怜倦客情怀。", "听吹竹弹丝金奏谐。", "有黄花插鬓，何妨敧帽，绿橙醒酒，莫惜空罍。", "坐上疏狂，帘间姝丽，应想横波一笑回。", "停杯久，待娇歌缓劝，归骑休催。"]'),
('song-ci-510','一落索','方千里','宋','宋词','song-ci','一落索','[]','心抵江莲长苦。',56,'宋词/ci.song.2000.json','["心抵江莲长苦。", "凌波人去。", "厌厌消瘦不胜衣，恨清泪、多於雨。", "旧曲慵歌琼树。", "谁传香素。", "碧溪流水过楼前，问红叶、来何处。"]'),
('song-ci-511','垂丝钓','方千里','宋','宋词','song-ci','垂丝钓','[]','锦鳞绣羽。',81,'宋词/ci.song.2000.json','["锦鳞绣羽。", "难传愁态颦妩。", "岸草际天，云影垂絮。", "人何许。", "谩并栏倚柱。", "烟光暮。", "怅榆钱满路。", "送春殢酒。", "欢期幽会希遇。", "彩箫凤侣。", "回首分携处。", "双脸吹愁雨。", "无限语。", "再见时记否。"]'),
('song-ci-512','满庭芳','方千里','宋','宋词','song-ci','满庭芳','[]','山色澄秋，水光融日，浮萍飘碎还圆。',118,'宋词/ci.song.2000.json','["山色澄秋，水光融日，浮萍飘碎还圆。", "数行征雁，分破白鸥烟，高下回塘暗谷，写幽思、终日溅溅。", "闲凝望，残霞暝霭，何处一渔船。", "江南，思旧隐，筠轩野径，茅舍疏椽。", "惯携壶花下，敧帽风前。", "想像渊明旧节，琴中趣、何必疏弦。", "归欤计，不将五斗，输与北窗眠。"]'),
('song-ci-513','隔浦莲・隔浦莲近拍','方千里','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','垂杨烟湿嫩葆。',88,'宋词/ci.song.2000.json','["垂杨烟湿嫩葆。", "别屿环清窈。", "绀影浮新涨，夷犹终日鱼鸟，花妥庭下草。", "鸣蝉闹。", "暗绿藏台沼。", "野轩小。", "敧眠断梦，闲书风叶颠倒。", "诗怀酒思，悔费十年昏晓。", "投老红尘倦再到。", "愁觉。", "悠然心寄天表。"]'),
('song-ci-514','法曲献仙音','方千里','宋','宋词','song-ci','法曲献仙音','[]','庭叶飘寒，砌蛩催织，夜色迢迢难度。',113,'宋词/ci.song.2000.json','["庭叶飘寒，砌蛩催织，夜色迢迢难度。", "细剔灯花，再添香兽，凄凉洞房朱户。", "见凤枕羞孤另，相思洒红雨。", "有谁语。", "道年来，为郎憔悴，音问隔，回首后期尚阻。", "寂寞两愁山，锁闲情、无限颦妩。", "嫩雪消肌，试罗衣、宽尽腰素。", "问何时梦里，趁得好风飞去。"]'),
('song-ci-515','过秦楼','方千里','宋','宋词','song-ci','过秦楼','[]','柳拂鹅黄，草揉螺黛，院落雨痕才断。',135,'宋词/ci.song.2000.json','["柳拂鹅黄，草揉螺黛，院落雨痕才断。", "蜂须雾湿，燕嘴泥融，陌上细风频扇。", "多少艳景关心，长苦春光，疾如飞箭。", "对东风忍负，西园清赏，翠深香远。", "空暗忆、醉走铜驼，闲敲金镫，倦迹素衣尘染。", "因花瘦觉，为酒情锺，绿鬓几番催变。", "何况逢迎向人，眉黛供愁，娇波回倩。", "料相思此际，浓似飞红万点。"]'),
('song-ci-516','侧犯','方千里','宋','宋词','song-ci','侧犯','[]','四山翠合，一溪碧绕秋容靓。',95,'宋词/ci.song.2000.json','["四山翠合，一溪碧绕秋容靓。", "波定。", "见鹭立鱼跳动平镜。", "修林散步屧，古木通幽径。", "风静。", "烟雾直、池塘倒晴影。", "流年旧事，老矣尘心莹。", "还暗省。", "点吴霜、憔悴愧潘令。", "梦忆江南，小园路迥。", "愁听。", "叶落辘轳金井。"]'),
('song-ci-517','塞翁吟','方千里','宋','宋词','song-ci','塞翁吟','[]','暮色催更鼓，庭户月影胧□。',115,'宋词/ci.song.2000.json','["暮色催更鼓，庭户月影胧□。", "记旧迹、玉楼东。", "看枕上芙蓉。", "云屏几轴江南画，香篆炉暖烟空。", "睡起处，绣衾重。", "尚残酒潮红。", "忡忡。", "从分散，歌稀宴小，怀丽质，浑如梦中。", "苦寂寞、离情万绪，似秋后、怯雨芭蕉，不展愁封。", "何时细语，此夕相思，曾对西风。"]'),
('song-ci-518','苏幕遮','方千里','宋','宋词','song-ci','苏幕遮','[]','扇留风，冰却暑。',76,'宋词/ci.song.2000.json','["扇留风，冰却暑。", "夏木阴阴，相对黄鹂语。", "薄晚轻阴还阁雨。", "远岸烟深，仿佛菱歌举。", "燕归来，花落去。", "几度逢迎，几度伤羁旅。", "油壁西陵人识否。", "好约追凉，小舣蒹葭浦。"]'),
('song-ci-519','浣溪沙','方千里','宋','宋词','song-ci','浣溪沙','[]','菱藕花开来路香。',48,'宋词/ci.song.2000.json','["菱藕花开来路香。", "满船丝竹载西凉。", "波摇发彩粉生光。", "翡翠双飞寻密浦，鸳鸯浓睡倚回塘。", "闲情须与酒商量。"]'),
('song-ci-520','浣溪沙','方千里','宋','宋词','song-ci','浣溪沙','[]','密约深期卒未成。',48,'宋词/ci.song.2000.json','["密约深期卒未成。", "藏钩春酒坐频倾。", "向人娇艳夜亭亭。", "相顾无言情易觉，归来单枕梦犹惊。", "眼梢怨泪几时晴。"]'),
('song-ci-521','浣溪沙','方千里','宋','宋词','song-ci','浣溪沙','[]','面面虚堂水照空。',48,'宋词/ci.song.2000.json','["面面虚堂水照空。", "天然一朵玉芙蓉。", "千娇百媚语惺憁。", "未散娇云轻□鬓，欲融轻雪乍凝胸。", "石榴裙衩为谁红。"]'),
('song-ci-522','浣溪沙','方千里','宋','宋词','song-ci','浣溪沙','[]','刻样衣裳巧刻绘。',48,'宋词/ci.song.2000.json','["刻样衣裳巧刻绘。", "彩枝环绕万年藤。", "生香吹透縠蚕冰。", "嫩水带山娇不断，湿云堆岭腻无声。", "香肩婀娜许谁凭。"]'),
('song-ci-523','点绛唇','方千里','宋','宋词','song-ci','点绛唇','[]','闲荡兰舟，翠娥仙袂风中举。',50,'宋词/ci.song.2000.json','["闲荡兰舟，翠娥仙袂风中举。", "鸳鸯深浦。", "绿暗曾来路。", "留恋荷香，薄晚慵归去。", "还相顾。", "练波澄素。", "月上潮生处。"]'),
('song-ci-524','诉衷情','方千里','宋','宋词','song-ci','诉衷情','[]','远山重叠乱山盘。',54,'宋词/ci.song.2000.json','["远山重叠乱山盘。", "江上晚风酸。", "秋容更兼残日，枫叶照人丹。", "书未到，梦犹闲。", "鬓先斑。", "凭高无语，征雁知愁，声断云间。"]'),
('song-ci-525','风流子','方千里','宋','宋词','song-ci','风流子','[]','河梁携手别，临歧语，共约踏青归。',135,'宋词/ci.song.2000.json','["河梁携手别，临歧语，共约踏青归。", "自双燕再来，断无音信，海棠开了，还又参差。", "料此际，笑随花便面，醉骋锦障泥。", "不忆故园，粉愁香怨，忍教华屋，绿惨红悲。", "旧家歌舞地，生疏久，尘暗凤缕罗衣。", "何限可怜心事，难诉欢期。", "但两点愁蛾，才开重敛，几行清泪，欲制还垂。", "争表为郎憔悴，相见方知。"]'),
('song-ci-526','华胥引','方千里','宋','宋词','song-ci','华胥引','[]','长亭无数，羁客将归，故园换叶。',104,'宋词/ci.song.2000.json','["长亭无数，羁客将归，故园换叶。", "乳鸭随波，轻苹满渚时共唼。", "接眼春色何穷，更橹声伊轧。", "思忆前欢，未言心已愁怯。", "欺鬓吴霜。", "恨星星、又还盈镊。", "锦纹鱼素，那堪重翻再阅。", "粉指香痕依旧，在绣裳鸳箧。", "多少相思，皱成眉上千叠。"]'),
('song-ci-527','宴清都','方千里','宋','宋词','song-ci','宴清都','[]','暮色闻津鼓。',126,'宋词/ci.song.2000.json','["暮色闻津鼓。", "烟波碧、数行征雁时度。", "轻榔聚网，长歌和楫，水村渔户。", "行人又落天涯，但怅望、高阳伴侣。", "记旧日、酒卸宫袍，马酬少妾词赋。", "如今鬓影萧然，相逢似雪，徒话愁苦。", "芳尘暗陌。", "残花遍野，岁华空去。", "垂阳翠拂门径，尚梦想、当时住处。", "纵早归、绿渐成阴，青娥在否。"]'),
('song-ci-528','四园竹','方千里','宋','宋词','song-ci','四园竹','[]','花骢纵策，制泪掩斜扉。',95,'宋词/ci.song.2000.json','["花骢纵策，制泪掩斜扉。", "玉炉细袅，鸳被半闲，萧瑟罗帏。", "银漏声，那更杂、疏疏雨里，此时怀抱谁知。", "恨凄其。", "西窗自剪寒花，沈吟暗数归期。", "最爱深情密意，无限当年，往复诗辞。", "千万纸。", "甚近日、人来字渐稀。"]'),
('song-ci-529','齐天乐','方千里','宋','宋词','song-ci','齐天乐','[]','碧纱窗外黄鹂语，声声似愁春晚。',125,'宋词/ci.song.2000.json','["碧纱窗外黄鹂语，声声似愁春晚。", "岸柳飘绵，庭花堕雪，惟有平芜如剪。", "重门尚掩。", "看风动疏帘，浪铺湘簟。", "暗想前欢，旧游心事寄诗卷。", "鳞鸿音信未睹，梦魂寻访后，关山又隔无限。", "客馆愁思，天涯倦迹，几许良宵展转。", "闲情意远。", "记密阁深闺，绣衾罗荐。", "睡起无人，料应眉黛敛。"]'),
('song-ci-530','木兰花・玉楼春','方千里','宋','宋词','song-ci','木兰花・玉楼春','[]','溶溶水映娟娟秀。',64,'宋词/ci.song.2000.json','["溶溶水映娟娟秀。", "浅约宫妆笼翠袖。", "舞馀杨柳乍萦风，睡起海棠犹带酒。", "憔悴萧郎缘底瘦。", "那日花前相见后。", "西窗疑是故人来，费得罗笺诗几首。"]'),
('song-ci-531','霜叶飞','方千里','宋','宋词','song-ci','霜叶飞','[]','塞云垂地，堤烟重，燕鸿初度江表。',131,'宋词/ci.song.2000.json','["塞云垂地，堤烟重，燕鸿初度江表。", "露荷风柳向人疏，台榭还清悄。", "恨脉脉、离情怨晓。", "相思魂梦银屏小。", "奈倦客征衣，自遍拂尘埃，玉镜羞照。", "无限静陌幽坊，追欢寻赏，未落人后先到。", "少年心事转头空，况老来怀抱。", "尽绿叶红英过了。", "离声慵整当时调。", "问丽质，从憔悴，消减腰围，似郎多少。"]'),
('song-ci-532','蕙兰芳・蕙兰芳引','方千里','宋','宋词','song-ci','蕙兰芳・蕙兰芳引','[]','庭院雨晴，倚斜照、睡馀双鹜。',103,'宋词/ci.song.2000.json','["庭院雨晴，倚斜照、睡馀双鹜。", "正学染修蛾，官柳细匀黛绿。", "绣帘半卷，透笑语、琐窗华屋。", "带脆声咽韵，远近时闻丝竹。", "乍著单衣，才拈圆扇，气候暄燠。", "趁骄马香车，同按绣坊画曲。", "人生如寄，浪勤耳目。", "归醉乡，犹胜旅情愁独。"]'),
('song-ci-533','塞垣春','方千里','宋','宋词','song-ci','塞垣春','[]','四远天垂野。',119,'宋词/ci.song.2000.json','["四远天垂野。", "向晚景，雕鞍卸。", "吴蓝滴草，塞锦藏柳，风物堪画。", "对雨收雾霁初晴也。", "正陌上、烟光洒。", "听黄鹂、啼红树，短长音□如写。", "怀抱几多愁，年时趁、欢会幽雅。", "尽日足相思，奈春昼难夜。", "念征尘、满堆襟袖，那堪更、独游花阴下。", "一别鬓毛减，镜中霜满把。"]'),
('song-ci-534','丁香结','方千里','宋','宋词','song-ci','丁香结','[]','烟湿高花，雨藏低叶，为谁翠消红陨。',120,'宋词/ci.song.2000.json','["烟湿高花，雨藏低叶，为谁翠消红陨。", "叹水流波迅。", "抚艳景、尚有轻阴馀润。", "乳莺啼处路，思归意、泪眼暗忍。", "青青榆荚满地，纵买闲愁难尽。", "勾引。", "正记著年时，乍怯春寒阵阵。", "小阁幽窗，残妆剩粉，黛眉曾晕。", "迢递魂梦万里，恨断柔肠寸。", "知何时重见，空为相思瘦损。"]'),
('song-ci-535','氐州第一','方千里','宋','宋词','song-ci','氐州第一','[]','朝日融怡，天气艳冶，桃英杏萼犹小。',127,'宋词/ci.song.2000.json','["朝日融怡，天气艳冶，桃英杏萼犹小。", "燕垒初营，蜂衙乍散，池面烟光缥缈。", "芳草如薰，更潋滟、波光相照。", "锦绣萦回，丹青映发，未容春老。", "倦客自嗟清兴少。", "念归记、梦魂飞绕。", "浪阔鱼沈，云高雁阻，瞪目添愁抱。", "忆香闺、临丽景，无人伴、轻颦浅笑。", "想像消魂，怨东风、孤衾独晓。"]'),
('song-ci-536','解蹀躞','方千里','宋','宋词','song-ci','解蹀躞','[]','院宇无人晴昼，静看帘波舞。',89,'宋词/ci.song.2000.json','["院宇无人晴昼，静看帘波舞。", "自怜春晚，漂流尚羁旅。", "那况泪湿征衣，恨添客鬓，终日子规声苦。", "动离绪。", "谩徘徊愁步。", "何时再相遇。", "旧欢如昨，匆匆楚台雨。", "别后南北天涯，梦魂犹记关山，屡随书去。"]'),
('song-ci-537','少年游','方千里','宋','宋词','song-ci','少年游','[]','人如秾李，香濛翠缕，芳酒嫩於橙。',62,'宋词/ci.song.2000.json','["人如秾李，香濛翠缕，芳酒嫩於橙。", "宝烛烘香，珠帘闲夜，银字理鸾笙。", "归时醉面春风醒，花雾隔疏更。", "低辗雕轮，轻栊骄马，相伴月中行。"]'),
('song-ci-538','庆春宫・高阳台','方千里','宋','宋词','song-ci','庆春宫・高阳台','[]','宿霭笼晴。',126,'宋词/ci.song.2000.json','["宿霭笼晴。", "层云遮日，送春望断愁城。", "篱落堆花，帘栊飞絮，更堪远近莺声。", "岁华流转，似行蚁、盘旋万星。", "人生如寄，利锁名缰，何用萦萦。", "骎骎皓发相迎。", "斜照难留，朝雾多零。", "宜趁良辰，何妨高会，为酬月皎风清。", "舞台歌榭，遇得旅、欢期易成。", "莫辞杯酒，天赋吾曹，特地锺情。"]'),
('song-ci-539','醉桃源・阮郎归','方千里','宋','宋词','song-ci','醉桃源・阮郎归','[]','良宵相对一灯青。',56,'宋词/ci.song.2000.json','["良宵相对一灯青。", "相思写砑绫。", "去时情泪滴红冰。", "西风吹涕零。", "愁宛转，意飞腾。", "晴窗穿纸蝇。", "梦知关塞不堪行。", "忆君犹问程。"]'),
('song-ci-540','醉桃源・阮郎归','方千里','宋','宋词','song-ci','醉桃源・阮郎归','[]','鸳鸯浓睡碧溪沙。',56,'宋词/ci.song.2000.json','["鸳鸯浓睡碧溪沙。", "荷花深处家。", "快风收电掣金蛇。", "凉波流素华。", "吴国艳，楚宫娃。", "红潮连翠霞。", "坐来忽忽烛光斜。", "城头闻乱鸦。"]'),
('song-ci-541','点绛唇','方千里','宋','宋词','song-ci','点绛唇','[]','绿叶阴阴，满城风雨催梅润。',50,'宋词/ci.song.2000.json','["绿叶阴阴，满城风雨催梅润。", "画楼人近。", "朝雾来芳信。", "从解雕鞍，休数花吹阵。", "无多闷。", "燕催莺趁。", "付与春归恨。"]'),
('song-ci-542','夜游宫','方千里','宋','宋词','song-ci','夜游宫','[]','一带垂杨蘸水。',71,'宋词/ci.song.2000.json','["一带垂杨蘸水。", "映芳草、萋萋千里。", "跋马回堤少年子。", "拥青娥，向红楼，南酒市。", "拼饮莺花底。", "恣欢笑、粉融香坠。", "不趁临分醉中起。", "但依稀，写柔情，留蜀纸。"]'),
('song-ci-543','夜游宫','方千里','宋','宋词','song-ci','夜游宫','[]','城上昏烟四敛。',71,'宋词/ci.song.2000.json','["城上昏烟四敛。", "画楼外、陡听更点。", "千里相思梦中见。", "恨年华，逐东流，随急箭。", "帘影参差转。", "夜初过、水沈烟乱。", "剩枕馀衾故人远。", "忆闲窗，亸云鬓，低粉面。"]'),
('song-ci-544','诉衷情','方千里','宋','宋词','song-ci','诉衷情','[]','一钩新月淡於霜。',54,'宋词/ci.song.2000.json','["一钩新月淡於霜。", "杨柳渐分行。", "征尘厌堆襟袂，鸡唱促晨装。", "淮水阔，楚山长。", "暗悲伤。", "重阳天气，杯酒黄花，还寄他乡。"]'),
('song-ci-545','伤情怨・清商怨','方千里','宋','宋词','song-ci','伤情怨・清商怨','[]','闲愁眉上翠小。',51,'宋词/ci.song.2000.json','["闲愁眉上翠小。", "尽春衫宽了。", "舞槛孤鸾，严妆羞独照。", "王孙音信尚渺。", "度寒食、禁烟须到。", "趁赏芳菲，今年春事早。"]'),
('song-ci-546','红林擒近','方千里','宋','宋词','song-ci','红林擒近','[]','花幕高烧烛，兽炉深炷香。',94,'宋词/ci.song.2000.json','["花幕高烧烛，兽炉深炷香。", "寒色上楼阁，春威遍池塘。", "多情天孙罢织，故与玉女穿窗。", "素脸浅约宫装。", "风韵胜笙簧。", "游冶寻旧侣，尊酒老吾乡。", "清歌度曲，何妨尘落雕梁。", "任瑶阶平尺，珠帘人报，剩拼酩酊飞羽觞。"]'),
('song-ci-547','红林擒近','方千里','宋','宋词','song-ci','红林擒近','[]','晓起山光惨，晚来花意寒。',94,'宋词/ci.song.2000.json','["晓起山光惨，晚来花意寒。", "映月衣纤缟，因风佩琅玕。", "三弄江梅听彻，几点岸柳飘残。", "宛然舞曲初翻。", "帘影卷波澜。", "把酒同唤醒，促膝小留欢。", "清狂痛饮，能消多少杯盘。", "况人生如寄，相逢半老，岁华休作容易看。"]'),
('song-ci-548','满路花・促拍满路花','方千里','宋','宋词','song-ci','满路花・促拍满路花','[]','帘筛月影金，风卷杨花雪。',101,'宋词/ci.song.2000.json','["帘筛月影金，风卷杨花雪。", "天边鸿雁少，音尘绝。", "春光欲暮，客心归心折。", "江湖波浪阔。", "目断家山，料应易过佳节。", "柔情千点，杜宇枝头血。", "危肠馀寸许，谁能接。", "眠思梦忆，不似今番切。", "欲对何人说。", "揽镜沈吟，瘦来须有差别。"]'),
('song-ci-549','解语花','方千里','宋','宋词','song-ci','解语花','[]','长空淡碧，素魄凝辉，星斗寒相射。',124,'宋词/ci.song.2000.json','["长空淡碧，素魄凝辉，星斗寒相射。", "凤楼鸳瓦。", "天风动，冉冉佩环高下。", "歌清韵雅。", "对好景、芳樽满把。", "花雾浓，灯火荧煌，笑语烘兰麝。", "千斛明珠照夜。", "况人如图画，明艳容冶。", "绣巾香帕。", "归来路，缓逐杏鞯骄马。", "笙歌散也。", "愁万炬、绛莲分谢。", "更楼残，惊听西楼，吹小梅初罢。"]'),
('song-ci-550','六么令','方千里','宋','宋词','song-ci','六么令','[]','照人明艳，肌雪消繁燠。',112,'宋词/ci.song.2000.json','["照人明艳，肌雪消繁燠。", "娇云慢垂柔领，绀发浓於沐。", "微晕红潮一线，拂拂桃腮熟。", "群芳难逐。", "天香国艳，试比春兰共秋菊。", "当时相见恨晚，彼此萦心目。", "别后空忆仙姿，路隔吹箫玉。", "何处栏干十二，缥缈阳台曲。", "佳期重卜。", "都将离恨，拼与尊前细留嘱。"]'),
('song-ci-551','倒犯','方千里','宋','宋词','song-ci','倒犯','[]','尽日、任梧桐自飞，翠阶慵扫。',127,'宋词/ci.song.2000.json','["尽日、任梧桐自飞，翠阶慵扫。", "闲云散缟。", "秋容莹、暮天清窈。", "斜阳到地，楼阁参差帘栊悄。", "嫩袖舞凉飔，拂拂生林表。", "荡尘襟，写名醥。", "携手故国，胜事寻踪，松篁幽径窵。", "曲沼瞰静绿，荫檐影、龟鱼小。", "信倦迹、归来好。", "倩叮咛、长安游子道。", "任鬓发霜侵，莫待菱花照。", "醉乡深处老。"]'),
('song-ci-552','大','方千里','宋','宋词','song-ci','大','[]','正夕阳闲，秋光淡，鸳瓦参差华屋。',164,'宋词/ci.song.2000.json','["正夕阳闲，秋光淡，鸳瓦参差华屋。", "高低帘幕迥，但风摇环佩，细声频触。", "瘦怯单衣，凉生两袖，零乱庭梧窗竹。", "相思谁能会，是归程客梦，路谙心熟。", "况时节黄昏，闲门人静，凭栏身独。", "欢情何太速。", "岁华似、飞马驰轻毂。", "谩自叹、河阳青鬓，苒苒如霜，把菱花、怅然凝目。", "老去疏狂减，思堕策、小坊幽曲。", "趁游乐、繁华国。", "回首无绪，清泪纷於红菽。", "话愁更堪剪烛。"]'),
('song-ci-553','玉烛新','方千里','宋','宋词','song-ci','玉烛新','[]','海棠初雨后。',124,'宋词/ci.song.2000.json','["海棠初雨后。", "似露粉妆成，肉红团就。", "太真帐里，春眠醒、缓蹙楼前宫漏。", "潮生酒晕，独自倚、阑干时候。", "吹鬓影、斜立东风，馀寒半侵罗袖。", "骊山宫殿无人，想笑问君王，艳容如否。", "万花竞斗。", "难比并、丽美巧匀丰瘦。", "闺房挺秀。", "□一顾、丹铅低首。", "应对、羯鼓声中，清歌美奏。"]'),
('song-ci-554','花犯','方千里','宋','宋词','song-ci','花犯','[]','渚风低，芙蓉万朵，清妍赋情味。',126,'宋词/ci.song.2000.json','["渚风低，芙蓉万朵，清妍赋情味。", "雾绡红缀。", "看曼立分行，闲淡佳丽。", "靓姿艳冶相扶倚。", "高低纷愠喜。", "正晓色、懒窥妆面，娇眠敧翠被。", "秋光为花且徘徊，朱颜迎缟露，还应憔悴。", "腰肢小，腮痕嫩、更堪飘坠。", "风流事、旧宫暗锁，谁复见、尘生香步里。", "谩叹息、玉儿何许，繁华空逝水。"]'),
('song-ci-555','丑奴儿・采桑子','方千里','宋','宋词','song-ci','丑奴儿・采桑子','[]','凌波台畔花如剪，几点吴霜。',52,'宋词/ci.song.2000.json','["凌波台畔花如剪，几点吴霜。", "烟淡云黄。", "东阁何人见晚妆。", "江南春近书千里，谁寄清香。", "别墅横塘。", "鼓角声中又夕阳。"]'),
('song-ci-556','水龙吟','方千里','宋','宋词','song-ci','水龙吟','[]','锦城春色移根，丽姿迥压江南地。',125,'宋词/ci.song.2000.json','["锦城春色移根，丽姿迥压江南地。", "琼酥拂脸，彩云满袖，群芳羞避。", "双燕来时，暮寒庭院，雨藏烟闭。", "正□□未足，宫妆尚怯，还轻洒胭脂泪。", "长是欢游花底。", "怕东风、陡成怨吹。", "高烧银烛，梁州催按，歌声渐起。", "绿态多慵，红情不语，动摇人意。", "算吴宫独步，昭阳第一，可依稀比。"]'),
('song-ci-557','六丑','方千里','宋','宋词','song-ci','六丑','[]','看流莺度柳，似急响、金梭飞掷。',172,'宋词/ci.song.2000.json','["看流莺度柳，似急响、金梭飞掷。", "护巢占泥，翩翩飞燕翼。", "昨梦前迹。", "暗数欢娱处，艳花幽草，纵冶游南国。", "芳心荡漾如波泽。", "系马青门，停车紫陌。", "年华转头堪惜。", "奈离襟别袂，容易疏隔。", "人间春寂。", "谩云容暮碧。", "远水沈双鲤、无信息。", "天涯渐老羁客。", "叹良宵漏断，独眠愁极。", "吴霜皎、半侵华帻。", "谁复省十载，匀香晕粉，髻倾鬟侧。", "相思意、不离潮汐。", "想旧家、接酒巡歌计，今难再得。"]'),
('song-ci-558','虞美人','方千里','宋','宋词','song-ci','虞美人','[]','花台响彻歌声暖。',66,'宋词/ci.song.2000.json','["花台响彻歌声暖。", "白日林中短。", "春心摇荡客魂消。", "搓粉揉香排比、一团娇。", "重来犹自寻芳径。", "吹鬓东风影。", "步金莲处绿苔封。", "不见彩云双袖、舞惊鸿。"]'),
('song-ci-559','虞美人','方千里','宋','宋词','song-ci','虞美人','[]','高楼远阁花飞遍。',66,'宋词/ci.song.2000.json','["高楼远阁花飞遍。", "急雨捎池面。", "けけ杨柳不知门。", "多少乱莺啼处、暮烟昏。", "银钩小字题芳絮。", "宛转回文语。", "可怜单枕梦行云。", "肠断江南千里、未归人。"]'),
('song-ci-560','兰陵王','方千里','宋','宋词','song-ci','兰陵王','[]','晚烟直。',159,'宋词/ci.song.2000.json','["晚烟直。", "池沼波痕皱碧。", "年芳为、花态柳情，采粉揉蓝酿春色。", "繁华记上国。", "曾识。", "倾城幼客。", "风流是、联句送钩，笺绿绡红递书尺。", "行云去无迹。", "念暖响歌台，香雾瑶席。", "当时谁信盟言食。", "知一岁离聚，几多间阻，人生如梦寄堠驿。", "况分散南北。", "悲恻。", "万愁积。", "奈鸾凤欢疏，鱼雁音寂。", "天涯何处相思极。", "但目断芳草，恨随塞笛。", "那堪庭院，更听得，夜雨滴。"]'),
('song-ci-561','蝶恋花','方千里','宋','宋词','song-ci','蝶恋花','[]','漏泄东君消息后。',70,'宋词/ci.song.2000.json','["漏泄东君消息后。", "短叶长条，著意遮轩牖。", "嫩比鹅黄初熟酒。", "染匀巧费春风手。", "万缕筛金新月透。", "入夜柔情，还胜朝来秀。", "彩笔雕章知几首。", "可人标韵无新旧。"]'),
('song-ci-562','蝶恋花','方千里','宋','宋词','song-ci','蝶恋花','[]','一搦腰肢初见后。',70,'宋词/ci.song.2000.json','["一搦腰肢初见后。", "恰似娉婷，十五藏朱牖。", "春色恼人浓抵酒。", "风前脉脉如招手。", "黛染修眉蛾绿透。", "态婉仪闲，自是闺房秀。", "堪惜年华同转首。", "女郎台畔春依旧。"]'),
('song-ci-563','蝶恋花','方千里','宋','宋词','song-ci','蝶恋花','[]','碎玉飞花寒食后。',70,'宋词/ci.song.2000.json','["碎玉飞花寒食后。", "薄影行风，终日穿疏牖。", "有客思归还把酒。", "闲吹倦絮轻黏手。", "雪满愁城寒欲透。", "飘尽残英，翠幄成秾秀。", "张绪风流今白首。", "少年襟度难如旧。"]'),
('song-ci-564','蝶恋花','方千里','宋','宋词','song-ci','蝶恋花','[]','翠浪蓝光新雨后。',70,'宋词/ci.song.2000.json','["翠浪蓝光新雨后。", "整整斜斜，高下笼窗牖。", "万斛深倾重碧酒。", "量愁知落何人手。", "栊雾梳烟晴色透。", "照影回风，一段嫣然秀。", "白下门东空引首。", "藏鸦枝叶长怀旧。"]'),
('song-ci-565','西河','方千里','宋','宋词','song-ci','西河','["\u897f\u6e56"]','都会地。',123,'宋词/ci.song.2000.json','["都会地。", "东南王气须记。", "龙盘凤舞到钱塘，瑞烟回起。", "画图彩笔写西湖，波光溶漾无际。", "翠栏最宜半倚。", "柳阴骏马谁系。", "鳞差观阁接飞翬，衙庐万垒。", "倒空碧浸软琉璃，云收天净如水。", "夕阳照晚听近市。", "沸笙箫、劝动闾里。", "比屋乐逢尧世。", "好相将载酒寻歌玄对。", "酬答年华莺花里。"]'),
('song-ci-566','三部乐','方千里','宋','宋词','song-ci','三部乐','[]','帘卷窗明，听杜宇乍啼，漏声初绝。',123,'宋词/ci.song.2000.json','["帘卷窗明，听杜宇乍啼，漏声初绝。", "乱云收尽，天际□留残月。", "奈相送、行客将归，怅去程渐促，霁色催发。", "断魂别浦，自上孤舟如叶。", "悠悠音信易隔。", "纵怨怀恨语，到见时难说。", "堪嗟水流急景，霜飞华发。", "想家山、路穷望睫。", "空倚仗、魂亲梦切。", "不似嫩朵，犹能替、离绪千结。"]'),
('song-ci-567','菩萨蛮','方千里','宋','宋词','song-ci','菩萨蛮','[]','黄鸡晓唱玲珑曲。',52,'宋词/ci.song.2000.json','["黄鸡晓唱玲珑曲。", "人生两鬓无重绿。", "官柳系行舟。", "相思独倚楼。", "来时花未发。", "去后纷如雪。", "春色不堪看。", "萧萧风雨寒。"]'),
('song-ci-568','品令','方千里','宋','宋词','song-ci','品令','[]','露晞烟静。',66,'宋词/ci.song.2000.json','["露晞烟静。", "寂寥转、梧桐寒影。", "天际历历征鸿近。", "被风吹散，声断无行阵。", "秋思客怀多少恨。", "谩厌厌谁问。", "晕残兰炧香消印。", "梦魂长定。", "愁伴更筹尽。"]'),
('song-ci-569','玉楼春','方千里','宋','宋词','song-ci','玉楼春','[]','华堂银烛堆红泪。',64,'宋词/ci.song.2000.json','["华堂银烛堆红泪。", "解说离人多少意。", "恨从别后恨无穷，愁到浓时惟一味。", "江南渭北三千里。", "憔悴相思何日已。", "马蹄清晓草黏天，庭院黄昏花满地。"]'),
('song-ci-570','满路花・促拍满路花','方千里','宋','宋词','song-ci','满路花・促拍满路花','[]','莺飞翠柳摇，鱼跃浮萍破。',101,'宋词/ci.song.2000.json','["莺飞翠柳摇，鱼跃浮萍破。", "班班红杏子，交榴火。", "池台昼永，缭绕花阴裹。", "山色遥供座。", "枕簟清凉，北窗时唤高卧。", "翻思少年，走马铜驼左。", "归来敲镫月，留关锁。", "年华老矣，事逐浮云过。", "今吾非故我。", "那日尊前，祗今问有谁呵。"]'),
('song-ci-571','沁园春','吴泳','宋','宋词','song-ci','沁园春','[]','鶗鴂鸣兮，卉木萋止，维暮之春。',140,'宋词/ci.song.2000.json','["鶗鴂鸣兮，卉木萋止，维暮之春。", "笑憨翁渐老，年加三豆，呆郎多事，诗记三星。", "六十有三，高吟勇退，只有尧夫范景仁。", "从今去，且亭前放鹤，溪上垂纶。", "交亲。", "散落如云。", "仅留得尊前康健身。", "有一编书传，一囊诗稿，一枰棋谱，一卷茶经。", "红杏尚书，碧桃学士，看了虚名都赚人。", "成何事，独青山有趣，白发无情。"]'),
('song-ci-572','摸鱼儿','吴泳','宋','宋词','song-ci','摸鱼儿','[]','甚一般、化工模子。',140,'宋词/ci.song.2000.json','["甚一般、化工模子。", "铸成一个拙底。", "生来不向春头上，却跨暮春婪尾。", "蓦省记。", "早冉冉花阴，НН循除水。", "虽然恁地。", "但笑咏春风，闲推鸣瑟，别自有真意。", "从前看，三十七年都未。", "醉生声利场里。", "浮云破处窗涵月，唤得自家醒起。", "别料理。", "那玉燕石麟，不当真符瑞。", "彻头地位。", "也须是长年，闻些好语，作个标月指。"]'),
('song-ci-573','沁园春','吴泳','宋','宋词','song-ci','沁园春','[]','春事阑斑，桐花烂漫，不堪凤栖。',139,'宋词/ci.song.2000.json','["春事阑斑，桐花烂漫，不堪凤栖。", "叹交枰世道，容容是福，危航宦海，了了成痴。", "邵子豪情，乐天狂态，六十六年才觉非。", "溪山畔，要看承风月，舍我其谁。", "文章高下随时。", "料织锦应须用锦机。", "愧老无健笔，高凌月胁，病无佳句，下解人颐。", "君昔东坡，我今韩愈，造化一炉如小儿。", "都休管，看龟翻荷露，燕落芹泥。"]'),
('song-ci-574','满江红','吴泳','宋','宋词','song-ci','满江红','[]','手摘桐花，怅还是、春风婪尾。',115,'宋词/ci.song.2000.json','["手摘桐花，怅还是、春风婪尾。", "按锦瑟、一弦一柱，又添一岁。", "紫马西来疑是梦，朱衣双引浑如醉。", "较香山、七十欠三年，吾衰矣。", "红袖却，青尊止。", "檀板住，琼杯废。", "淡香凝一室，自观生意。", "事业不堪霜满镜，文章底用花如绮。", "笑江滨、游女尚高歌，滕王记。"]'),
('song-ci-575','满江红','吴泳','宋','宋词','song-ci','满江红','[]','梦绕家山，曾访问、鹤林遗迹。',116,'宋词/ci.song.2000.json','["梦绕家山，曾访问、鹤林遗迹。", "见老鹤、翩跹飞下，方瞳如漆。", "蕙帐香消形色静，玉笙吹彻丰神逸。", "梦醒来、忽记鹤归时，翁生日。", "南陌杖，东山屐。", "红楼酒，青霄笛。", "料中梁何似，涪江今夕。", "君不见洛阳耆英会，花前雅放诗闲适。", "独北都、留守未归来，七十一。"]'),
('song-ci-576','水龙吟','吴泳','宋','宋词','song-ci','水龙吟','[]','清江社雨初晴，秋香吹彻高堂晓。',126,'宋词/ci.song.2000.json','["清江社雨初晴，秋香吹彻高堂晓。", "天然带得，酒星风骨，诗囊才调。", "沔水春深，屏山月淡，吟鞭俱到。", "算一生绕遍，瑶阶玉树，如君样、人间少。", "未放鹤归华表。", "伴仙翁、依然天杪。", "知他费几，雁边红粒，马边青草。", "待得清夷，彩衣花绶，哄堂一笑。", "且和平心事，等闲博个，千秋不老。"]'),
('song-ci-577','鹊桥仙','吴泳','宋','宋词','song-ci','鹊桥仙','[]','二童一马，素琴独鹤，长与仙翁为伴。',68,'宋词/ci.song.2000.json','["二童一马，素琴独鹤，长与仙翁为伴。", "自从分付益州来，便蔚有、隆中人望。", "边烽白羽，军符赤籍，弄得不成模样。", "愿公福德厚如山，为扶起、坤陲一半。"]'),
('song-ci-578','清平乐','吴泳','宋','宋词','song-ci','清平乐','[]','梅霖未歇。',54,'宋词/ci.song.2000.json','["梅霖未歇。", "直透菖华节。", "荔子才丹栀子白。", "抬贴诞弥嘉月。", "峨冠蝉尾けけ。", "整衣鹤骨彯彯。", "闻道彩云深处，新添弄玉吹箫。"]'),
('song-ci-579','贺新凉・贺新郎','吴泳','宋','宋词','song-ci','贺新凉・贺新郎','[]','碧嶂青红路。',142,'宋词/ci.song.2000.json','["碧嶂青红路。", "近重阳、不寒不暖，不风不雨。", "杜宇花残银杏过，犹有秋英未吐。", "但日对、南山延伫。", "碧落仙人骑赤鲤，渺风烟、不上瞿塘去。", "来伴我，宛陵住。", "西风画角高堂暮。", "炙银灯、疏帘影里，笑呼儿女。", "爷作嘉兴新太守，囝拜鹗书天府。", "况哥共、白头相聚。", "天分从来锺至乐，更谁思、野鸭鸳鸯语。", "提大斗，酌寒露。"]'),
('song-ci-580','渔家傲','吴泳','宋','宋词','song-ci','渔家傲','[]','翠隐红藏春尚薄。',72,'宋词/ci.song.2000.json','["翠隐红藏春尚薄。", "百花头上梅先觉。", "清晓寒城闻画角。", "云一握。", "鸦翻诏墨天边落。", "碧眼棱棱言谔谔。", "谏书犹自留黄阁。", "世事翻腾谁认错。", "休话著。", "绿尊且举鸬鹚杓。"]'),
('song-ci-581','八声甘州','吴泳','宋','宋词','song-ci','八声甘州','[]','又一番、沪水出牂牁。',119,'宋词/ci.song.2000.json','["又一番、沪水出牂牁。", "江声汹鸣鼍。", "正南人争望，转移虎节，弹压鲸波。", "未见元戎羽葆，民气已冲和。", "不待禁中选，李牧廉颇。", "却顾边陲以北，似乘航共济，亡楫中河。", "纵缆头襦尾，其奈不牢何。", "□明公、一襟忠愤，想誓江、无日不酣歌。", "当津者，岂应袖手，长宴江沱。"]'),
('song-ci-582','青玉案','吴泳','宋','宋词','song-ci','青玉案','[]','杏花时候匆匆别。',80,'宋词/ci.song.2000.json','["杏花时候匆匆别。", "又欲迫、黄花节。", "过了三年经八月。", "骊驹声里，青鸿头畔，几见刀头折。", "诸生立尽门前雪。", "半偈重翻为渠说。", "且莫从头烹瓠叶。", "已呼童稚，多藏酒秫，共醉陶彭泽。"]'),
('song-ci-583','谒金门','吴泳','宋','宋词','song-ci','谒金门','[]','将进酒。',53,'宋词/ci.song.2000.json','["将进酒。", "吹起黄钟清调。", "手按玉笙寒尚峭。", "陇梅春已透。", "蓝染溪光绿皱。", "花簇马蹄红斗。", "尽使宛陵人说道。", "状元今岁又。"]'),
('song-ci-584','谒金门','吴泳','宋','宋词','song-ci','谒金门','[]','金榜揭。',53,'宋词/ci.song.2000.json','["金榜揭。", "都是鹿鸣仙客。", "手按玉笙寒尚怯。", "倚梅歌一阕。", "柳拂御街明月。", "莺扑上林残雪。", "前岁杏花元一色。", "马蹄归路滑。"]'),
('song-ci-585','柳梢青','吴泳','宋','宋词','song-ci','柳梢青','[]','元九不回，胡三不问，花说与谁。',61,'宋词/ci.song.2000.json','["元九不回，胡三不问，花说与谁。", "赖得东皇，调停春住，句管花飞。", "庭前密打红围。", "想孙子、兵来出奇。", "似恁丰神，谁人刚道，色比明妃。"]'),
('song-ci-586','摸鱼儿','吴泳','宋','宋词','song-ci','摸鱼儿','[]','倚南墙、几回凝伫。',140,'宋词/ci.song.2000.json','["倚南墙、几回凝伫。", "绿筠冉冉如故。", "帝城景色缘何事，一半花枝风雨。", "收听取。", "这气象精神，则要人来做。", "当留客处。", "且遇酒高歌，逢场戏剧，莫作皱眉事。", "那个是，紫佩飞霞仙侣。", "骎骎云步如许。", "清闲笑我如鸥鹭。", "不肯对松觅句。", "萍散聚。", "又明月、还寻锦里烟霞路。", "浮名自误。", "待好好归来，携筒载酒，同访子云去。"]'),
('song-ci-587','水龙吟','吴泳','宋','宋词','song-ci','水龙吟','[]','修篁翠葆人家，分明水槛光中住。',126,'宋词/ci.song.2000.json','["修篁翠葆人家，分明水槛光中住。", "就中得要，危亭瞰渌，小桥当路。", "一榻桃笙，半窗竹简，清凉如许。", "纵武陵佳丽，若耶深窈，那得似、双溪趣。", "一夜檐花落枕，想鱼天、涨痕新露。", "多君唤我，扫花作晚，解衣逃暑。", "脍切银丝，酒招玉友，曲歌金缕。", "愿张郎，长与莲花相似，朝朝暮暮。"]'),
('song-ci-588','鱼游春水','吴泳','宋','宋词','song-ci','鱼游春水','[]','东里韶光早。',105,'宋词/ci.song.2000.json','["东里韶光早。", "百舌枝头啼碎了。", "溪梅开尽，池水绿波还皱。", "种柳先生觉意阑，看花君子非年少。", "心似淡云，梦随芳草。", "满地松花不扫。", "镇日春愁萦怀抱。", "谁能击筑长歌，吹笳清啸。", "寄声玉关行人道，未报君恩难便老。", "鸡塞雨寒，戍楼烟渺。"]'),
('song-ci-589','祝英台・祝英台近','吴泳','宋','宋词','song-ci','祝英台・祝英台近','[]','小池塘，闲院落，薄薄见山影。',96,'宋词/ci.song.2000.json','["小池塘，闲院落，薄薄见山影。", "杨柳风来，吹彻醉魂醒。", "有时低按秦筝，高歌水调，落花外、纷纷人境。", "猛深省。", "但有竹屋三间，莲田二顷。", "便可休官，日对漏壶永。", "假饶是、红杏尚书，碧桃学士，买不得、朱颜芳景。"]'),
('song-ci-590','千秋岁','吴泳','宋','宋词','song-ci','千秋岁','[]','松舟桂楫。',87,'宋词/ci.song.2000.json','["松舟桂楫。", "苕霅溪头别。", "秋后雨，春前雪。", "书凭湖雁寄，手把江蓠折。", "人未老，相看元似来时节。", "芳草鸣鶗鴂。", "野菜飞黄蝶。", "时易去，愁难说。", "析波浮玉醴，换火繙银叶。", "拚醉也，马蹄归踏梨花月。"]'),
('song-ci-591','上西平・金人捧露盘','吴泳','宋','宋词','song-ci','上西平・金人捧露盘','[]','似斜斜，才整整，又霏霏。',97,'宋词/ci.song.2000.json','["似斜斜，才整整，又霏霏。", "今夜里、窗户先知。", "嫌春未透，故穿庭树作花飞。", "起来寻访剡溪人，半压桥低。", "兔园册，渔江画，兰房曲，竹丘诗。", "怎模得、似当时。", "天寒堕指，问谁能解白登围。", "也须凭酒遣拿担，击乱鹅池。"]'),
('song-ci-592','沁园春','吴泳','宋','宋词','song-ci','沁园春','["\u6ed5\u738b\u9601"]','夸说洪都，西滕王阁，北豫章台。',139,'宋词/ci.song.2000.json','["夸说洪都，西滕王阁，北豫章台。", "对雨帘半卷，江横如旧，沟亭敧压，梯上无媒。", "但有江山，更无豪杰，拔脚风尘外一杯。", "题千墨，须杜陵老手，太白天才。", "力能笔走风雷。", "人道是闽乡老万回。", "把崇天普地，层胸荡出，横今竖古，信手拈来。", "使翰墨场，著伏波老，上马犹堪矍铄哉。", "今耄矣，独莼鲈在梦，泉石萦怀。"]'),
('song-ci-593','满江红','吴泳','宋','宋词','song-ci','满江红','[]','伶俐聪明，都不似、阿奴碌碌。',116,'宋词/ci.song.2000.json','["伶俐聪明，都不似、阿奴碌碌。", "渐欲买、青山路隐，白云同宿。", "半醉尽教乌帻堕，熟眠休管屏风触。", "算人生、能有几时闲，金乌速。", "粗粗饭，天仓粟。", "浊浊酒，天家禄。", "更钓鲜采薇，有何不足。", "君不见当年金谷事，绿珠弄笛椒涂屋。", "到而今、富贵一场空，终非福。"]'),
('song-ci-594','卜算子','吴泳','宋','宋词','song-ci','卜算子','[]','漠漠雨其濛，湛湛江之永。',52,'宋词/ci.song.2000.json','["漠漠雨其濛，湛湛江之永。", "冻压溪桥并见花，安得杯中影。", "明水未登彝，饰玉先浮鼎。", "寄语清居山上翁，驿使催归近。"]'),
('song-ci-595','满江红','吴泳','宋','宋词','song-ci','满江红','[]','元帅筹边，谁肯办、向前一著。',115,'宋词/ci.song.2000.json','["元帅筹边，谁肯办、向前一著。", "大丞相、孙儿挺伟，素闲兵略。", "杨柳依依烟在眼，檀车嘽嘽春浮脚。", "更何妨、二十五长亭，横冰槊。", "登剑栈，怀关洛。", "机易去，愁难割。", "岂而今全是，从前都错。", "鹿走未知真局面，兽穷渐近空篱落。", "早经营、勋业复归来，江头酌。"]'),
('song-ci-596','渔家傲','黄裳','宋','宋词','song-ci','渔家傲','[]','风入金波凝不住。',72,'宋词/ci.song.2000.json','["风入金波凝不住。", "玉楼间倚谁飞举。", "霜艳雪光来竞素。", "分辨处。", "独垂馀意窥庭户。", "强薄罗衣催玉步。", "美人为我当尊舞。", "醉到春来能几度。", "愁今古。", "月华不去年华去。"]'),
('song-ci-597','渔家傲','黄裳','宋','宋词','song-ci','渔家傲','[]','方令庚生初皎皎。',72,'宋词/ci.song.2000.json','["方令庚生初皎皎。", "珠帘钩上华堂晓。", "十二栏干多窈窕。", "妆欲妙。", "玉篦偷学娥眉小。", "扰扰时人随兔走。", "十分皆望菱花照。", "瑞荚莫嫌生得少。", "圆未了。", "已圆却恐佳期窵。"]'),
('song-ci-598','渔家傲','黄裳','宋','宋词','song-ci','渔家傲','[]','已送清歌归去后。',72,'宋词/ci.song.2000.json','["已送清歌归去后。", "东南楼上人声悄。", "冷落尤临弦上调。", "欢意少。", "空将万感收残照。", "窗外剑光初出鞘。", "斜窥梦断人年少。", "未到盖棺心未了。", "尘虑扰。", "双眸竟入扶桑晓。"]'),
('song-ci-599','永遇乐','黄裳','宋','宋词','song-ci','永遇乐','[]','朝霭藏晖，客袍惊暖，天巧无意。',128,'宋词/ci.song.2000.json','["朝霭藏晖，客袍惊暖，天巧无意。", "杳杳谁知，包含造化，忽作人间瑞。", "儿童欢笑，忙来花下，便饮九春和气。", "急拿舟，高人乘兴，江天助我幽思。", "缤纷似翦，峥嵘如画，莫道冬容憔悴。", "恍象含空，尘无一点，疑在天宫里。", "酒楼酣宴，茶轩清玩，且待桂花来至。", "有馀光，明年待看，明红暗翠。"]'),
('song-ci-600','永遇乐','黄裳','宋','宋词','song-ci','永遇乐','[]','天接重云，月临残腊，时有幽意。',128,'宋词/ci.song.2000.json','["天接重云，月临残腊，时有幽意。", "化作瑶池，纷纷戏蝶，一色非人世。", "无情征雁，乘风南向，怅望有情难寄。", "暖惊梅，先传芳信，夜来万宝春至。", "中齐胜境，东藩和气，自有名园佳丽。", "一梦休嗟，三千好客，何处寻珠履。", "小堂人静，尊前清昼，好惜岁华如逝。", "管弦中，金杯更劝，朱颜皓齿。"]'),
('song-ci-601','蓦山溪','黄裳','宋','宋词','song-ci','蓦山溪','[]','春前信息，到处欢声满。',102,'宋词/ci.song.2000.json','["春前信息，到处欢声满。", "旌旆出西郊，拥笙歌、婵娟两畔。", "东巡事往，空有雪中山，仙驭悄，古风间，谩动吟人叹。", "天边身世，况值重华旦。", "击壤访遗民，想如云、望中不断。", "功名休论，齐楚共唐虞，开口笑，插花归，更候清秋晚。"]'),
('song-ci-602','喜朝天・踏莎行','黄裳','宋','宋词','song-ci','喜朝天・踏莎行','[]','雪云浓。',126,'宋词/ci.song.2000.json','["雪云浓。", "送愁思，衾寒更怯霜风。", "惹起离恨，为光阴恼，人意无穷。", "谁省年华屡换，渐作个、浮生玉髯翁。", "休易感，新醅泛蚁，且共时同。", "相逢。", "笑语相契，况驾言游处，山里齐宫。", "寂寞时候，自有皓景，粉泽冬容。", "先顾丽人期约，痛赏候、花开洛城红。", "三十日，回头过尽，喜对春工。"]'),
('song-ci-603','锦堂春・锦堂春慢','黄裳','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','天女多情，梨花碎翦，人间赠与多才。',117,'宋词/ci.song.2000.json','["天女多情，梨花碎翦，人间赠与多才。", "渐瑶池潋滟，粉翘徘徊。", "面不禁风力，背人飞去还来。", "最清虚好处，遥度幽香，不掩寒梅。", "岁华多幸呈瑞，泛寒光，一样仙子楼台。", "虽喜朱颜可照，时更相催。", "细认沙汀鹭下，静看烟渚潮回。", "遣青蛾趁拍，斗献轻盈，且更传杯。"]'),
('song-ci-604','霜叶飞','黄裳','宋','宋词','song-ci','霜叶飞','[]','谁能留得年华住。',137,'宋词/ci.song.2000.json','["谁能留得年华住。", "韶华今在何处。", "万林飞尽，但惊天篆，半空无数。", "望消息、霜催雁过，佳人愁起云垂暮。", "就绣幕、红炉去。", "金鸭时飘异香，柳腰人舞。", "休道行且分飞，共乐还一岁，见景长是欢聚。", "大来芳意，既与名园，是花为主。", "翠娥说、尊前笑语，来年管取人如故。", "向寂寞，中先喜，俄顷飞琼，化成寰宇。"]'),
('song-ci-605','水龙吟','黄裳','宋','宋词','song-ci','水龙吟','[]','五城中锁奇书，世间睡里无人唤。',125,'宋词/ci.song.2000.json','["五城中锁奇书，世间睡里无人唤。", "家家自有，月中丹桂，朱衣仙子。", "能驻光阴，解留颜鬓，引君霄汉。", "便西归、休梦华胥国□，约无限、烟霞伴。", "谁是采真高士，幻中寻取元非幻。", "时人不为，玉峰三秀，尘缘难断。", "莫说英雄，万端愁绪，夕阳孤馆。", "到流年过尽，韶华去了，起浮生叹。"]'),
('song-ci-606','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','每到花开春已暮。',70,'宋词/ci.song.2000.json','["每到花开春已暮。", "况是人生，难得长欢聚。", "一日一游能几度。", "看看背我堂堂去。", "蝶乱蜂忙红粉妒。", "醉眼吟情，且与花为主。", "雪怨云愁无问处。", "芳心待向谁分付。"]'),
('song-ci-607','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','兴到浓时春不住。',70,'宋词/ci.song.2000.json','["兴到浓时春不住。", "昨夜雕栏，放了花无数。", "谈笑急邀吟醉侣。", "青娥也合随轩去。", "媚恐情生娇恐妒。", "今日开尊，多幸无风雨。", "休唱宴琼林一句。", "来年花共人何处。"]'),
('song-ci-608','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','南北两山骄欲斗。',70,'宋词/ci.song.2000.json','["南北两山骄欲斗。", "中有涟漪，莫道壶山小。", "落落情怀临漂渺。", "驾言来处铃斋悄。", "行到桃溪花解笑。", "人面相逢，竞好窥寒照。", "醉步敧斜西日少。", "欢声犹唱多情调。"]'),
('song-ci-609','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','高下亭台山水境。',70,'宋词/ci.song.2000.json','["高下亭台山水境。", "两畔清辉，中有垂杨径。", "鹭点前汀供雪景。", "花乘流水传春信。", "不醉无归先说定。", "醉待言归，又被风吹醒。", "月下壶天游未尽。", "广寒宫是波中影。"]'),
('song-ci-610','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','杳杳晴虚寒漫漫。',70,'宋词/ci.song.2000.json','["杳杳晴虚寒漫漫。", "放下尘劳，相共游银汉。", "便入醉乡休浩叹。", "神仙只在云门馆。", "饮兴偏宜流水畔。", "时有红蕖，落在黄金盏。", "鹭未忘机移别岸。", "画船更上前汀看。"]'),
('song-ci-611','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','水鉴中看尤未老。',70,'宋词/ci.song.2000.json','["水鉴中看尤未老。", "乘兴拿舟，更向湘江过。", "俯仰太虚都一个。", "九春风思谁吟到。", "闲上钓台云外坐。", "待得金鳞，始放芳尊倒。", "醉后言归犹更早。", "素纤有数君须道。"]'),
('song-ci-612','喜迁莺','黄裳','宋','宋词','song-ci','喜迁莺','[]','雕栏闲倚，瑞雪霁、浣出人间金碧。',124,'宋词/ci.song.2000.json','["雕栏闲倚，瑞雪霁、浣出人间金碧。", "下想名园，芳心多少，欲占九州颜色。", "洞开路入丹汉，自是神仙真宅。", "寒吟外，看歌云舞雪，光阴难得。", "谁共怀古意，东海一老，居易头垂白。", "自此英雄，功名相继，空有寂寥遗迹。", "圣贤电拂休笑，离合许多宾客。", "使君乐与人同，且对云门斜日。"]'),
('song-ci-613','宴琼林','黄裳','宋','宋词','song-ci','宴琼林','[]','红紫趁春阑，独万簇琼英，尤未开罢。',129,'宋词/ci.song.2000.json','["红紫趁春阑，独万簇琼英，尤未开罢。", "问谁共、绿幄宴群真，皓雪肌肤相亚。", "华堂路，小桥边，向晴阴一架。", "为香清、把作寒梅看，喜风来偏惹。", "莫笑因缘，见景跨春空，荣称亭榭。", "助巧笑、晓妆如画，有花钿堪借。", "新醅泛、寒冰几点，拚今日、醉尤飞斝。", "翠罗帏中，卧蟾光碎，何须待还舍。"]'),
('song-ci-614','宴春台','黄裳','宋','宋词','song-ci','宴春台','[]','夏景舒长，麦天清润，高低万木成阴。',120,'宋词/ci.song.2000.json','["夏景舒长，麦天清润，高低万木成阴。", "晓意寒轻，一声未放蝉吟。", "但闻莺友同音。", "宴华堂、绿水中心。", "芙蓉都没，红妆信息，终待重寻。", "清冷相照，邂逅俱欢，翠娥拥我，芳酝强斟。", "笙歌引步，登临更向瑶岑。", "卧影沈沈。", "自风来、与客披襟。", "纵更深。", "归来洞府，红烛如林。"]'),
('song-ci-615','雨霖铃','黄裳','宋','宋词','song-ci','雨霖铃','[]','天南游客。',128,'宋词/ci.song.2000.json','["天南游客。", "甚而今、却送君南国。", "薰风万里无限，吟蝉暗续，离情如织。", "秣马脂车，去即去、多少人惜。", "为惠爱、烟惨云山，送两城愁作行色。", "飞帆过、浙西封域。", "到秋深、且舣菏花泽。", "就船买得鲈鳜。", "新谷破、雪堆香粒。", "此兴谁同，须记东秦，有客相忆。", "愿听了、一阕歌声，醉倒拚今日。"]'),
('song-ci-616','桂枝香','黄裳','宋','宋词','song-ci','桂枝香','[]','醱醅初熟。',123,'宋词/ci.song.2000.json','["醱醅初熟。", "竞看九日、西风弄寒菊。", "姝子新妆，向晓淡黄千簇。", "清香闹处君须住，掺盈头、醉乡相逐。", "马台欢笑，龙山纵逸，佳话重绪。", "共尽日、登临未足。", "更休问明年，浮世荣辱。", "难得良辰，鬓发见秋尤绿。", "且邀月照金尊上，近人寒、如对飞瀑。", "宴归还趁人来，茱萸佩垂红玉。"]'),
('song-ci-617','喜迁莺','黄裳','宋','宋词','song-ci','喜迁莺','[]','梅霖初歇。',126,'宋词/ci.song.2000.json','["梅霖初歇。", "乍绛蕊海榴，争开时节。", "角黍包金，香蒲切玉，是处玳筵罗列。", "斗巧尽输少年，玉腕彩丝双结。", "舣彩舫，看龙舟两两，波心齐发。", "奇绝。", "难画处，激起浪花，飞作湖间雪。", "画鼓喧雷，红旗闪电，夺罢锦标方彻。", "望中水天日暮，犹见朱帘高揭。", "归棹晚，载菏花十里，一钩新月。"]'),
('song-ci-618','洞仙歌','黄裳','宋','宋词','song-ci','洞仙歌','[]','乱蝉何事，冒暑吟如诉。',102,'宋词/ci.song.2000.json','["乱蝉何事，冒暑吟如诉。", "断续声中为谁苦。", "阵云行碧落，舒卷光阴，秋意爽，俄作晴空骤雨。", "明珠无限数。", "都在荷花，疑是星河对庭户。", "莫负昼如年，况有清尊，披襟坐、水风来处。", "信美景良辰、自古难并，既不遇多才，岂能欢聚。"]'),
('song-ci-619','洞仙歌','黄裳','宋','宋词','song-ci','洞仙歌','[]','杳无风色，肠断莲花信。',102,'宋词/ci.song.2000.json','["杳无风色，肠断莲花信。", "水鉴云垂数峰影。", "向劳生辛苦，寒暑煎人，争不老，空想秋堂夜静。", "玉姬挥皓月，时送微凉，莫吝金卮为伊尽。", "柳下夕阳收，傍水重游，花茵上、雪回襟冷。", "问避暑天机、自有奇人，但且对湖光，世间谁醒。"]'),
('song-ci-620','洞仙歌','黄裳','宋','宋词','song-ci','洞仙歌','[]','世间言笑，天上谁欢聚。',102,'宋词/ci.song.2000.json','["世间言笑，天上谁欢聚。", "河汉涵秋静无暑。", "望丹霄杳杳，云幄俄开，缘会远，空引时情万缕。", "彩楼人送目，今夕无双，巧在灵丝暗相许。", "爽气御西风，众乐难寻，乘槎看、鹊桥初度。", "过几刻良时、早已分飞，向月下何辞，十分芳醑。"]'),
('song-ci-621','八声甘州','黄裳','宋','宋词','song-ci','八声甘州','[]','化工多事了，却收天巧，都与西风。',119,'宋词/ci.song.2000.json','["化工多事了，却收天巧，都与西风。", "数峰云如扫，闲垂六幕，初见秋容。", "昨夜烦襟顿释，一雨洗遥空。", "偏有银蟾好，千里人同。", "引起游人多感，为静中景色，悲思无穷。", "傍雕栏怀古，谁问紫元翁。", "也难逢、金华时候，又岂知、幽会水精宫。", "尘缘满，指烟霞去，多在江东。"]'),
('song-ci-622','满庭芳','黄裳','宋','宋词','song-ci','满庭芳','[]','琼馆烟轻，银河风细，玉桥云锁方开。',118,'宋词/ci.song.2000.json','["琼馆烟轻，银河风细，玉桥云锁方开。", "晓虹千丈，宛转下天来。", "人在水精宫里，行乐处、锦绣成堆。", "仍相问，人间天上，何处有蓬莱。", "徘徊。", "追往事，征南巧架，傅野怀才。", "谩石驱东海，沙合龙台。", "好是乐成初宴，红牙碎、声隐晴雷。", "江天晚，游人未散，莫放隼旟回。"]'),
('song-ci-623','宴琼林','黄裳','宋','宋词','song-ci','宴琼林','[]','霜月和银灯，乍送目楼台，星汉高下。',128,'宋词/ci.song.2000.json','["霜月和银灯，乍送目楼台，星汉高下。", "爱东风、已暖绮罗香，竞走去来车马。", "红莲万斛，开尽处、长安一夜。", "少年郎、两两桃花面，有馀光相借。", "因甚灵山在此，是何人、能运神化。", "对景便作神仙会，恐云軿且驾。", "思曾侍、龙楼俯览，笑声远、洞天飞斝。", "向东来、尤幸时如故，群芳未开谢。"]'),
('song-ci-624','宴琼林','黄裳','宋','宋词','song-ci','宴琼林','[]','遽暖间俄寒，妙用向园林，难问春意。',128,'宋词/ci.song.2000.json','["遽暖间俄寒，妙用向园林，难问春意。", "万般声与色，自闻雷、便作浮华人世。", "红娇翠软，谁顿悟、天机此理。", "似韶容、可驻无人会，且忘言闲醉。", "当度仙家长日，向人间、闲看佳丽。", "念远处有东风在，梦悠悠往事。", "桃溪近、幽香远远，谩凝望、落花流水。", "桂华中、珠佩随轩去，还从卖花市。"]'),
('song-ci-625','宴琼林','黄裳','宋','宋词','song-ci','宴琼林','[]','已览遍韶容，最后有花王，芳信来报。',128,'宋词/ci.song.2000.json','["已览遍韶容，最后有花王，芳信来报。", "魏妃天与色，拥姚黄、去赏十洲仙岛。", "东君到此，缘费尽、天机亦老。", "为娇多、只恐能言笑。", "惹风流烦恼。", "莫道两都迥出，倩多才、吟看谁好。", "为我惨有如花面，说良辰欲过。", "须勤向、雕栏秉烛，更休管、夕阳芳草。", "算来年、花共人何处，金尊为花倒。"]'),
('song-ci-626','满江红','黄裳','宋','宋词','song-ci','满江红','[]','绿盖纷纷，多少个、云霄仙子。',117,'宋词/ci.song.2000.json','["绿盖纷纷，多少个、云霄仙子。", "应是有，瑶池盛会，靓妆临水。", "无奈轻盈风信急，瑞香乱翠红相倚。", "谁共吟、此景竹林人，桃溪士。", "时雨过，明珠细。", "朝雾染，香腮腻。", "轻舟破幽径，烦襟都洗。", "第一朵须寻华池景，寿觞边偶得龟千岁。", "乘兴泻、云液落新荷，休辞醉。"]'),
('song-ci-627','减字木兰花','黄裳','宋','宋词','song-ci','减字木兰花','[]','红旗高举。',52,'宋词/ci.song.2000.json','["红旗高举。", "飞出深深杨柳渚。", "鼓击春雷。", "直破烟波远远回。", "欢声震地。", "惊退万人争战气。", "金碧楼西。", "衔得锦标第一归。"]'),
('song-ci-628','瑶池月・瑶台月','黄裳','宋','宋词','song-ci','瑶池月・瑶台月','[]','微尘濯尽，栖真处、群山排在云汉。',150,'宋词/ci.song.2000.json','["微尘濯尽，栖真处、群山排在云汉。", "青盘翠跃，掩映平林寒涧。", "流水急、数片桃花逝，自有留春仙馆。", "秦渔问，前朝换。", "卢郎待，今生满。", "谁伴。", "元翁笑语，相从未晚。", "更安得、世味堪玩。", "道未立、身尤是幻。", "浮生一梭过，梦回人散。", "卧松庵、当会灵源，现万象、无中须看。", "乾坤鼎，阴阳炭。", "琼枝秀，金圆烂。", "何患。", "朝元事往，孤云难管。"]'),
('song-ci-629','瑶池月・瑶台月','黄裳','宋','宋词','song-ci','瑶池月・瑶台月','[]','扁舟寓兴，江湖上、无人知道名姓。',150,'宋词/ci.song.2000.json','["扁舟寓兴，江湖上、无人知道名姓。", "忘机对景，咫尺群鸥相认。", "烟雨急、一片篷声碎，醉眼看山还醒。", "晴云断，狂风信。", "寒蟾倒，远山影。", "谁听。", "横琴数曲，瑶池夜冷。", "这些子、名利休问。", "况是物、都归幻境。", "须臾百年梦，去来无定。", "向婵娟、留住青春，笑世上、风流多病。", "蒹葭渚，芙蓉径。", "放侯印，趁渔艇。", "争甚。", "须知九鼎，金砂如圣。"]'),
('song-ci-630','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','忽破黄昏还太素。',70,'宋词/ci.song.2000.json','["忽破黄昏还太素。", "寒浸楼台，缥缈非烟雾。", "江上分明星汉路。", "金银闪闪神仙府。", "影卧清光随我舞。", "邂逅三人，只愿长相聚。", "今月亭亭曾照古。", "古人问月今何处。"]'),
('song-ci-631','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','满到十分人望尽。',70,'宋词/ci.song.2000.json','["满到十分人望尽。", "仙桂无根，到处留光景。", "听我尊前欢未竟。", "金卮已弄寒蟾影。", "银色界中风色定。", "散了浮云，宝匣初开镜。", "归去不须红烛影。", "天边自与人相趁。"]'),
('song-ci-632','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','古往今来忙里过。',70,'宋词/ci.song.2000.json','["古往今来忙里过。", "今古清光，静照人行道。", "难似素娥长见好。", "见频只是催人老。", "欲驻征轮无计那。", "世上多情，却被无情恼。", "夜夜乌飞谁识破。", "满头空恨霜华早。"]'),
('song-ci-633','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','俄落盏中如有恋。',70,'宋词/ci.song.2000.json','["俄落盏中如有恋。", "盏未乾时，还见霜娥现。", "说向翠鬟斟莫浅。", "殷勤此意应相劝。", "光景尤宜年少面。", "千里同看，不与人同怨。", "席上笑歌身更健。", "良时只愿长相见。"]'),
('song-ci-634','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','千二百回圆未半。',70,'宋词/ci.song.2000.json','["千二百回圆未半。", "人世悲欢，此景长相伴。", "行到身边琼步款。", "金船载酒银河畔。", "谁为别来音信断。", "那更蟾光，一点窥孤馆。", "静送忘言愁一段。", "会须莫放笙歌散。"]'),
('song-ci-635','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','人逐金乌忙到夜。',70,'宋词/ci.song.2000.json','["人逐金乌忙到夜。", "不见金乌，方见人闲暇。", "天汉似来尊畔泻。", "须知闲暇欢无价。", "银色满身谁可画。", "两腋风生，爽气骎骎马。", "待入蟾宫偷造化。", "姮娥已许仙方借。"]'),
('song-ci-636','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','万籁无声天地静。',70,'宋词/ci.song.2000.json','["万籁无声天地静。", "清抱朱弦，不愧丹霄镜。", "照到林梢风有信。", "抬头疑是梅花领。", "万感只应闲对景。", "独倚危栏，扰扰人初定。", "吟不尽中愁不尽。", "溪山千古沈沈影。"]'),
('song-ci-637','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','谁悟月中真火冷。',70,'宋词/ci.song.2000.json','["谁悟月中真火冷。", "能引尘缘，遂出轮迥境。", "争奈多情都未醒。", "九回肠断花间影。", "万古兴亡闲事定。", "物是人非，杳杳无音信。", "问月可知谁可问。", "不如且醉尊前景。"]'),
('song-ci-638','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','忽送林光禽有语。',70,'宋词/ci.song.2000.json','["忽送林光禽有语。", "飞如遥空，失素归洲鹭。", "照处无私清望富。", "馀辉不惜人人与。", "玉绳欲到中天路。", "且待飞觞，缓缓移琼步。", "花下影圆良夜午。", "东南楼上还相顾。"]'),
('song-ci-639','蝶恋花','黄裳','宋','宋词','song-ci','蝶恋花','[]','一望瑶华初委地。',70,'宋词/ci.song.2000.json','["一望瑶华初委地。", "更约幽人，共赏岩边翠。", "拭把方诸聊与试。", "无情争得无中泪。", "飞瀑恐从星汉至。", "渐向宾筵，但觉寒如水。", "自爱一轮方得意。", "轻随箕毕还成累。"]'),
('song-ci-640','青门引・青门饮','黄裳','宋','宋词','song-ci','青门引・青门饮','[]','鸿落寒滨，燕辞幽馆，西成万室，颦眉人少。',132,'宋词/ci.song.2000.json','["鸿落寒滨，燕辞幽馆，西成万室，颦眉人少。", "自古云隮，洞门何处，南望数峰秋晓。", "千骑旌麾远，去寻真、忙中心了。", "佩声盘入，烟霞绝顶，谁闻欢笑。", "当候青童相报。", "因待访仙人，长生微妙。", "置俎争来，四乡宴社，且看翠围红绕。", "似可扪青汉，到北扉、两城斜照。", "醉翁回首，丹台梦觉，钧天声杳。"]'),
('song-ci-641','满路花・促拍满路花','黄裳','宋','宋词','song-ci','满路花・促拍满路花','[]','乾坤生古意，草木起秋声。',103,'宋词/ci.song.2000.json','["乾坤生古意，草木起秋声。", "移人名利境，梦中惊。", "便寻灵宝，凤髓与龟精。", "密报黄芽就，紫府门开，道情有个莺莺。", "问归含楚山青。", "卧影水天明。", "松庵谁笑话，见还婴。", "鹤归日落，聚散两忘情。", "好笑人痴处，白头青冢，世间犹说醒醒。"]'),
('song-ci-642','倦寻芳慢・倦寻芳','王','宋','宋词','song-ci','倦寻芳慢・倦寻芳','[]','露晞向晚，帘幕风轻，小院闲昼。',118,'宋词/ci.song.2000.json','["露晞向晚，帘幕风轻，小院闲昼。", "翠迳莺来，惊下乱红铺绣。", "倚危墙，登高榭，海棠经雨胭脂透。", "算韶华，又因循过了，清明时候。", "倦游燕、风光满目，好景良辰，谁共携手。", "恨被榆钱，买断两眉长斗。", "忆高阳，人散后。", "落花流水仍依旧。", "这情怀，对东风、尽成消瘦。"]'),
('song-ci-643','虞美人','张景修','宋','宋词','song-ci','虞美人','[]','春风曾见桃花面。',66,'宋词/ci.song.2000.json','["春风曾见桃花面。", "重见胜初见。", "两枝独占小春开。", "应怪刘郎迷路、又重来。", "旁人应笑髯公老。", "独爱花枝好。", "世间好景不长圆。", "莫放笙歌归院、且尊前。"]'),
('song-ci-644','选冠子','张景修','宋','宋词','song-ci','选冠子','[]','嫩水挼蓝，遥堤映翠，半雨半烟桥畔。',138,'宋词/ci.song.2000.json','["嫩水挼蓝，遥堤映翠，半雨半烟桥畔。", "鸣禽弄舌，蔓草萦心，偏称谢家池馆。", "红粉墙头，柳摇金缕，纤柔舞腰低软。", "被和风、搭在阑干，终日绣帘谁卷。", "春易老，细叶舒眉，轻花吐絮，渐觉绿阴垂暖。", "章台系马，灞水维舟，追念凤城人远。", "惆怅阳关故国，杯酒飘零，惹人肠断。", "恨青青客舍，江头风笛，乱云空晚。"]'),
('song-ci-645','青玉案','黄大临','宋','宋词','song-ci','青玉案','[]','行人欲上来时路。',80,'宋词/ci.song.2000.json','["行人欲上来时路。", "破晓雾、轻寒去。", "隔叶子规声暗度。", "十分酒满，舞裀歌袖，沾夜无寻处。", "故人近送旌旗暮。", "但听阳关第三句。", "欲断离肠馀几许。", "满天星月，看人憔悴，烛泪垂如雨。"]'),
('song-ci-646','青玉案','黄大临','宋','宋词','song-ci','青玉案','[]','千锋百嶂宜州路。',80,'宋词/ci.song.2000.json','["千锋百嶂宜州路。", "天黯淡、知人去。", "晓别吾家黄叔度。", "弟兄华发，远山修水，异日同归处。", "樽罍饮散长亭暮。", "别语缠绵不成句。", "已断离肠能几许。", "水村山馆，夜阑无寐，听尽空阶雨。"]'),
('song-ci-647','七娘子','黄大临','宋','宋词','song-ci','七娘子','[]','画堂银烛明如昼。',72,'宋词/ci.song.2000.json','["画堂银烛明如昼。", "见林宗、巾垫羞蓬首。", "针指花枝，线赊罗袖。", "须臾两带还依旧。", "劝君倒戴休令后。", "也不须、更漉渊明酒。", "宝箧深藏，浓香熏透。", "为经十指如葱手。"]'),
('song-ci-648','念奴娇','黄庭坚','宋','宋词','song-ci','念奴娇','[]','断虹霁雨，净秋空，山染修眉新绿。',121,'宋词/ci.song.2000.json','["断虹霁雨，净秋空，山染修眉新绿。", "桂影扶疏，谁便道，今夕清辉不足。", "万里青天，姮娥何处，驾此一轮玉。", "寒光零乱，为谁遍照醽醁。", "年少从我追游，晚凉幽径，绕张园森木。", "共倒金荷家万里，难得尊前相属。", "老子平生，江南江北，最爱临风曲。", "孙郎微笑，坐来声喷霜竹。"]'),
('song-ci-649','水调歌头','黄庭坚','宋','宋词','song-ci','水调歌头','[]','瑶草一何碧，春入武陵溪。',114,'宋词/ci.song.2000.json','["瑶草一何碧，春入武陵溪。", "溪上桃花无数，花上有黄鹂。", "我欲穿花寻路，直入白云深处，浩气展红霓。", "只恐花深里，红露湿人衣。", "坐玉石，敧玉枕，拂金徽。", "谪仙何处，无人伴我白螺杯。", "我为灵芝仙草，不为朱唇丹脸，长啸亦何为。", "醉舞下山去，明月逐人归。"]'),
('song-ci-650','水调歌头','黄庭坚','宋','宋词','song-ci','水调歌头','[]','落日塞垣路，风劲戛貂裘。',114,'宋词/ci.song.2000.json','["落日塞垣路，风劲戛貂裘。", "翩翩数骑闲猎，深入黑山头。", "极目平沙千里，惟见雕弓白羽，铁面骏骅骝。", "隐隐望青冢，特地起闲愁。", "汉天子，方鼎盛，四百州。", "玉颜皓齿，深锁三十六宫秋。", "堂有经纶贤相，边有纵横谋将，不减翠娥羞。", "戎虏和乐也，圣主永无忧。"]'),
('song-ci-651','满庭芳','黄庭坚','宋','宋词','song-ci','满庭芳','[]','初绾云鬟，才胜罗绮，便嫌柳陌花街。',118,'宋词/ci.song.2000.json','["初绾云鬟，才胜罗绮，便嫌柳陌花街。", "占春才子，容易托行媒。", "其奈风情债负，烟花部、不免差排。", "刘郎恨，桃花片片，随水染尘埃。", "风流，贤太守，能笼翠羽，宜醉金钗。", "且留取垂杨，掩映厅阶。", "直待朱轓去后，从伊便、窄袜弓鞋。", "知恩否，朝云暮雨，还向梦中来。"]'),
('song-ci-652','满庭芳','黄庭坚','宋','宋词','song-ci','满庭芳','[]','北苑春风，方圭圆璧，万里名动京关。',118,'宋词/ci.song.2000.json','["北苑春风，方圭圆璧，万里名动京关。", "碎身粉骨，功合上凌烟。", "尊俎风流战胜，降春睡、开拓愁边。", "纤纤捧，研膏溅乳，金缕鹧鸪斑。", "相如，虽病渴，一觞一咏，宾有群贤。", "为扶起灯前，醉玉颓山。", "搜搅心中万卷，还倾动、三峡词源。", "归来晚，文君未寝，相对小窗前。"]'),
('song-ci-653','鼓笛慢・水龙吟','黄庭坚','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','早秋明月新圆，汉家戚里生飞将。',126,'宋词/ci.song.2000.json','["早秋明月新圆，汉家戚里生飞将。", "青骢宝勒，绿沈金锁，曾瞻天仗。", "种德江南，宣威西夏，合宫陪享。", "况当年定计，昭陵与子，勋劳在、诸公上。", "千骑风流年少，暂淹留、莫辜清赏。", "平坡驻马，虚弦落雁，思临虏帐。", "遍舞摩围，递歌彭水，拂云惊浪。", "看朱颜绿鬓，封侯万里，写凌烟像。"]'),
('song-ci-654','洞仙歌','黄庭坚','宋','宋词','song-ci','洞仙歌','[]','月中丹桂，自风霜难老。',104,'宋词/ci.song.2000.json','["月中丹桂，自风霜难老。", "阅尽人间盛衰草。", "望中秋、才有几日，十分圆，霾风雨，云表常如永昼。", "不得文章力，白首防秋，谁念云中上功守。", "正注意，得人雄，静扫河山，应难纵、五湖归棹。", "问持节冯唐几时来，看再策勋名，印窠如斗。"]'),
('song-ci-655','雨中花・夜行船','黄庭坚','宋','宋词','song-ci','雨中花・夜行船','[]','政乐中和，夷夏宴喜，官梅乍传消息。',121,'宋词/ci.song.2000.json','["政乐中和，夷夏宴喜，官梅乍传消息。", "待作新年欢计，断送春色。", "桃李成阴，甘棠少讼，又移旌戟。", "念画楼朱阁，风流高会，顿冷谈席。", "西州纵有，舞裙歌板，谁共茗邀棋敌。", "归来未得，先沾离袖，管弦催滴。", "乐事赏心易散，良辰美景难得。", "会须醉倒，玉山扶起，更倾春碧。"]'),
('song-ci-656','忆帝京','黄庭坚','宋','宋词','song-ci','忆帝京','[]','鸣鸠乳燕春闲暇。',87,'宋词/ci.song.2000.json','["鸣鸠乳燕春闲暇。", "化作绿阴槐夏。", "寿酒舞红裳，睡鸭飘香麝。", "醉此洛阳人，佐郡深儒雅。", "况坐上、玉麟金马。", "更莫问、莺老花谢。", "万里相依，千金为寿，未厌玉烛传清夜。", "不醉欲言归，笑杀高阳社。"]'),
('song-ci-657','醉蓬莱','黄庭坚','宋','宋词','song-ci','醉蓬莱','[]','对朝云叆叇，暮雨霏微，乱峰相倚。',120,'宋词/ci.song.2000.json','["对朝云叆叇，暮雨霏微，乱峰相倚。", "巫峡高唐，锁楚宫朱翠。", "画戟移春，靓妆迎马，向一川都会。", "万里投荒，一身吊影，成何欢意。", "尽道黔南，去天尺五，望极神州，万里烟水。", "尊酒公堂，有中朝佳士。", "荔颊红深，麝脐香满，醉舞裀歌袂。", "杜宇声声，催人到晓，不如归是。"]'),
('song-ci-658','南歌子','黄庭坚','宋','宋词','song-ci','南歌子','[]','诗有渊明语，歌无子夜声。',62,'宋词/ci.song.2000.json','["诗有渊明语，歌无子夜声。", "论文思见老弥明。", "坐想罗浮山下、羽衣轻。", "何处黔中郡，遥知隔晚晴。", "雨馀风急断虹横。", "应梦池塘春草、若为情。"]'),
('song-ci-659','蓦山溪','黄庭坚','宋','宋词','song-ci','蓦山溪','[]','鸳鸯翡翠，小小思珍偶。',102,'宋词/ci.song.2000.json','["鸳鸯翡翠，小小思珍偶。", "眉黛敛秋波，尽湖南、山明水秀。", "娉娉袅袅，恰近十三馀，春未透。", "花枝瘦。", "正是愁时候。", "寻花载酒。", "肯落谁人后。", "只恐远归来，绿成阴、青梅如豆。", "心期得处，每自不由人，长亭柳。", "君知否。", "千里犹回首。"]'),
('song-ci-660','转调丑奴儿・采桑子','黄庭坚','宋','宋词','song-ci','转调丑奴儿・采桑子','[]','得意许多时。',76,'宋词/ci.song.2000.json','["得意许多时。", "长醉赏、月影花枝。", "暴风狂雨年年有，金笼锁定，莺雏燕友，不被鸡期。", "红旆转逶迤。", "悔无计、千里追随。", "再来应绾泸南印，而今目下，凄惶怎向，日永春迟。"]'),
('song-ci-661','品令','黄庭坚','宋','宋词','song-ci','品令','[]','败叶霜天晓。',79,'宋词/ci.song.2000.json','["败叶霜天晓。", "渐鼓吹、催行棹。", "栽成桃李未开，便解银章归报。", "去取麒麟图画，要及年少。", "劝公醉倒。", "别语怎向醒时道。", "楚山千里暮云，正锁离人情抱。", "记取江州司马，坐中最老。"]'),
('song-ci-662','踏莎行','黄庭坚','宋','宋词','song-ci','踏莎行','[]','画鼓催春，蛮歌走饷。',68,'宋词/ci.song.2000.json','["画鼓催春，蛮歌走饷。", "雨前一焙谁争长。", "低株摘尽到高株，株株别是闽溪样。", "碾破春风，香凝午帐。", "银瓶雪滚翻成浪。", "今宵无睡酒醒时，摩围影在秋江上。"]'),
('song-ci-663','踏莎行','黄庭坚','宋','宋词','song-ci','踏莎行','[]','临水夭桃，倚墙繁李。',68,'宋词/ci.song.2000.json','["临水夭桃，倚墙繁李。", "长杨风掉青骢尾。", "尊中有酒且酬春，更寻何处无愁地。", "明日重来，落花如绮。", "芭蕉渐展山公启。", "欲笺心事寄天公，教人长对花前醉。"]'),
('song-ci-664','定风波','黄庭坚','宋','宋词','song-ci','定风波','[]','自断此生休问天。',73,'宋词/ci.song.2000.json','["自断此生休问天。", "白头波上泛孤船。", "老去文章无气味。", "憔悴。", "不堪驱使菊花前。", "闻道使君携将吏。", "高会。", "参军吹帽晚风颠。", "千骑插花秋色暮。", "归去。", "翠娥扶入醉时肩。"]'),
('song-ci-665','定风波','黄庭坚','宋','宋词','song-ci','定风波','[]','万里黔中一漏天。',73,'宋词/ci.song.2000.json','["万里黔中一漏天。", "屋居终日似乘船。", "及至重阳天也霁。", "催醉。", "鬼门关外蜀江前。", "莫笑老翁犹气岸。", "君看。", "几人黄菊上华颠。", "戏马台南追两谢。", "驰射。", "风流犹拍古人肩。"]'),
('song-ci-666','定风波','黄庭坚','宋','宋词','song-ci','定风波','[]','晚岁监州闻荔枝。',73,'宋词/ci.song.2000.json','["晚岁监州闻荔枝。", "赤英垂坠压阑枝。", "万里来逢芳意歇。", "愁绝。", "满盘空忆去年时。", "涧草山花光照坐。", "春过。", "等闲桃李又累累。", "辜负寒泉浸红皱。", "消瘦。", "有人花病损香肌。"]'),
('song-ci-667','定风波','黄庭坚','宋','宋词','song-ci','定风波','[]','准拟阶前摘荔枝。',73,'宋词/ci.song.2000.json','["准拟阶前摘荔枝。", "今年歇尽去年枝。", "莫是春光厮料理。", "无比。", "譬如痎疟有休时。", "碧甃朱阑情不浅。", "何晚。", "来年枝上报累累。", "雨后园林坐清影。", "苏醒。", "红裳剥尽看香肌。"]'),
('song-ci-668','鹊桥仙','黄庭坚','宋','宋词','song-ci','鹊桥仙','[]','八年不见，清都绛阙，望河汉、溶溶漾漾。',70,'宋词/ci.song.2000.json','["八年不见，清都绛阙，望河汉、溶溶漾漾。", "年年牛女恨风波，拼此事、人间天上。", "野麋丰草，江鸥远水，老去惟便疏放。", "百钱端欲问君平，早晚具、归田小舫。"]'),
('song-ci-669','鹊桥仙','黄庭坚','宋','宋词','song-ci','鹊桥仙','[]','朱楼彩舫，浮瓜沈李，报答风光有处。',68,'宋词/ci.song.2000.json','["朱楼彩舫，浮瓜沈李，报答风光有处。", "一年尊酒暂时同，别泪作、人间晓雨。", "鸳鸯机综，能令侬巧，也待乘槎仙去。", "若逢海上白头翁，共一访、痴牛呆女。"]'),
('song-ci-670','阮郎归','黄庭坚','宋','宋词','song-ci','阮郎归','[]','黔中桃李可寻芳。',56,'宋词/ci.song.2000.json','["黔中桃李可寻芳。", "摘茶人自忙。", "月团犀胯斗圆方。", "研膏入焙香。", "青箬裹，绛纱囊。", "品高闻外江。", "酒阑传碗舞红裳。", "都濡春味长。"]'),
('song-ci-671','阮郎归','黄庭坚','宋','宋词','song-ci','阮郎归','[]','烹茶留客驻金鞍。',56,'宋词/ci.song.2000.json','["烹茶留客驻金鞍。", "月斜窗外山。", "别郎容易见郎难。", "有人思远山。", "归去后，忆前欢。", "画屏金博山。", "一杯春露莫留残。", "与郎扶玉山。"]'),
('song-ci-672','更漏子','黄庭坚','宋','宋词','song-ci','更漏子','[]','庵摩勒，西土果。',58,'宋词/ci.song.2000.json','["庵摩勒，西土果。", "霜后明珠颗颗。", "凭玉兔，捣香尘。", "称为席上珍。", "号馀甘，争奈苦。", "临上马时分付。", "管回味，却思量。", "忠言君拭尝。"]'),
('song-ci-673','绣带子・好女儿','黄庭坚','宋','宋词','song-ci','绣带子・好女儿','[]','小院一枝梅。',55,'宋词/ci.song.2000.json','["小院一枝梅。", "冲破晓寒开。", "晚到芳园游戏，满袖带香回。", "玉酒覆银杯。", "尽醉去、犹待重来。", "东邻何事，惊吹怨笛，雪片成堆。"]'),
('song-ci-674','撼庭竹','黄庭坚','宋','宋词','song-ci','撼庭竹','[]','呜咽南楼吹落梅。',84,'宋词/ci.song.2000.json','["呜咽南楼吹落梅。", "闻鸦树惊栖。", "梦中相见不多时。", "隔城今夜也应知。", "坐久水空碧，山月影沈西。", "买个宅儿住著伊。", "刚不肯相随。", "如今果被天嗔作，永落鸡群被鸡欺。", "空恁可怜伊。", "风日损花枝。"]'),
('song-ci-675','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','馀寒争令。',52,'宋词/ci.song.2000.json','["馀寒争令。", "雪共蜡梅相照影。", "昨夜东风。", "已出耕牛劝岁功。", "阴云幂幂。", "近觉去天无几尺。", "休恨春迟。", "桃李梢头次第知。"]'),
('song-ci-676','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','使君那里。',52,'宋词/ci.song.2000.json','["使君那里。", "千骑尘中依约是。", "拂我眉头。", "无处重寻庾信愁。", "山云弥漫。", "夹道旌旗联复断。", "万事茫茫。", "分付澄波与烂肠。"]'),
('song-ci-677','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','襄王梦里。',52,'宋词/ci.song.2000.json','["襄王梦里。", "草绿烟深何处是。", "宋玉台头。", "暮雨朝云几许愁。", "飞花漫漫。", "不管羁人肠欲断。", "春水茫茫。", "欲度南陵更断肠。"]'),
('song-ci-678','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','巫山古县。',52,'宋词/ci.song.2000.json','["巫山古县。", "老杜淹留情始见。", "拨闷题诗。", "千古神交世不知。", "云阳台下。", "更值清明风雨夜。", "知道愁辛。", "果是当时作赋人。"]'),
('song-ci-679','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','诗翁才刃。',52,'宋词/ci.song.2000.json','["诗翁才刃。", "曾陷文场貔虎阵。", "谁敢当哉。", "况是焚舟决胜来。", "三巴春杪。", "客馆梦回风雨晓。", "胸次峥嵘。", "欲共涛头赤甲平。"]'),
('song-ci-680','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','苍崖万仞。',52,'宋词/ci.song.2000.json','["苍崖万仞。", "下有奔雷千百阵。", "自古危哉。", "谁遣西园漝麽来。", "猿啼云杪。", "破梦一声巫峡晓。", "苦唤愁生。", "不是西园作麽平。"]'),
('song-ci-681','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','终宵忘寐。',52,'宋词/ci.song.2000.json','["终宵忘寐。", "好事如何犹尚未。", "子细沈吟。", "珠泪盈盈湿袖襟。", "与君别也。", "愿在郎心莫暂舍。", "记取盟言。", "闻早回程却再圆。"]'),
('song-ci-682','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','中秋多雨。',52,'宋词/ci.song.2000.json','["中秋多雨。", "常是尊罍狼藉去。", "今夜云开。", "须道姮娥得得来。", "不知云外。", "还有清光同此会。", "笛在层楼。", "声彻摩围顶上头。"]'),
('song-ci-683','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','中秋无雨。',52,'宋词/ci.song.2000.json','["中秋无雨。", "醉送月衔西岭去。", "笑口须开。", "几度中秋见月来。", "前年江外。", "儿女传杯兄弟会。", "此夜登楼。", "小谢清吟慰白头。"]'),
('song-ci-684','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','浓云骤雨。',52,'宋词/ci.song.2000.json','["浓云骤雨。", "巫峡有情来又去。", "今夜天开。", "不与姮娥作伴来。", "清光无外。", "白发老人心自会。", "何处歌楼。", "贪看冰轮不转头。"]'),
('song-ci-685','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','举头无语。',52,'宋词/ci.song.2000.json','["举头无语。", "家在月明生处住。", "拟上摩围。", "最上峰头试望之。", "偏怜络秀。", "苦淡同甘谁更有。", "想见牵衣。", "月到愁边总不知。"]'),
('song-ci-686','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','月中笑语。',52,'宋词/ci.song.2000.json','["月中笑语。", "万里同依光景住。", "天水相围。", "相见无因梦见之。", "诸儿娟秀。", "儒学传家渠自有。", "自作秋衣。", "渐老先寒人未知。"]'),
('song-ci-687','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','当年夜雨。',52,'宋词/ci.song.2000.json','["当年夜雨。", "头白相依无去住。", "儿女成围。", "欢笑尊前月照之。", "阿连高秀。", "千万里来忠孝有。", "岂谓无衣。", "岁晚先寒要弟知。"]'),
('song-ci-688','木兰花令','黄庭坚','宋','宋词','song-ci','木兰花令','[]','风开水面鱼纹皱。',64,'宋词/ci.song.2000.json','["风开水面鱼纹皱。", "暖入草心犀点透。", "乍看晴日弄柔条，忆得章台人姓柳。", "心情老大痴成就。", "不复淋漓沾翠袖。", "早梅献笑尚窥邻，小蜜窃香如遗寿。"]'),
('song-ci-689','木兰花令','黄庭坚','宋','宋词','song-ci','木兰花令','[]','东君未试雷霆手。',64,'宋词/ci.song.2000.json','["东君未试雷霆手。", "洒雪开春春锁透。", "帝台应点万年枝，穷巷偏欺三径柳。", "峰排群玉森相就。", "中有摩围为领袖。", "凝香窗下与谁看，一曲琵琶千万寿。"]'),
('song-ci-690','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','新年何许春光漏。',64,'宋词/ci.song.2000.json','["新年何许春光漏。", "小院闭门风日透。", "酥花入坐颇欺梅，雪絮因风全是柳。", "使君落笔春词就。", "应唤歌檀催舞袖。", "得开眉处且开眉，人世可能金石寿。"]'),
('song-ci-691','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','黄金捍拨春风手。',64,'宋词/ci.song.2000.json','["黄金捍拨春风手。", "帘幕重重音韵透。", "梅花破萼便回春，似有黄鹂鸣翠柳。", "晓妆未惬梅添就。", "玉笋捧杯离钿袖。", "会拼千日笑尊前，他日相思空损寿。"]'),
('song-ci-692','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','黔中士女游晴昼。',64,'宋词/ci.song.2000.json','["黔中士女游晴昼。", "花信轻寒罗袖透。", "争寻穿石道宜男，更买江鱼双贯柳。", "竹枝歌好移船就。", "依倚风光垂翠袖。", "满倾芦酒指摩围，相守与郎如许寿。"]'),
('song-ci-693','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','可怜翡翠随鸡走。',64,'宋词/ci.song.2000.json','["可怜翡翠随鸡走。", "学绾双鬟年纪小。", "见来行待恶怜伊，心性娇痴空解笑。", "红蕖照映霜林表。", "杨柳舞风腰袅袅。", "衾馀枕剩尽相容，只是老人难再少。"]'),
('song-ci-694','清平乐','黄庭坚','宋','宋词','song-ci','清平乐','[]','春归何处。',54,'宋词/ci.song.2000.json','["春归何处。", "寂寞无行路。", "若有人知春去处。", "唤取归来同住。", "春无踪迹谁知。", "除非问取黄鹂。", "百啭无人能解，因风飞过蔷薇。"]'),
('song-ci-695','清平乐','黄庭坚','宋','宋词','song-ci','清平乐','[]','黄花当户。',54,'宋词/ci.song.2000.json','["黄花当户。", "已觉秋容暮。", "云梦南州逢笑语。", "心在歌边舞处。", "使君一笑眉开。", "新晴照酒尊来。", "且乐尊前见在，休思走马章台。"]'),
('song-ci-696','清平乐','黄庭坚','宋','宋词','song-ci','清平乐','[]','休推小户。',54,'宋词/ci.song.2000.json','["休推小户。", "看即风光暮。", "萸粉菊英浮碗醑。", "报答风光有处。", "几回笑口能开。", "少年不肯重来。", "借问牛山戏马，今为谁姓池台。"]'),
('song-ci-697','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','舞鬟娟好。',54,'宋词/ci.song.2000.json','["舞鬟娟好。", "白发黄花帽。", "醉任旁观嘲潦倒。", "扶老偏宜年小。", "舞回脸玉胸酥。", "缠头一斛明珠。", "日日梁州薄媚，年年金菊茱萸。"]'),
('song-ci-698','减字木兰花','黄庭坚','宋','宋词','song-ci','减字木兰花','[]','乍晴秋好。',54,'宋词/ci.song.2000.json','["乍晴秋好。", "黄菊敧乌帽。", "不见清谈人绝倒。", "更忆添丁小小。", "蜀娘漫点花酥。", "酒槽空滴真珠。", "兄弟四人别住，他年同插茱萸。"]'),
('song-ci-699','清平乐','黄庭坚','宋','宋词','song-ci','清平乐','[]','冰堂酒好。',54,'宋词/ci.song.2000.json','["冰堂酒好。", "只恨银杯小。", "新作金荷工献巧。", "图要连台拗倒。", "采莲一曲清歌。", "急檀催卷金河。", "醉里香飘睡鸭，更惊罗袜凌波。"]'),
('song-ci-700','忆帝京','黄庭坚','宋','宋词','song-ci','忆帝京','[]','薄妆小靥闲情素。',87,'宋词/ci.song.2000.json','["薄妆小靥闲情素。", "抱著琵琶凝伫。", "慢拈复轻拢，切切如私语。", "转拨割朱弦，一段惊沙去。", "万里嫁、乌孙公主。", "对易水、明妃不渡。", "泪粉行行，红颜片片，指下花落狂风雨。", "借问本师谁，敛拨当心住。"]'),
('song-ci-701','忆帝京','黄庭坚','宋','宋词','song-ci','忆帝京','[]','银烛生花如红豆。',96,'宋词/ci.song.2000.json','["银烛生花如红豆。", "占好事、而今有。", "人醉曲屏深，借宝瑟、轻招手。", "一阵白苹风，故灭烛、教相就。", "花带雨、冰肌香透。", "恨啼乌、辘轳声晓。", "岸柳微凉吹残酒。", "断肠时、至今依旧。", "镜中消瘦。", "那人知后。", "怕夯你来僝僽。"]'),
('song-ci-702','画堂春','黄庭坚','宋','宋词','song-ci','画堂春','[]','东堂西畔有池塘。',57,'宋词/ci.song.2000.json','["东堂西畔有池塘。", "使君棐几明窗。", "日西人吏散东廊。", "蒲苇送清凉。", "翠管细通岩溜，小峰重叠山光。", "近池催置琵琶床。", "衣带水风香。"]'),
('song-ci-703','画堂春','黄庭坚','宋','宋词','song-ci','画堂春','[]','摩围小隐枕蛮江。',57,'宋词/ci.song.2000.json','["摩围小隐枕蛮江。", "蛛丝闲锁晴窗。", "水风山影上修廊。", "不到晚来凉。", "相伴蝶穿花径，独飞鸥舞春光。", "不因送客下绳床。", "添火炷炉香。"]'),
('song-ci-704','鹧鸪天','黄庭坚','宋','宋词','song-ci','鹧鸪天','[]','万事令人心骨寒。',64,'宋词/ci.song.2000.json','["万事令人心骨寒。", "故人坟上土新乾。", "淫坊酒肆狂居士，李下何妨也整冠。", "金作鼎，玉为餐。", "老来亦失少时欢。", "茱萸菊蕊年年事，十日还将九日看。"]'),
('song-ci-705','鹧鸪天','黄庭坚','宋','宋词','song-ci','鹧鸪天','[]','黄菊枝头生晓寒。',64,'宋词/ci.song.2000.json','["黄菊枝头生晓寒。", "人生莫放酒杯乾。", "风前横笛斜吹雨，醉里簪花倒著冠。", "身健在，且加餐。", "舞裙歌板尽清欢。", "黄花白发相牵挽，付与时人洗眼看。"]'),
('song-ci-706','鹧鸪天','黄庭坚','宋','宋词','song-ci','鹧鸪天','[]','紫菊黄花风露寒。',64,'宋词/ci.song.2000.json','["紫菊黄花风露寒。", "平沙戏马雨新乾。", "且看欲尽花经眼，休说弹冠与挂冠。", "甘酒病，废朝餐。", "何人得似醉中欢。", "十年一觉扬州梦，为报时人洗眼看。"]'),
('song-ci-707','鹧鸪天','黄庭坚','宋','宋词','song-ci','鹧鸪天','[]','西塞山边白鹭飞。',64,'宋词/ci.song.2000.json','["西塞山边白鹭飞。", "桃花流水鳜鱼肥。", "朝廷尚觅玄真子，何处如今更有诗。", "青箬笠，绿蓑衣。", "斜风细雨不须归。", "人间底是无波处，一日风波十二时。"]'),
('song-ci-708','醉落魄・一斛珠','黄庭坚','宋','宋词','song-ci','醉落魄・一斛珠','[]','陶陶兀兀。',67,'宋词/ci.song.2000.json','["陶陶兀兀。", "尊前是我华胥国。", "争名争利休休莫。", "雪月风花，不醉怎生得。", "邯郸一枕谁忧乐。", "新诗新事因闲适。", "东山小妓携丝竹。", "家里乐天，村里谢安石。"]'),
('song-ci-709','醉落魄・一斛珠','黄庭坚','宋','宋词','song-ci','醉落魄・一斛珠','[]','陶陶兀兀。',67,'宋词/ci.song.2000.json','["陶陶兀兀。", "人生无累何由得。", "杯中三万六千日。", "闷损旁观，自我解落魄。", "扶头不起还颓玉。", "日高春睡平生足。", "谁门可款新篘熟。", "安乐春泉，玉醴荔枝绿。"]'),
('song-ci-710','醉落魄・一斛珠','黄庭坚','宋','宋词','song-ci','醉落魄・一斛珠','[]','陶陶兀兀。',67,'宋词/ci.song.2000.json','["陶陶兀兀。", "人生梦里槐安国。", "教公休醉公但莫。", "盏倒垂莲，一笑是赢得。", "街头酒贱民声乐。", "寻常行处寻欢适。", "醉看檐雨森银竹。", "我欲忧民，渠有二千石。"]'),
('song-ci-711','醉落魄・一斛珠','黄庭坚','宋','宋词','song-ci','醉落魄・一斛珠','[]','陶陶兀兀。',67,'宋词/ci.song.2000.json','["陶陶兀兀。", "醉乡路远归不得。", "心情那似当年日。", "割爱金河，一碗淡莫托。", "异乡薪桂炊苍玉。", "摩挲经笥须知足。", "明年细麦能黄熟。", "不管轻霜，点尽鬓边绿。"]'),
('song-ci-712','南乡子','黄庭坚','宋','宋词','song-ci','南乡子','[]','招唤欲千回。',66,'宋词/ci.song.2000.json','["招唤欲千回。", "暂得尊前笑口开。", "万水千山还麽去，悠哉。", "酒面黄花欲醉谁。", "顾影又徘徊。", "立到斜风细雨吹。", "见我未衰容易去，还来。", "不道年年即渐衰。"]'),
('song-ci-713','南乡子','黄庭坚','宋','宋词','song-ci','南乡子','[]','未报贾船回。',66,'宋词/ci.song.2000.json','["未报贾船回。", "三径荒锄菊卧开。", "想得邻船霜笛罢，沾衣。", "不为涪翁更为谁。", "风力袅萸枝。", "酒面红鳞惬细吹。", "莫笑插花和事老，摧颓。", "却向人间耐盛衰。"]'),
('song-ci-714','南乡子','黄庭坚','宋','宋词','song-ci','南乡子','[]','黄菊满东篱。',66,'宋词/ci.song.2000.json','["黄菊满东篱。", "与客携壶上翠微。", "已是有花兼有酒，良期。", "不用登临恨落晖。", "满酌不须辞。", "莫待无花空折枝。", "寂寞酒醒人散后，堪悲。", "节去蜂愁蝶不知。"]'),
('song-ci-715','南乡子','黄庭坚','宋','宋词','song-ci','南乡子','[]','卧稻雨馀收。',66,'宋词/ci.song.2000.json','["卧稻雨馀收。", "处处游人簇远洲。", "白发又扶红袖醉，戎州。", "乱折黄花插满头。", "青眼想风流。", "画出西楼一帧秋。", "还把去年欢意舞，梁洲。", "塞雁西来特地愁。"]'),
('song-ci-716','点绛唇','黄庭坚','宋','宋词','song-ci','点绛唇','[]','浊酒黄花，画檐十日无秋燕。',50,'宋词/ci.song.2000.json','["浊酒黄花，画檐十日无秋燕。", "梦中相见。", "起作南柯观。", "镜里朱颜，又减年时半。", "江山远。", "登高人健。", "应问西来雁。"]'),
('song-ci-717','谒金门','黄庭坚','宋','宋词','song-ci','谒金门','[]','山又水。',53,'宋词/ci.song.2000.json','["山又水。", "行尽吴头楚尾。", "兄弟灯前家万里。", "相看如梦寐。", "君似成蹊桃李。", "入我草堂松桂。", "莫厌岁寒无气味。", "馀生今已矣。"]'),
('song-ci-718','采桑子','黄庭坚','宋','宋词','song-ci','采桑子','[]','宗盟有妓能歌舞，宜醉尊罍。',52,'宋词/ci.song.2000.json','["宗盟有妓能歌舞，宜醉尊罍。", "待约新醅。", "车上危坡尽要推。", "西邻三弄争秋月，邀勒春回。", "个里声催。", "铁树枝头花也开。"]'),
('song-ci-719','采桑子','黄庭坚','宋','宋词','song-ci','采桑子','[]','荔枝滩上留千骑，桃李阴繁。',52,'宋词/ci.song.2000.json','["荔枝滩上留千骑，桃李阴繁。", "燕寝香残。", "画戟森森镇八蛮。", "永康又得风流守，管领江山。", "少讼多闲。", "烟霭楼台舞翠鬟。"]'),
('song-ci-720','采桑子','黄庭坚','宋','宋词','song-ci','采桑子','[]','马湖来舞钗初赐，笳鼓声繁。',52,'宋词/ci.song.2000.json','["马湖来舞钗初赐，笳鼓声繁。", "贤将开关。", "威竦西山八诏蛮。", "南溪地逐名贤重，深锁群山。", "燕喜公闲。", "一斛明珠两小鬟。"]'),
('song-ci-721','西江月','黄庭坚','宋','宋词','song-ci','西江月','[]','龙焙头纲春早，谷帘第一泉香。',58,'宋词/ci.song.2000.json','["龙焙头纲春早，谷帘第一泉香。", "已醺浮蚁嫩鹅黄。", "想见翻成雪浪。", "兔褐金丝宝碗，松风蟹眼新汤。", "无因更发次公狂。", "甘露来从仙掌。"]'),
('song-ci-722','鹧鸪天','黄庭坚','宋','宋词','song-ci','鹧鸪天','[]','汤泛冰瓷一坐春。',64,'宋词/ci.song.2000.json','["汤泛冰瓷一坐春。", "长松林下得灵根。", "吉祥老子亲拈出，个个教成百岁人。", "灯焰焰，酒醺醺。", "壑源曾未醒酲魂。", "与君更把长生碗，聊为清歌驻白云。"]'),
('song-ci-723','渔家傲','黄庭坚','宋','宋词','song-ci','渔家傲','[]','万水千山来此土。',72,'宋词/ci.song.2000.json','["万水千山来此土。", "本提心印传梁武。", "对朕者谁浑不顾。", "成死语。", "江头暗折长芦渡。", "面壁九年看二祖。", "一花五叶亲分付。", "只履提归葱岭去。", "君知否。", "分明忘却来时路。"]'),
('song-ci-724','渔家傲','黄庭坚','宋','宋词','song-ci','渔家傲','[]','三十年来无孔窍。',72,'宋词/ci.song.2000.json','["三十年来无孔窍。", "几回得眼还迷照。", "一见桃花参学了。", "呈法要。", "无弦琴上单于调。", "摘叶寻枝虚半老。", "拈花特地重年少。", "今后水云人欲晓。", "非玄妙。", "灵云合破桃花笑。"]'),
('song-ci-725','渔家傲','黄庭坚','宋','宋词','song-ci','渔家傲','[]','忆昔药山生一虎。',72,'宋词/ci.song.2000.json','["忆昔药山生一虎。", "华亭船上寻人渡。", "散却夹山拈坐具。", "呈见处。", "繁驴橛上合头语。", "千户垂丝君看取。", "离钩三寸无生路。", "蓦口一桡亲子父，犹回顾。", "瞎驴丧我儿孙去。"]'),
('song-ci-726','渔家傲','黄庭坚','宋','宋词','song-ci','渔家傲','[]','百丈峰头开古镜。',72,'宋词/ci.song.2000.json','["百丈峰头开古镜。", "马驹踏杀重苏醒。", "接得古灵心眼净。", "光炯炯。", "归来藏在袈裟影。", "好个佛堂佛不圣。", "祖师沈醉犹看镜。", "却与斩新提祖令。", "方猛省。", "无声三昧天皇饼。"]'),
('song-ci-727','渔家傲','黄庭坚','宋','宋词','song-ci','渔家傲','[]','踏破草鞋参到了。',72,'宋词/ci.song.2000.json','["踏破草鞋参到了。", "等闲拾得衣中宝。", "遇酒逢花须一笑。", "长年少。", "俗人不用嗔贫道。", "何处青旗夸酒好。", "醉乡路上多芳草。", "提著葫芦行未到。", "风落帽。", "葫芦却缠葫芦倒。"]'),
('song-ci-728','拨棹子','黄庭坚','宋','宋词','song-ci','拨棹子','[]','归去来。',76,'宋词/ci.song.2000.json','["归去来。", "归去来。", "携手旧山归去来。", "有人共、月对尊罍。", "横一琴，甚处不逍遥自在。", "闲世界。", "无利害。", "何必向、世间甘幻爱。", "与君钓、晚烟寒濑。", "蒸白鱼稻饭，溪童供笋菜。"]'),
('song-ci-729','诉衷情','黄庭坚','宋','宋词','song-ci','诉衷情','[]','一波才动万波随。',54,'宋词/ci.song.2000.json','["一波才动万波随。", "蓑笠一钩丝。", "锦鳞正在深处，千尺也须垂。", "吞又吐，信还疑。", "上钩迟。", "水寒江静，满目青山，载月明归。"]'),
('song-ci-730','浣溪沙','黄庭坚','宋','宋词','song-ci','浣溪沙','[]','新妇滩头眉黛愁。',48,'宋词/ci.song.2000.json','["新妇滩头眉黛愁。", "女儿浦口眼波秋。", "惊鱼错认月沈钩。", "青箬笠前无限事，绿蓑衣底一时休。", "斜风吹雨转船头。"]'),
('song-ci-731','菩萨蛮','黄庭坚','宋','宋词','song-ci','菩萨蛮','[]','半烟半雨溪桥畔。',52,'宋词/ci.song.2000.json','["半烟半雨溪桥畔。", "渔翁醉著无人唤。", "疏懒意何长。", "春风花草香。", "江山如有待。", "此意陶潜解。", "问我去何之。", "君行到自知。"]'),
('song-ci-732','调笑歌・调笑令','黄庭坚','宋','宋词','song-ci','调笑歌・调笑令','[]','无语。',45,'宋词/ci.song.2000.json','["无语。", "恨如许。", "方士归时肠断处。", "梨花一枝春带雨。", "半钿分钗亲付。", "天长地久相思苦。", "渺渺鲸波无路。"]'),
('song-ci-733','步蟾宫','黄庭坚','宋','宋词','song-ci','步蟾宫','[]','虫儿真个忒灵利。',74,'宋词/ci.song.2000.json','["虫儿真个忒灵利。", "恼乱得、道人眼起。", "醉归来、恰似出桃源，但目送、落花流水。", "何妨随我归云际。", "共作个、住山活计。", "照清溪，匀粉面，插山花，也须胜、风尘气味。"]'),
('song-ci-734','南柯子・南歌子','黄庭坚','宋','宋词','song-ci','南柯子・南歌子','[]','郭泰曾名我，刘翁复见谁。',62,'宋词/ci.song.2000.json','["郭泰曾名我，刘翁复见谁。", "入廛还作和罗槌。", "特地干戈相待、使人疑。", "秋浦横波眼，春窗远岫眉。", "补陀岩畔夕阳迟。", "何似金沙滩上、放憨时。"]'),
('song-ci-735','南柯子・南歌子','黄庭坚','宋','宋词','song-ci','南柯子・南歌子','[]','万里沧江月，波清说向谁。',62,'宋词/ci.song.2000.json','["万里沧江月，波清说向谁。", "顶门须更下金槌。", "只恐风惊草动、又生疑。", "金雁斜妆颊，青螺浅画眉。", "庖丁有底下刀迟。", "直要人牛无际、是休时。"]'),
('song-ci-736','丑奴儿・采桑子','黄庭坚','宋','宋词','song-ci','丑奴儿・采桑子','[]','夜来酒醒清无梦，愁倚阑干。',52,'宋词/ci.song.2000.json','["夜来酒醒清无梦，愁倚阑干。", "露滴轻寒。", "雨打芙蓉泪不乾。", "佳人别后音尘悄，消瘦难拼。", "明月无端。", "已过红楼十二间。"]'),
('song-ci-737','西江月','黄庭坚','宋','宋词','song-ci','西江月','[]','断送一生惟有，破除万事无过。',58,'宋词/ci.song.2000.json','["断送一生惟有，破除万事无过。", "远山横黛蘸秋波。", "不饮旁人笑我。", "花病等闲瘦弱，春愁没处遮拦。", "杯行到手莫留残。", "不道月斜人散。"]'),
('song-ci-738','画堂春','黄庭坚','宋','宋词','song-ci','画堂春','[]','东风吹柳日初长。',55,'宋词/ci.song.2000.json','["东风吹柳日初长。", "雨馀芳草斜阳。", "杏花零乱燕泥香。", "睡损红妆。", "宝篆烟消龙凤，画屏云锁潇湘。", "夜寒微透薄罗裳。", "无限思量。"]'),
('song-ci-739','虞美人','黄庭坚','宋','宋词','song-ci','虞美人','[]','平王本爱江湖住。',66,'宋词/ci.song.2000.json','["平王本爱江湖住。", "鸥鹭无人处。", "江南江北水云连。", "莫笑醯鸡歌舞、瓮中天。", "当涂舣棹蒹葭外。", "赖有宾朋在。", "此身无路入修门。", "惭愧诗翁清些、与招魂。"]'),
('song-ci-740','虞美人','黄庭坚','宋','宋词','song-ci','虞美人','[]','天涯也有江南信。',66,'宋词/ci.song.2000.json','["天涯也有江南信。", "梅破知春近。", "夜阑风细得香迟。", "不道晓来开遍、向南枝。", "玉台弄粉花应妒。", "飘到眉心住。", "平生个里愿杯深。", "去国十年老尽、少年心。"]'),
('song-ci-741','两同心','黄庭坚','宋','宋词','song-ci','两同心','[]','巧笑眉颦。',86,'宋词/ci.song.2000.json','["巧笑眉颦。", "行步精神。", "隐隐似、朝云行雨，弓弓样、罗袜生尘。", "尊前见，玉槛雕笼，堪爱难亲。", "自言家住天津。", "生小从人。", "恐舞罢、随风飞去，顾阿母、教窣珠裙。", "从今去，唯愿银缸，莫照离尊。"]'),
('song-ci-742','两同心','黄庭坚','宋','宋词','song-ci','两同心','[]','一笑千金。',86,'宋词/ci.song.2000.json','["一笑千金。", "越样情深。", "曾共结、合欢罗带，终愿效、比翼纹禽。", "许多时，灵利惺惺，蓦地昏沈。", "自从官不容针。", "直至而今。", "你共人、女边著子，争知我、门里挑心。", "记携手，小院回廊，月影花阴。"]'),
('song-ci-743','两同心','黄庭坚','宋','宋词','song-ci','两同心','[]','秋水遥岑。',86,'宋词/ci.song.2000.json','["秋水遥岑。", "妆淡情深。", "尽道教、心坚穿石，更说甚、官不容针。", "霎时间，雨散云归，无处追寻。", "小楼朱阁沈沈。", "一笑千金。", "你共人、女边著子，争知我、门里挑心。", "最难忘，小院回廊，月影花阴。"]'),
('song-ci-744','满庭芳','黄庭坚','宋','宋词','song-ci','满庭芳','[]','北苑龙团，江南鹰爪，万里名动京关。',118,'宋词/ci.song.2000.json','["北苑龙团，江南鹰爪，万里名动京关。", "碾深罗细，琼蕊暖生烟，一种风流气味，如甘露、不染尘凡。", "纤纤捧，冰瓷莹玉，金缕鹧鸪斑。", "相如，方病酒，银瓶蟹眼，波怒涛翻。", "为扶起，尊前醉玉颓山。", "饮罢风生两腋，醒魂到、明月轮边。", "归来晚，文君未寝，相对小窗前。"]'),
('song-ci-745','满庭芳','黄庭坚','宋','宋词','song-ci','满庭芳','[]','明眼空青，忘忧萱草，翠玉闲淡疏妆。',118,'宋词/ci.song.2000.json','["明眼空青，忘忧萱草，翠玉闲淡疏妆。", "小来歌舞，长是倚风光。", "我已逍遥物外，人冤道、别有思量。", "难忘处，良辰美景，襟袖有馀香。", "鸳鸯。", "头白早，多情易感，红蓼池塘。", "又须得，尊前席上成双。", "些子风流罪过，都说与、明月空床。", "难拘管，朝云暮雨，分付楚襄王。"]'),
('song-ci-746','满庭芳','黄庭坚','宋','宋词','song-ci','满庭芳','[]','修水浓青，新条淡绿，翠光交映虚亭。',118,'宋词/ci.song.2000.json','["修水浓青，新条淡绿，翠光交映虚亭。", "锦鸳霜鹭，荷径拾幽苹。", "香渡栏干屈曲，红妆映、薄绮疏櫺。", "风清夜，横塘月满，水净见移星。", "堪听。", "微雨过，媻姗藻荇，琐碎浮萍。", "便移转，胡床湘簟方屏。", "练霭鳞云旋满，声不断、檐响风铃。", "重开宴，瑶池雪沁，山露佛头青。"]'),
('song-ci-747','蓦山溪','黄庭坚','宋','宋词','song-ci','蓦山溪','[]','山围江暮。',102,'宋词/ci.song.2000.json','["山围江暮。", "天镜开晴絮。", "斜影过梨花，照文星、老人星聚。", "清樽一笑，欢甚却成愁，别时襟，馀点点，疑是高唐雨。", "无人知处。", "梦里云归路。", "回雁晓风清，雁不来、啼鸦无数。", "心情老懒，尤物解宜人，春尽也，有南风，好便回帆去。"]'),
('song-ci-748','蓦山溪','黄庭坚','宋','宋词','song-ci','蓦山溪','[]','稠花乱叶，到处撩人醉。',102,'宋词/ci.song.2000.json','["稠花乱叶，到处撩人醉。", "林下有孤芳，不匆匆、成蹊桃李。", "今年风雨，莫送断肠红，斜枝倚。", "风尘里。", "不带尘风气。", "微嗔又喜。", "约略知春味。", "江上一帆愁，梦犹寻、歌梁舞地。", "如今对酒，不似那回时，书谩写，梦来空，只有相思是。"]'),
('song-ci-749','蓦山溪','黄庭坚','宋','宋词','song-ci','蓦山溪','[]','山明水秀，尽属诗人道。',102,'宋词/ci.song.2000.json','["山明水秀，尽属诗人道。", "应是五陵儿，见衰翁、孤吟绝倒。", "一觞一咏，潇洒寄高闲，松月下，竹风间，试想为襟抱。", "玉关遥指，万里天衢杳。", "笔阵扫秋风，泻珠玑、琅琅皎皎。", "卧龙智略，三诏佐升平，烟塞事，玉堂心，频把菱花照。"]'),
('song-ci-750','阮郎归','黄庭坚','宋','宋词','song-ci','阮郎归','[]','盈盈娇女似罗敷。',56,'宋词/ci.song.2000.json','["盈盈娇女似罗敷。", "湘江明月珠。", "起来绾髻又重梳。", "弄妆仍学书。", "歌调态，舞工夫。", "湖南都不如。", "它年未厌白髭鬚。", "同舟归五湖。"]'),
('song-ci-751','阮郎归','黄庭坚','宋','宋词','song-ci','阮郎归','[]','歌停檀板舞停鸾。',56,'宋词/ci.song.2000.json','["歌停檀板舞停鸾。", "高阳饮兴阑。", "兽烟喷尽玉壶乾。", "香分小凤团。", "雪浪浅，露花圆。", "捧瓯春笋寒。", "绛纱笼下跃金鞍。", "归时人倚阑。"]'),
('song-ci-752','阮郎归','黄庭坚','宋','宋词','song-ci','阮郎归','[]','摘山初制小龙团。',56,'宋词/ci.song.2000.json','["摘山初制小龙团。", "色和香味全。", "碾声初断夜将阑。", "烹时鹤避烟。", "消滞思，解尘烦。", "金瓯雪浪翻。", "只愁啜罢水流天。", "馀清搅夜眠。"]'),
('song-ci-753','阮郎归','黄庭坚','宋','宋词','song-ci','阮郎归','[]','退红衫子乱蜂儿。',56,'宋词/ci.song.2000.json','["退红衫子乱蜂儿。", "衣宽只为伊。", "为伊去得忒多时。", "教人直是疑。", "长睡晚，理妆迟。", "愁多懒画眉。", "夜来算得有归期。", "灯花则甚知。"]'),
('song-ci-754','阮郎归','黄庭坚','宋','宋词','song-ci','阮郎归','[]','贫家春到也骚骚。',56,'宋词/ci.song.2000.json','["贫家春到也骚骚。", "琼浆注小槽。", "老夫不出长蓬蒿。", "邻墙开碧桃。", "木芍药，品题高。", "一枝烦剪刀。", "传杯犹似少年豪。", "醉红浸雪毛。"]'),
('song-ci-755','定风波','黄庭坚','宋','宋词','song-ci','定风波','[]','把酒花前欲问溪。',73,'宋词/ci.song.2000.json','["把酒花前欲问溪。", "问溪何事晚声悲。", "名利往来人尽老。", "谁道。", "溪声今古有休时。", "且共玉人斟玉醑。", "休诉。", "笙歌一曲黛眉低。", "情似长溪长不断。", "君看。", "水声东去月轮西。"]'),
('song-ci-756','定风波','黄庭坚','宋','宋词','song-ci','定风波','[]','小院难图云雨期。',73,'宋词/ci.song.2000.json','["小院难图云雨期。", "幽欢浑待赏花时。", "到得春来君却去。", "相误。", "不须言语泪双垂。", "密约尊前难嘱付。", "偷顾。", "手搓金橘敛双眉。", "庭榭清风明月媚。", "须记。", "归时莫待杏花飞。"]'),
('song-ci-757','定风波','黄庭坚','宋','宋词','song-ci','定风波','[]','上客休辞酒浅深。',73,'宋词/ci.song.2000.json','["上客休辞酒浅深。", "素儿歌里细听沈。", "粉面不须歌扇掩，闲静，一声一字总关心。", "花外黄鹂能密语。", "休诉。", "有花能得几时斟。", "画作远山临碧水。", "明媚。", "梦为胡蝶去登临。"]'),
('song-ci-758','定风波','黄庭坚','宋','宋词','song-ci','定风波','[]','歌舞阑珊退晚妆。',73,'宋词/ci.song.2000.json','["歌舞阑珊退晚妆。", "主人情重更留汤。", "冠帽斜敧辞醉去，邀定，玉人纤手自磨香。", "又得尊前聊笑语。", "如许。", "短歌宜舞小红裳。", "宝马促归朱户闭。", "人睡。", "夜来应恨月侵床。"]'),
('song-ci-759','浪淘沙','黄庭坚','宋','宋词','song-ci','浪淘沙','[]','忆昔谪巴蛮。',64,'宋词/ci.song.2000.json','["忆昔谪巴蛮。", "荔子亲攀。", "冰肌照映柘枝冠。", "日擘轻红三百颗，一味甘寒。", "重入鬼门关。", "也似人间。", "一双和叶插云鬟。", "赖得清湘燕玉面，同倚阑干。"]'),
('song-ci-760','看花回','黄庭坚','宋','宋词','song-ci','看花回','[]','夜永兰堂醺饮，半倚颓玉。',123,'宋词/ci.song.2000.json','["夜永兰堂醺饮，半倚颓玉。", "烂熳坠钿堕履，是醉时风景，花暗烛残，欢意未阑，舞燕歌珠成断续。", "催茗饮、旋煮寒泉，露井瓶窦响飞瀑。", "纤指缓、连环动触。", "渐泛起、满瓯银粟。", "香引春风在手，似粤岭闽溪，初采盈掬。", "暗想当时，探春连云询篁竹。", "怎归得，鬓将老，付与杯中绿。"]'),
('song-ci-761','惜馀欢・惜余欢','黄庭坚','宋','宋词','song-ci','惜馀欢・惜余欢','[]','四时美景，正年少赏心，频启东阁。',126,'宋词/ci.song.2000.json','["四时美景，正年少赏心，频启东阁。", "芳酒载盈车，喜朋侣簪合。", "杯觞交飞劝酬献，正酣饮、醉主公陈榻。", "坐来争奈，玉山未颓，兴寻巫峡。", "歌阑旋烧绛蜡。", "况漏转铜壶，烟断香鸭。", "犹整醉中花，借纤手重插。", "相将扶上，金鞍騕袅，碾春焙、愿少延欢洽。", "未须归去，重寻艳歌，更留时霎。"]'),
('song-ci-762','醉落魄・一斛珠','黄庭坚','宋','宋词','song-ci','醉落魄・一斛珠','[]','苍颜华发。',67,'宋词/ci.song.2000.json','["苍颜华发。", "故山归计无因得。", "旧交新贵音书绝。", "惟有家人，犹作殷勤别。", "离亭欲去歌声咽。", "潇潇细雨凉生颊。", "泪珠不用罗巾裛。", "弹在罗衫，图得见时说。"]'),
('song-ci-763','西江月','黄庭坚','宋','宋词','song-ci','西江月','[]','月侧金盆堕水，雁回醉墨书空。',58,'宋词/ci.song.2000.json','["月侧金盆堕水，雁回醉墨书空。", "君诗秀色雨园葱。", "想见衲衣寒拥。", "蚁穴梦魂人世，杨花踪迹风中。", "莫将社燕等秋鸿。", "处处春山翠重。"]'),
('song-ci-764','西江月','黄庭坚','宋','宋词','song-ci','西江月','[]','宋玉短墙东畔，桃源落日西斜。',58,'宋词/ci.song.2000.json','["宋玉短墙东畔，桃源落日西斜。", "浓妆下著绣帘遮。", "鼓笛相催清夜。", "转眄惊翻长袖，低徊细踏红靴。", "舞馀犹颤满头花。", "娇学男儿拜谢。"]'),
('song-ci-765','木兰花令','黄庭坚','宋','宋词','song-ci','木兰花令','[]','凌歊台上青青麦。',64,'宋词/ci.song.2000.json','["凌歊台上青青麦。", "姑熟堂前馀翰墨。", "暂分一印管江山，稍为诸公分皂白。", "江山依旧云空碧。", "昨日主人今日客。", "谁分宾主强惺惺，问取矶头新妇石。"]'),
('song-ci-766','木兰花令','黄庭坚','宋','宋词','song-ci','木兰花令','[]','翰林本是神仙谪。',64,'宋词/ci.song.2000.json','["翰林本是神仙谪。", "落帽风流倾座席。", "坐中还有赏音人，能岸乌纱倾大白。", "江山依旧云横碧。", "昨日主人今日客。", "谁分宾主强惺惺，问取矶头新妇石。"]'),
('song-ci-767','木兰花令','黄庭坚','宋','宋词','song-ci','木兰花令','[]','青壶乃似壶中谪。',64,'宋词/ci.song.2000.json','["青壶乃似壶中谪。", "万象光辉森宴席。", "红尘闹处便休休，不是个中无皂白。", "歌烦舞倦朱成碧。", "春草池塘凌谢客。", "共君商略老生涯，归种玉田秧白石。"]'),
('song-ci-768','木兰花令','黄庭坚','宋','宋词','song-ci','木兰花令','[]','庾郎三九常安乐。',64,'宋词/ci.song.2000.json','["庾郎三九常安乐。", "使有万钱无处著。", "徐熙小鸭水边花，明月清风都占却。", "朱颜老尽心如昨。", "万事休休休莫莫。", "樽前见在不饶人，欧舞梅歌君更酌。"]'),
('song-ci-769','木兰花令','黄庭坚','宋','宋词','song-ci','木兰花令','[]','少年得意从军乐。',64,'宋词/ci.song.2000.json','["少年得意从军乐。", "晚岁天教闲处著。", "功名富贵久寒灰，翰墨文章新讳却。", "是非不用分今昨。", "云月孤高公也莫。", "喜欢为地醉为乡，饮客不来但自酌。"]'),
('song-ci-770','品令','黄庭坚','宋','宋词','song-ci','品令','[]','凤舞团团饼。',83,'宋词/ci.song.2000.json','["凤舞团团饼。", "恨分破、教孤令。", "金渠体净，只轮慢碾，玉尘光莹。", "汤响松风，早减了、二分酒病。", "味浓香永。", "醉乡路、成佳镜。", "恰如灯下，故人万里，归来对影。", "口不能言，心下快活自省。"]'),
('song-ci-771','醉蓬莱','黄庭坚','宋','宋词','song-ci','醉蓬莱','[]','对朝云叆叇，暮雨霏微，翠峰相倚。',120,'宋词/ci.song.2000.json','["对朝云叆叇，暮雨霏微，翠峰相倚。", "巫峡高唐，锁楚宫佳丽，蘸水朱门，半空霜戟，自一川都会。", "虏酒千杯，夷歌百转，迫人垂泪。", "人道黔南，去天尺五，望极神京，万重烟水。", "悬榻相迎，有风流千骑。", "荔脸红深，麝脐香满，醉舞裀歌袂。", "杜宇催人，声声到晓，不如归是。"]'),
('song-ci-772','江城子','黄庭坚','宋','宋词','song-ci','江城子','[]','画堂高会酒阑珊。',86,'宋词/ci.song.2000.json','["画堂高会酒阑珊。", "倚栏干。", "霎时间。", "千里关山，常恨见伊难。", "及至而今相见了，依旧似、隔关山。", "倩人传语问平安。", "省愁烦。", "泪休弹。", "哭损眼儿，不似旧时单。", "寻得石榴双叶子，凭寄与、插云鬖。"]'),
('song-ci-773','江城子','黄庭坚','宋','宋词','song-ci','江城子','[]','新来曾被眼奚搐。',86,'宋词/ci.song.2000.json','["新来曾被眼奚搐。", "不甘伏。", "怎拘束。", "似梦还真，烦乱损心曲。", "见面暂时还不见，看不足、惜不足。", "不成欢笑不成哭。", "戏人目。", "远山蹙。", "有分看伊，无分共伊宿。", "一贯一文跷十贯，千不足、万不足。"]'),
('song-ci-774','逍遥乐','黄庭坚','宋','宋词','song-ci','逍遥乐','[]','春意渐归芳草。',120,'宋词/ci.song.2000.json','["春意渐归芳草。", "故国佳人，千里信沈音杳。", "雨润烟光，晚景澄明，极目危栏斜照。", "梦当年少。", "对樽前、上客邹枚，小鬟燕赵。", "共舞雪歌尘，醉里谈笑。", "花色枝枝争好。", "鬓丝年年渐老。", "如今遇风景，空瘦损、向谁道。", "东君幸赐与，天幕翠遮红绕。", "休休，醉乡歧路，华胥蓬岛。"]'),
('song-ci-775','离亭燕・离亭宴','黄庭坚','宋','宋词','song-ci','离亭燕・离亭宴','[]','十载樽前谈笑。',84,'宋词/ci.song.2000.json','["十载樽前谈笑。", "天禄故人年少。", "可是陆沈英俊地，看即锁窗批诏。", "此处忽相逢，潦倒秃翁同调。", "西顾郎官湖渺。", "事看庾楼人小。", "短艇绝江空怅望，寄得诗来高妙。", "梦去倚君傍，胡蝶归来清晓。"]'),
('song-ci-776','归田乐引・归田乐','黄庭坚','宋','宋词','song-ci','归田乐引・归田乐','[]','暮雨濛阶砌。',84,'宋词/ci.song.2000.json','["暮雨濛阶砌。", "漏渐移、转添寂寞，点点心如碎。", "怨你又恋你。", "恨你惜你。", "毕竟教人怎生是。", "前欢算未已。", "奈向如今愁无计。", "为伊聪俊，销得人憔悴。", "这里诮睡里。", "梦里心里。", "一向无言但垂泪。"]'),
('song-ci-777','归田乐引・归田乐','黄庭坚','宋','宋词','song-ci','归田乐引・归田乐','[]','对景还销瘦。',86,'宋词/ci.song.2000.json','["对景还销瘦。", "被个人、把人调戏，我也心儿有。", "忆我又唤我，见我嗔我，天生教人怎生受。", "看承幸厮勾。", "又是尊前眉峰皱。", "是人惊怪，冤我忒撋就。", "拼了又舍了，定是这回休了，及至相逢又依旧。"]'),
('song-ci-778','归田乐令・归田乐','黄庭坚','宋','宋词','song-ci','归田乐令・归田乐','[]','引调得、甚今日心肠不恋家。',55,'宋词/ci.song.2000.json','["引调得、甚今日心肠不恋家。", "宁宁地、思量他，思量他。", "两情各自肯，甚忙咱。", "意思里、莫是赚人唦。", "噷奴真个ヵ、共人ヵ。"]'),
('song-ci-779','望远行','黄庭坚','宋','宋词','song-ci','望远行','[]','自见来，虚过却、好时好日。',89,'宋词/ci.song.2000.json','["自见来，虚过却、好时好日。", "这訑尿粘腻得处煞是律。", "据眼前言定，也有十分七八。", "冤我无心除告佛。", "管人闲底，且放我快活ヵ。", "便索些别茶祗待，又怎不遇偎花映月。", "且与一班半点，只怕你没丁香核。"]'),
('song-ci-780','鼓笛令','黄庭坚','宋','宋词','song-ci','鼓笛令','[]','酒阑命友闲为戏。',65,'宋词/ci.song.2000.json','["酒阑命友闲为戏。", "打揭儿、非常惬意。", "各自输赢只赌是。", "赏罚采、分明须记。", "小五出来无事。", "却跋翻和九底。", "若要十一花下死。", "管十三、不如十二。"]'),
('song-ci-781','鼓笛令','黄庭坚','宋','宋词','song-ci','鼓笛令','[]','宝犀未解心先透。',67,'宋词/ci.song.2000.json','["宝犀未解心先透。", "恼杀人、远山微皱。", "意淡言疏情最厚。", "枉教作、著行官柳。", "小雨勒花时候。", "抱琵琶、为谁清瘦。", "翡翠金笼思珍偶。", "忽拼与、山鸡僝僽。"]'),
('song-ci-782','鼓笛令','黄庭坚','宋','宋词','song-ci','鼓笛令','[]','见来两个宁宁地。',68,'宋词/ci.song.2000.json','["见来两个宁宁地。", "眼厮打、过如拳踢。", "恰得尝些香甜底。", "苦杀人、遭谁调戏。", "腊月望州坡上地。", "冻著你、影亸村鬼。", "你但那些一处睡。", "烧沙糖、管好滋味。"]'),
('song-ci-783','鼓笛令','黄庭坚','宋','宋词','song-ci','鼓笛令','[]','见来便觉情於我。',68,'宋词/ci.song.2000.json','["见来便觉情於我。", "厮守著、新来好过。", "人道他家有婆婆。", "与一口、管教�拍ァ�", "副靖传语木大。", "鼓儿里、且打一和。", "更有些儿得处囉。", "烧沙糖、香药添和。"]'),
('song-ci-784','好女儿','黄庭坚','宋','宋词','song-ci','好女儿','[]','春去几时还。',54,'宋词/ci.song.2000.json','["春去几时还。", "问桃李无言。", "燕子归栖风劲，梨雪乱西园。", "唯有月婵娟。", "似人人、难近如天。", "愿教清影常相见，更乞取团圆。"]'),
('song-ci-785','好女儿','黄庭坚','宋','宋词','song-ci','好女儿','[]','粉泪一行行。',55,'宋词/ci.song.2000.json','["粉泪一行行。", "啼破晓来妆。", "懒系酥胸罗带，羞见绣鸳鸯。", "拟待不思量。", "怎奈向、目下恓惶。", "假饶来后，教人见了，却去何妨。"]'),
('song-ci-786','采桑子','黄庭坚','宋','宋词','song-ci','采桑子','[]','虚堂密候参同火，梨枣枝繁。',52,'宋词/ci.song.2000.json','["虚堂密候参同火，梨枣枝繁。", "深锁三关。", "不要樊姬与小蛮。", "遥知风雨更阑夜，犹梦巫山。", "浓丽清闲。", "晓镜新梳十二鬟。"]'),
('song-ci-787','采桑子','黄庭坚','宋','宋词','song-ci','采桑子','[]','投荒万里无归路，雪点鬓繁。',52,'宋词/ci.song.2000.json','["投荒万里无归路，雪点鬓繁。", "度鬼门关。", "已拼儿童作楚蛮。", "黄云苦竹啼归去，绕荔枝山。", "蓬户身闲。", "歌板谁家教小鬟。"]'),
('song-ci-788','采桑子','黄庭坚','宋','宋词','song-ci','采桑子','[]','樱桃著子如红豆，不管春归。',52,'宋词/ci.song.2000.json','["樱桃著子如红豆，不管春归。", "闻道开时。", "蜂惹香须蝶惹衣。", "楼台灯火明珠翠，酒恋歌迷。", "醉玉东西。", "少个人人暖被携。"]'),
('song-ci-789','采桑子','黄庭坚','宋','宋词','song-ci','采桑子','[]','城南城北看桃李，依倚年华。',52,'宋词/ci.song.2000.json','["城南城北看桃李，依倚年华。", "杨柳藏鸦。", "又是无言飐落花。", "春风一面长含笑，偷顾羞遮。", "分付谁家。", "把酒花前试问他。"]'),
('song-ci-790','丑奴儿・采桑子','黄庭坚','宋','宋词','song-ci','丑奴儿・采桑子','[]','济楚好得些。',74,'宋词/ci.song.2000.json','["济楚好得些。", "憔悴损、都是因它。", "那回得句闲言语，傍人尽道，你管又还鬼那人唦。", "得过口儿嘛。", "直勾得、风了自家。", "是即好意也毒害，你还甜杀人了，怎生申报孩儿。"]'),
('song-ci-791','菩萨蛮','黄庭坚','宋','宋词','song-ci','菩萨蛮','[]','细腰宫外清明雨。',52,'宋词/ci.song.2000.json','["细腰宫外清明雨。", "云阳台上烟如缕。", "云雨暗巫山。", "流人殊未还。", "阿谁知此意。", "解遣双壶至。", "不是白头新。", "周郎旧可人。"]'),
('song-ci-792','鹧鸪天','黄庭坚','宋','宋词','song-ci','鹧鸪天','[]','塞雁初来秋影寒。',64,'宋词/ci.song.2000.json','["塞雁初来秋影寒。", "霜林风过叶声乾。", "龙山落帽千年事，我对西风犹整冠。", "兰委佩，菊堪餐。", "人情时事半悲欢。", "但将酩酊酬佳节，更把茱萸仔细看。"]'),
('song-ci-793','鹧鸪天','黄庭坚','宋','宋词','song-ci','鹧鸪天','[]','节去蜂愁蝶不知。',64,'宋词/ci.song.2000.json','["节去蜂愁蝶不知。", "晓庭环绕折残枝。", "自然今日人心别，未必秋香一夜衰。", "无闲事，即芳期。", "菊花须插满头归。", "宜将酩酊酬佳节，不用登临送落晖。"]'),
('song-ci-794','鹧鸪天','黄庭坚','宋','宋词','song-ci','鹧鸪天','[]','闻说君家有翠娥。',64,'宋词/ci.song.2000.json','["闻说君家有翠娥。", "施朱施粉总嫌多。", "背人语处藏珠履，覰得羞时整玉梭。", "拖远岫，压横波。", "何时传酒更传歌。", "为君写就黄庭了，不要山阴道士鹅。"]'),
('song-ci-795','少年心','黄庭坚','宋','宋词','song-ci','少年心','[]','对景惹起愁闷。',74,'宋词/ci.song.2000.json','["对景惹起愁闷。", "染相思、病成方寸。", "是阿谁先有意，阿谁薄幸。", "斗顿恁、少喜多嗔。", "合下休传音问。", "你有我、我无你分。", "似合欢桃核，真堪人恨。", "心儿里、有两个人人。"]'),
('song-ci-796','少年心','黄庭坚','宋','宋词','song-ci','少年心','[]','心里人人，暂不见、霎时难过。',81,'宋词/ci.song.2000.json','["心里人人，暂不见、霎时难过。", "天生你要憔悴我。", "把心头从前鬼，著手摩挲。", "抖擞了、百病销磨。", "见说那厮脾鳖热。", "大不成我便与拆破。", "待来时、鬲上与厮噷则个。", "温存著、且教推磨。"]'),
('song-ci-797','点绛唇','黄庭坚','宋','宋词','song-ci','点绛唇','[]','几日无书，举头欲问西来燕。',50,'宋词/ci.song.2000.json','["几日无书，举头欲问西来燕。", "世情梦幻。", "复作如斯观。", "自叹人生，分合常相半。", "戎虽远。", "念中相见。", "不托鱼和雁。"]'),
('song-ci-798','点绛唇','黄庭坚','宋','宋词','song-ci','点绛唇','[]','罗带双垂，妙香长恁携纤手。',50,'宋词/ci.song.2000.json','["罗带双垂，妙香长恁携纤手。", "半妆红豆。", "各自相思瘦。", "闻道伊家，终日眉儿皱。", "不能勾。", "泪珠轻溜。", "裛损揉蓝袖。"]'),
('song-ci-799','南乡子','黄庭坚','宋','宋词','song-ci','南乡子','[]','诸将说封侯。',66,'宋词/ci.song.2000.json','["诸将说封侯。", "短笛长歌独倚楼。", "万事尽随风雨去，休休。", "戏马台南金络头。", "催酒莫迟留。", "酒味今秋似去秋。", "花向老人头上笑，羞羞。", "白发簪花不解愁。"]'),
('song-ci-800','南歌子','黄庭坚','宋','宋词','song-ci','南歌子','[]','槐绿低窗暗，榴红照眼明。',62,'宋词/ci.song.2000.json','["槐绿低窗暗，榴红照眼明。", "玉人邀我少留行。", "无奈一帆烟雨、画船轻。", "柳叶随歌皱，梨花与泪倾。", "别时不似见时情。", "今夜月明江上、酒初醒。"]'),
('song-ci-801','更漏子','黄庭坚','宋','宋词','song-ci','更漏子','[]','体妖娆，鬟婀娜。',58,'宋词/ci.song.2000.json','["体妖娆，鬟婀娜。", "玉甲银筝照座。", "危柱促，曲声残。", "王孙带笑看。", "休休休，莫莫莫。", "愁拨个丝中索。", "了了了，玄玄玄。", "山僧无碗禅。"]'),
('song-ci-802','好事近','黄庭坚','宋','宋词','song-ci','好事近','[]','歌罢酒阑时，潇洒座中风色。',53,'宋词/ci.song.2000.json','["歌罢酒阑时，潇洒座中风色。", "主礼到君须尽，奈宾朋南北。", "暂时分散总寻常，难堪久离拆。", "不似建溪春草，解留连佳客。"]'),
('song-ci-803','好事近','黄庭坚','宋','宋词','song-ci','好事近','[]','一弄醒心弦，情在两山斜叠。',53,'宋词/ci.song.2000.json','["一弄醒心弦，情在两山斜叠。", "弹到古人愁处，有真珠承睫。", "使君来去本无心，休泪界红颊。", "自恨老来憎酒，负十分金叶。"]'),
('song-ci-804','好事近','黄庭坚','宋','宋词','song-ci','好事近','[]','不见片时霎，魂梦镇相随著。',53,'宋词/ci.song.2000.json','["不见片时霎，魂梦镇相随著。", "因甚近新无据，误窃香深约。", "思量模样忔憎儿，恶又怎生恶。", "终待共伊相见，与佯佯奚落。"]'),
('song-ci-805','喝火令','黄庭坚','宋','宋词','song-ci','喝火令','[]','见晚情如旧，交疏分已深。',77,'宋词/ci.song.2000.json','["见晚情如旧，交疏分已深。", "舞时歌处动人心。", "烟水数年魂梦，无处可追寻。", "昨夜灯前见，重题汉上襟。", "便愁云雨又难寻。", "晓也星稀，晓也月西沈。", "晓也雁行低度，不会寄芳音。"]'),
('song-ci-806','留春令','黄庭坚','宋','宋词','song-ci','留春令','[]','江南一雁横秋水。',66,'宋词/ci.song.2000.json','["江南一雁横秋水。", "叹咫尺、断行千里。", "回纹机上字纵横，欲寄远、凭谁是。", "谢客池塘春都未。", "微微动、短墙桃李。", "半阴才暖却清寒，是瘦损、人天气。"]'),
('song-ci-807','宴桃源・如梦令','黄庭坚','宋','宋词','song-ci','宴桃源・如梦令','[]','天气把人僝僽。',40,'宋词/ci.song.2000.json','["天气把人僝僽。", "落絮游丝时候。", "茶饭可曾忺，镜中赢得销瘦。", "生受。", "生受。", "更被养娘催绣。"]'),
('song-ci-808','雪花飞','黄庭坚','宋','宋词','song-ci','雪花飞','[]','携手青云路稳，天声迤逦传呼。',50,'宋词/ci.song.2000.json','["携手青云路稳，天声迤逦传呼。", "袍笏恩章乍赐，春满皇都。", "何处难忘酒，琼花照玉壶。", "归袅丝梢竞醉，雪舞郊衢。"]'),
('song-ci-809','下水船','黄庭坚','宋','宋词','song-ci','下水船','[]','总领神仙侣。',90,'宋词/ci.song.2000.json','["总领神仙侣。", "齐到青云歧路。", "丹禁风微，咫尺谛闻天语。", "尽荣遇。", "看即如龙变化，一掷灵梭风雨。", "真游处。", "上苑寻春去。", "芳草芊芊迎步。", "几曲笙歌，樱桃艳里欢聚。", "瑶觞举。", "回祝尧龄万万，端的君恩难负。"]'),
('song-ci-810','贺圣朝','黄庭坚','宋','宋词','song-ci','贺圣朝','[]','脱霜披茜初登第。',55,'宋词/ci.song.2000.json','["脱霜披茜初登第。", "名高得意。", "樱桃荣宴玉墀游，领群仙行缀。", "佳人何事轻相戏。", "道得之何济。", "君家声誉古无双，且均平居二。"]'),
('song-ci-811','青玉案','黄庭坚','宋','宋词','song-ci','青玉案','[]','烟中一线来时路。',80,'宋词/ci.song.2000.json','["烟中一线来时路。", "极目送、归鸿去。", "第四阳关云不度。", "山胡新啭，子规言语。", "正在人愁处。", "忧能损性休朝暮。", "忆我当年醉时句。", "渡水穿云心已许。", "暮年光景，小轩南浦。", "同卷西山雨。"]'),
('song-ci-812','沁园春','黄庭坚','宋','宋词','song-ci','沁园春','[]','把我身心，为伊烦恼，算天便知。',140,'宋词/ci.song.2000.json','["把我身心，为伊烦恼，算天便知。", "恨一回相见，百方作计，未能偎倚，早觅东西。", "镜里拈花，水中捉月，觑著无由得近伊。", "添憔悴，镇花销翠减，玉瘦香肌。", "奴儿。", "又有行期。", "你去即无妨我共谁。", "向眼前常见，心犹未足，怎生禁得，真个分离。", "地角天涯，我随君去。", "掘井为盟无改移。", "君须是，做些儿相度，莫待临时。"]'),
('song-ci-813','千秋岁','黄庭坚','宋','宋词','song-ci','千秋岁','[]','苑边花外。',87,'宋词/ci.song.2000.json','["苑边花外。", "记得同朝退。", "飞骑轧，鸣珂碎。", "齐歌云绕扇，赵舞风回带。", "岩鼓断，杯盘狼藉犹相对。", "洒泪谁能会。", "醉卧藤阴盖。", "人已去，词空在。", "兔园高宴悄，虎观英游改。", "重感慨，波涛万顷珠沈海。"]'),
('song-ci-814','千秋岁','黄庭坚','宋','宋词','song-ci','千秋岁','[]','世间好事。',87,'宋词/ci.song.2000.json','["世间好事。", "恰恁厮当对。", "乍夜永，凉天气。", "雨稀帘外滴，香篆盘中字。", "长入梦，如今见也分明是。", "欢极娇无力，玉软花敧坠。", "钗罥袖，云堆臂。", "灯斜明媚眼，汗浃瞢腾醉。", "奴奴睡，奴奴睡也奴奴睡。"]'),
('song-ci-815','河传','黄庭坚','宋','宋词','song-ci','河传','[]','心情老懒。',75,'宋词/ci.song.2000.json','["心情老懒。", "对歌对舞，犹是当时眼。", "巧笑靓妆，近我衰容华鬓。", "似扶著、卖卜算。", "思量好个当年见。", "催酒催更，只怕归期短。", "饮散灯稀，背锁落花深院。", "好杀人、天不管。"]'),
('song-ci-816','望江东','黄庭坚','宋','宋词','song-ci','望江东','[]','江水西头隔烟树。',64,'宋词/ci.song.2000.json','["江水西头隔烟树。", "望不见、江东路。", "思量只有梦来去。", "更不怕、江阑住。", "灯前写了书无数。", "算没个、人传与。", "直饶寻得雁分付。", "又还是、秋将暮。"]'),
('song-ci-817','桃源忆故人','黄庭坚','宋','宋词','song-ci','桃源忆故人','[]','碧天露洗春容净。',56,'宋词/ci.song.2000.json','["碧天露洗春容净。", "淡月晓收残晕。", "花上密烟飘尽。", "花底莺声嫩。", "云归楚峡厌厌困。", "两点遥山新恨。", "和泪暗弹红粉。", "生怕人来问。"]'),
('song-ci-818','卜算子','黄庭坚','宋','宋词','song-ci','卜算子','[]','要见不得见，要近不得近。',56,'宋词/ci.song.2000.json','["要见不得见，要近不得近。", "试问得君多少怜，管不解、多於恨。", "禁止不得泪，忍管不得闷。", "天上人间有底愁，向个里、都谙尽。"]'),
('song-ci-819','蝶恋花','黄庭坚','宋','宋词','song-ci','蝶恋花','[]','海角芳菲留不住。',70,'宋词/ci.song.2000.json','["海角芳菲留不住。", "笔下风生，吹入青云去。", "仙籍有名天赐与。", "致君事业安排取。", "要识世间平坦路。", "当使人人，各有安身处。", "黑发便逢尧舜主。", "笑人白首耕南亩。"]'),
('song-ci-820','浣溪沙','黄庭坚','宋','宋词','song-ci','浣溪沙','[]','飞鹊台前晕翠蛾。',48,'宋词/ci.song.2000.json','["飞鹊台前晕翠蛾。", "千金新买帝青螺。", "最难如意为情多。", "几处泪痕留醉袖，一春愁思近横波。", "远山低尽不成歌。"]'),
('song-ci-821','浣溪沙','黄庭坚','宋','宋词','song-ci','浣溪沙','[]','一叶扁舟卷画帘。',48,'宋词/ci.song.2000.json','["一叶扁舟卷画帘。", "老妻学饮伴清谈。", "人传诗句满江南。", "林下猿垂窥涤砚，岩前鹿卧看收帆。", "杜鹃声乱水如环。"]'),
('song-ci-822','诉衷情','黄庭坚','宋','宋词','song-ci','诉衷情','[]','小桃灼灼柳鬖鬖。',54,'宋词/ci.song.2000.json','["小桃灼灼柳鬖鬖。", "春色满江南。", "雨晴风暖烟淡，天气正醺酣。", "山泼黛，水挼蓝。", "翠相搀。", "歌楼酒旆，故故招人，权典青衫。"]'),
('song-ci-823','诉衷情','黄庭坚','宋','宋词','song-ci','诉衷情','[]','旋揎玉指著红靴。',56,'宋词/ci.song.2000.json','["旋揎玉指著红靴。", "宛宛斗弯讹。", "天然自有殊态，供愁黛、不须多。", "分远岫，压横波。", "妙难过。", "自敧枕处，独倚阑时，不奈颦何。"]'),
('song-ci-824','诉衷情','黄庭坚','宋','宋词','song-ci','诉衷情','[]','珠帘绣幕卷轻霜。',56,'宋词/ci.song.2000.json','["珠帘绣幕卷轻霜。", "呵手试梅妆。", "都缘自有离恨，故画作、远山长。", "思往事，惜流光。", "恨难忘。", "未歌先敛，欲笑还颦，最断人肠。"]'),
('song-ci-825','昼夜乐','黄庭坚','宋','宋词','song-ci','昼夜乐','[]','夜深记得临歧语。',118,'宋词/ci.song.2000.json','["夜深记得临歧语。", "说花时、归来去。", "教人每日思量，到处与谁分付。", "其奈冤家无定据。", "约云朝、又还雨暮。", "将泪入鸳衾，总不成行步。", "元来也解知思虑。", "一封书、深相许。", "情知玉帐堪欢，为向金门进取。", "直待腰金拖紫后，有夫人、县君相与。", "争奈会分疏，没嫌伊门路。"]'),
('song-ci-826','一落索','黄庭坚','宋','宋词','song-ci','一落索','[]','谁道秋来烟景素。',60,'宋词/ci.song.2000.json','["谁道秋来烟景素。", "任游人不顾。", "一番时态一番新，到得意、皆欢慕。", "紫萸黄菊繁华处。", "对风庭月露。", "愁来即便去寻芳，更作甚、悲秋赋。"]'),
('song-ci-827','满庭芳','黄庭坚','宋','宋词','song-ci','满庭芳','[]','风力驱寒，云容呈瑞，晓来到处花飞。',118,'宋词/ci.song.2000.json','["风力驱寒，云容呈瑞，晓来到处花飞。", "遍装琼树，春意到南枝。", "便是渔蓑旧画，纶竿重、横玉低垂。", "今宵里，香闺邃馆，幽赏事偏宜。", "风流，金马客，歌鬟醉拥，乌帽斜敧。", "问人间何处，鹏运天池。", "且共周郎按曲，音微误、首已先回。", "同心事，丹山路稳，长伴彩鸾归。"]'),
('song-ci-828','西江月','黄庭坚','宋','宋词','song-ci','西江月','[]','细细风清撼竹，迟迟日暖开花。',58,'宋词/ci.song.2000.json','["细细风清撼竹，迟迟日暖开花。", "香帏深卧醉人家。", "媚语娇声娅姹。", "姹娅声娇语媚，家人醉卧深帏。", "香花开暖日迟迟。", "竹撼清风细细。"]'),
('song-ci-829','失调名','黄庭坚','宋','宋词','song-ci','失调名','[]','直须把、茱萸遍插，看满座、细嗅清香。',18,'宋词/ci.song.2000.json','["直须把、茱萸遍插，看满座、细嗅清香。"]'),
('song-ci-830','好事近','黄庭坚','宋','宋词','song-ci','好事近','[]','潇洒荐冰盘，满座暗惊香集。',53,'宋词/ci.song.2000.json','["潇洒荐冰盘，满座暗惊香集。", "久后一般风味，问几人知得。", "画堂饮散已归来，清润转更惜。", "留取酒醒时候，助茗瓯春色。"]'),
('song-ci-831','瑞鹤仙','黄庭坚','宋','宋词','song-ci','瑞鹤仙','[]','环滁皆山也。',126,'宋词/ci.song.2000.json','["环滁皆山也。", "望蔚然深秀，琅琊山也。", "山行六七里，有翼然泉上，醉翁亭也。", "翁之乐也。", "得之心、寓之酒也。", "更野芳佳木，风高日出，景无穷也。", "游也。", "山肴野蔌，酒冽泉香，沸筹觥也。", "太守醉也。", "喧哗众宾欢也。", "况宴酣之乐、非丝非竹，太守乐其乐也。", "问当时、太守为谁，醉翁是也。"]'),
('song-ci-832','蓦山溪','黄庭坚','宋','宋词','song-ci','蓦山溪','[]','朝来风日，陡觉春衫便。',102,'宋词/ci.song.2000.json','["朝来风日，陡觉春衫便。", "翠柳艳明眉，戏秋千、谁家倩盼。", "烟匀露洗，草色媚横塘，平沙软。", "雕轮转。", "行乐闻弦管。", "追思年少，走马寻芳伴。", "一醉几缠头，过扬州、珠帘尽卷。", "而今老矣，花似雾中看，欢喜浅。", "天涯远。", "信马归来晚。"]'),
('song-ci-833','捣练子','黄庭坚','宋','宋词','song-ci','捣练子','[]','梅凋粉，柳摇金。',32,'宋词/ci.song.2000.json','["梅凋粉，柳摇金。", "微雨轻风敛陌尘。", "厚约深盟何处诉，除非重见那人人。"]'),
('song-ci-834','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','浮动花钗影鬓烟。',48,'宋词/ci.song.2000.json','["浮动花钗影鬓烟。", "浅妆浓笑有馀妍。", "酒醺檀点语凭肩。", "留不住时分钿镜，旧曾行处失金莲。", "碧云芳草恨年年。"]'),
('song-ci-835','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','两点春山一寸波。',48,'宋词/ci.song.2000.json','["两点春山一寸波。", "当筵娇甚不成歌。", "动人情态可须多。", "金井露寒风下叶，画桥云断月侵河。", "厌厌此夜奈愁何。"]'),
('song-ci-836','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','清浅陂塘藕叶乾。',48,'宋词/ci.song.2000.json','["清浅陂塘藕叶乾。", "细风蔬雨鹭鸶寒。", "半垂帘幕倚阑干。", "惆怅窃香人不见，几回憔悴后庭兰。", "行云可是渡江难。"]'),
('song-ci-837','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','楼角初销一缕霞。',48,'宋词/ci.song.2000.json','["楼角初销一缕霞。", "淡黄杨柳暗栖鸦。", "玉人和月摘梅花。", "笑拈粉香归洞户，更垂帘幕护窗纱。", "东风寒似夜来些。"]'),
('song-ci-838','相思引','贺铸','宋','宋词','song-ci','相思引','[]','团扇单衣杨柳陌。',90,'宋词/ci.song.2000.json','["团扇单衣杨柳陌。", "花似春风□无迹。", "赖白玉香奁供汾泽。", "借秀色。", "添春色。", "借秀色。", "添春色。", "云幕华灯张绮席。", "半醉客。", "留醒客。", "半醉客。", "留醒客。", "渐促膝倾鬟琴差拍。", "问此夕。", "知何夕。", "问此夕。", "知何夕。"]'),
('song-ci-839','天门谣','贺铸','宋','宋词','song-ci','天门谣','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','牛渚天门险。',57,'宋词/ci.song.2000.json','["牛渚天门险。", "限南北、七雄豪占。", "清雾敛。", "与闲人登览。", "待月上潮平波滟滟。", "塞管轻吹新《阿滥》。", "风满槛。", "历历数、西州更点。"]'),
('song-ci-840','献金杯・厌金杯','贺铸','宋','宋词','song-ci','献金杯・厌金杯','[]','风软香迟，花深漏短。',82,'宋词/ci.song.2000.json','["风软香迟，花深漏短。", "可怜宵、画堂春半。", "碧纱窗影，卷帐蜡灯红，鸳枕畔。", "密写乌丝一段。", "采苹溪晚。", "拾翠沙空，尽愁倚、梦云飞观。", "木兰艇子，几日渡江来，心目断。", "桃叶青山隔岸。"]'),
('song-ci-841','清平乐','贺铸','宋','宋词','song-ci','清平乐','[]','阴晴未定。',54,'宋词/ci.song.2000.json','["阴晴未定。", "薄日烘云影。", "临水朱门花一径。", "尽日鸟啼人静。", "厌厌几许春情。", "可怜老去兰成。", "看取镊残双鬓，不随芳草重生。"]'),
('song-ci-842','清平乐','贺铸','宋','宋词','song-ci','清平乐','[]','小桃初谢。',54,'宋词/ci.song.2000.json','["小桃初谢。", "双燕还来也。", "记得年时寒食下。", "紫陌青门游冶。", "楚城满目春华。", "可堪游子思家。", "惟有夜来归梦，不知身在天涯。"]'),
('song-ci-843','摊破浣溪沙・山花子','贺铸','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','湖上秋深藕叶黄。',56,'宋词/ci.song.2000.json','["湖上秋深藕叶黄。", "清霜销瘦损垂杨。", "洲嘴嫩沙斜照暖，睡鸳鸯。", "红粉莲娃何处在，西风不为管馀香。", "今夜月明闻水调，断人肠。"]'),
('song-ci-844','摊破浣溪沙・山花子','贺铸','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','双凤箫声隔彩霞。',56,'宋词/ci.song.2000.json','["双凤箫声隔彩霞。", "朱门深闭七香车。", "何处探春寻旧约，谢娘家。", "旖旎细风飘水麝，玲珑残雪浸山茶。", "饮罢西厢帘影外，玉蟾斜。"]'),
('song-ci-845','惜双双・惜分飞','贺铸','宋','宋词','song-ci','惜双双・惜分飞','[]','皎镜平湖三十里。',58,'宋词/ci.song.2000.json','["皎镜平湖三十里。", "碧玉山围四际。", "莲荡香风里。", "彩鸳鸯觉双飞起。", "明月多情随舵尾。", "偏照空床翠被。", "回首笙歌地。", "醉更衣处长相记。"]'),
('song-ci-846','思越人・朝天子','贺铸','宋','宋词','song-ci','思越人・朝天子','[]','紫府东风放夜时。',64,'宋词/ci.song.2000.json','["紫府东风放夜时。", "步莲秾李伴人归。", "五更钟动笙歌散，十里月明灯火稀。", "香苒苒，梦依依。", "天涯寒尽减春衣。", "凤凰城阕知何处，寥落星河一雁飞。"]'),
('song-ci-847','思越人・朝天子','贺铸','宋','宋词','song-ci','思越人・朝天子','[]','怊怅离亭断采襟。',64,'宋词/ci.song.2000.json','["怊怅离亭断采襟。", "碧云明月两关心。", "几行书尾情何限，一尺裙腰瘦不禁。", "遥夜半，曲房深。", "有时昵语话如今。", "侵窗冷雨灯生晕，泪湿罗笺楚调吟。"]'),
('song-ci-848','鹤冲天','贺铸','宋','宋词','song-ci','鹤冲天','[]','冬冬鼓动，花外沈残漏。',103,'宋词/ci.song.2000.json','["冬冬鼓动，花外沈残漏。", "华月万枝灯，还清昼。", "广陌衣香度，飞盖影、相先后。", "个处频回首。", "锦房西去，期约武陵西口。", "当时早恨欢难偶。", "可堪流浪远，分携久。", "小畹兰英在，轻付与、何人手。", "不似长亭柳。", "舞枫眠雨，伴我一春销瘦。"]'),
('song-ci-849','小重山','贺铸','宋','宋词','song-ci','小重山','[]','飘径梅英雪未融。',70,'宋词/ci.song.2000.json','["飘径梅英雪未融。", "芳菲消息到，杏梢红。", "隔年欢事水西东。", "凝思久，不语坐书空。", "回想夹城中。", "采山箫鼓沸，绮罗丛。", "钿轮珠网玉花骢。", "香陌上，谁与斗春风。"]'),
('song-ci-850','六州歌头','贺铸','宋','宋词','song-ci','六州歌头','[]','少年侠气，交结五都雄。',123,'宋词/ci.song.2000.json','["少年侠气，交结五都雄。", "肝胆洞。", "毛发耸。", "立谈中。", "死生同。", "一诺千金重。", "推翘勇。", "衿豪踪。", "轻盖拥。", "聊飞鞚。", "斗城东。", "轰饮酒炉，春色浮寒瓮。", "吸海垂虹。", "闲呼鹰嗾犬，白羽摘雕弓。", "狡穴俄空。", "乐匆匆。", "似黄粱梦。", "辞丹凤。", "明月共。", "漾孤篷。", "官冗从。", "怀倥偬。", "落尘笼。", "薄书从。"]'),
('song-ci-851','浣溪沙','贺铸','宋','宋词','song-ci','浣溪沙','[]','翠縠参差拂水风。',48,'宋词/ci.song.2000.json','["翠縠参差拂水风。", "暖云如絮扑低空。", "丽人波脸觉春融。", "缨挂宝钗初促席，檀高微注玉杯红。", "芳醪何似此情浓。"]'),
('song-ci-852','浣溪沙','贺铸','宋','宋词','song-ci','浣溪沙','[]','云母窗前歇绣针。',48,'宋词/ci.song.2000.json','["云母窗前歇绣针。", "低鬟凝思坐调琴。", "玉纤纤按十三金。", "归卧文园犹带酒，柳花飞度画堂阴。", "只凭双燕话春心。"]'),
('song-ci-853','浣溪沙','贺铸','宋','宋词','song-ci','浣溪沙','[]','叠鼓新歌百样娇。',48,'宋词/ci.song.2000.json','["叠鼓新歌百样娇。", "铜丸玉腕促云谣。", "揭帘飞瓦雹声焦。", "九渠池边杨柳陌，香轮轧轧马箫箫。", "细风妆面酒痕销。"]'),
('song-ci-854','江城子','贺铸','宋','宋词','song-ci','江城子','[]','麝熏微度绣芙蓉。',86,'宋词/ci.song.2000.json','["麝熏微度绣芙蓉。", "翠衾重。", "画堂空。", "前夜偷期，相见却匆匆。", "心事两知何处问，依约是，梦中逢。", "坐疑行听竹窗风。", "出帘栊。", "杳无踪。", "已过黄昏，缠动寺楼钟。", "暮雨不来春又去，花满地，月朦胧。"]'),
('song-ci-855','浪淘沙','贺铸','宋','宋词','song-ci','浪淘沙','[]','一叶忽惊秋。',64,'宋词/ci.song.2000.json','["一叶忽惊秋。", "分付东流。", "殷勤为过白苹洲。", "洲上小楼帘半卷，应认归舟。", "回首恋朋游。", "迹去心留。", "歌尘萧散梦云收。", "惟有尊前曾见月，相伴人愁。"]'),
('song-ci-856','木兰花・玉楼春','贺铸','宋','宋词','song-ci','木兰花・玉楼春','[]','佩环声认腰肢软。',64,'宋词/ci.song.2000.json','["佩环声认腰肢软。", "风里麝熏知近远。", "此身常羡玉妆台，得见晓来梳画面。", "回廊几步通深院。", "一桁绣衣帘不卷。", "酒阑歌罢欲黄昏，肠断归巢双燕燕。"]'),
('song-ci-857','木兰花・玉楼春','贺铸','宋','宋词','song-ci','木兰花・玉楼春','[]','银黄雁柱香檀拨。',64,'宋词/ci.song.2000.json','["银黄雁柱香檀拨。", "镂板三声催细抹。", "舞腰轻怯绛裙长，羞按筑球花十八。", "东城柳岸匆匆发。", "画舫一篙烟水阔。", "可怜单枕欲眠时，还见尊前前夜月。"]'),
('song-ci-858','蝶恋花','贺铸','宋','宋词','song-ci','蝶恋花','[]','小院朱扉开一扇。',70,'宋词/ci.song.2000.json','["小院朱扉开一扇。", "内样新妆，镜里分明见。", "眉晕半深唇注浅。", "朵云冠子偏宜面。", "被掩芙蓉熏麝煎。", "帘影沈沈，祗有双飞燕。", "心事向人犹腼腆。", "强来窗下寻针线。"]'),
('song-ci-859','石州引・石州慢','贺铸','宋','宋词','song-ci','石州引・石州慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','薄雨初寒，斜照弄晴，春意空阔。',123,'宋词/ci.song.2000.json','["薄雨初寒，斜照弄晴，春意空阔。", "长亭柳色缠黄，远客一枝先折。", "烟横水际，映带几点归鸦，东风销尽龙沙雪。", "还记初关来，恰而今时节。", "将发。", "画楼芳酒，红泪清歌，顿成清别。", "已是经年，杳杳音尘多绝。", "欲知方寸，共有几许清愁，芭蕉不展丁香结。", "枉望断天涯，两厌厌风月。"]'),
('song-ci-860','失调名','贺铸','宋','宋词','song-ci','失调名','[]','罗帷映月，玉研生冰。',10,'宋词/ci.song.2000.json','["罗帷映月，玉研生冰。"]'),
('song-ci-861','失调名','贺铸','宋','宋词','song-ci','失调名','[]','风头梦、吹无迹。',8,'宋词/ci.song.2000.json','["风头梦、吹无迹。"]'),
('song-ci-862','减字木兰花','贺铸','宋','宋词','song-ci','减字木兰花','[]','簪花照镜。',52,'宋词/ci.song.2000.json','["簪花照镜。", "客鬓萧萧都不整。", "拟倩东□。", "化作尊前如梦云。", "风香月影。", "信是瑶台清夜永。", "深闭重门。", "牵绊刘郎别后魂。"]'),
('song-ci-863','凤栖梧・蝶恋花','贺铸','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','为问宛溪桥畔柳。',70,'宋词/ci.song.2000.json','["为问宛溪桥畔柳。", "拂水倡条，几赠行人手。", "一样叶眉偏解皱。", "白绵飞尽因谁瘦。", "今日离亭还对酒。", "唱断青青，好去休回首。", "美阴向人疏似旧。", "何须更待秋风后。"]'),
('song-ci-864','南柯子・南歌子','贺铸','宋','宋词','song-ci','南柯子・南歌子','[]','斗酒才供泪，扁舟只载愁。',62,'宋词/ci.song.2000.json','["斗酒才供泪，扁舟只载愁。", "画桥青柳小朱楼。", "犹记出城车马、为迟留。", "有恨花空委，无情水自流。", "河阳新鬓尽禁秋。", "萧散楚云巫雨、生此休。"]'),
('song-ci-865','望湘人','贺铸','宋','宋词','song-ci','望湘人','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','厌莺声到枕，花气动帘，醉魂愁梦相半。',130,'宋词/ci.song.2000.json','["厌莺声到枕，花气动帘，醉魂愁梦相半。", "被惜馀薰，带惊剩眼。", "几许伤春春晚。", "泪竹痕鲜，佩兰香老，湘天浓暖。", "记小江、风月佳时，屡约非烟游伴。", "须信鸾弦易断。", "奈云和再鼓，曲终人远。", "认罗袜无踪，旧处弄波清浅。", "青翰棹舣，白苹洲畔。", "尽木临皋飞观。", "不解寄、一字相思，幸有归来双燕。"]'),
('song-ci-866','谒金门','贺铸','宋','宋词','song-ci','谒金门','[]','杨花落。',54,'宋词/ci.song.2000.json','["杨花落。", "燕子横川朱阁。", "常恨春醪如水薄。", "闲愁无处著。", "绿野带江山络角。", "桃叶参差前约。", "历历短樯沙外泊。", "东风晚来恶。"]'),
('song-ci-867','蝶恋花','贺铸','宋','宋词','song-ci','蝶恋花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','几许伤春春复暮。',70,'宋词/ci.song.2000.json','["几许伤春春复暮。", "杨柳清阴，偏碍游丝度。", "天际小山桃叶步。", "白苹花满湔裙处。", "竟日微吟长短句。", "帘影灯昏，心寄胡琴语。", "数点雨声风约住。", "朦胧淡月云来去。"]'),
('song-ci-868','小梅花・梅花引','贺铸','宋','宋词','song-ci','小梅花・梅花引','[]','思前别。',140,'宋词/ci.song.2000.json','["思前别。", "记时节。", "美人颜色如花发。", "美人归。", "天一涯。", "娟娟姮娥，三五满还亏。", "翠眉蝉鬓生离诀。", "遥望青楼心欲绝。", "梦中寻。", "卧巫云。", "觉来珠泪，滴向湘水深。", "愁无已。", "奏绿绮。", "历历高山与流水。", "妙通神。", "觉知音。", "不知暮雨朝云、何山岑。", "相思无计堪可比。", "珠箔雕阑集千里。", "漏将分。", "月窗明。", "一夜梅花忽开、疑是君。"]'),
('song-ci-869','乌啼月・乌夜啼','贺铸','宋','宋词','song-ci','乌啼月・乌夜啼','[]','牛女相望处，星桥不碍东西。',55,'宋词/ci.song.2000.json','["牛女相望处，星桥不碍东西。", "重墙未抵蓬山远，却恨画楼低。", "细字频传幽怨，凝缸长照单栖。", "城乌可是知人意，偏向月明啼。"]'),
('song-ci-870','簇水近','贺铸','宋','宋词','song-ci','簇水近','[]','一笛清风弄袖，新月梳云缕。',100,'宋词/ci.song.2000.json','["一笛清风弄袖，新月梳云缕。", "澄凉夜色，缠过几点黄昏雨。", "侠少朋游，正喜九陌消尘土。", "鞭穗袅、紫骝花步。", "过朱户。", "认得宫妆，为谁重扫新眉妩。", "徘徊片响难问，桃李都无语。", "十二青楼下，指灯火章台路。", "不念人、肠断归去。"]'),
('song-ci-871','画眉郎・好女儿','贺铸','宋','宋词','song-ci','画眉郎・好女儿','[]','雪絮雕章。',77,'宋词/ci.song.2000.json','["雪絮雕章。", "梅粉华妆。", "小芒台、榧机罗湘素，鼓铜蟾砚滴，金雕琴写，玉燕钗梁。", "五马徘徊长路，漫非意、凤求凰。", "认兰情、自有怜才处，似题桥贵客，栽花潘令，真画眉郎。"]'),
('song-ci-872','试周郎・诉衷情','贺铸','宋','宋词','song-ci','试周郎・诉衷情','[]','乔家深闭郁金堂。',54,'宋词/ci.song.2000.json','["乔家深闭郁金堂。", "朝镜事梅妆。", "云鬟翠钿浮动，微步拥钗梁。", "情尚秘，色犹庄。", "递瞻相。", "弄丝调管，时误新声，翻试周郎。"]'),
('song-ci-873','新念别・夜游宫','贺铸','宋','宋词','song-ci','新念别・夜游宫','[]','湖上兰舟暮发。',70,'宋词/ci.song.2000.json','["湖上兰舟暮发。", "扬州梦断灯明灭。", "想见琼花开似雪。", "帽檐香，玉纤纤，曾为折。", "渔管吹还咽。", "问何意、煎人愁绝。", "江北江南新念别。", "掩芳尊，与谁同，今夜月。"]'),
('song-ci-874','谒金门','贺铸','宋','宋词','song-ci','谒金门','[]','溪声急。',53,'宋词/ci.song.2000.json','["溪声急。", "无数落花漂出。", "燕子分泥蜂酿蜜。", "迟迟艳风日。", "须信芳菲随失。", "况复佳期难必。", "拟把此情书万一。", "愁多翻阁笔。"]'),
('song-ci-875','减字木兰花','贺铸','宋','宋词','song-ci','减字木兰花','[]','冷香浮动。',52,'宋词/ci.song.2000.json','["冷香浮动。", "望处欲声胡蝶梦。", "晓日曈昽。", "愁见凝酥暖渐融。", "鼓催歌送。", "芳酒一尊谁与共。", "寂寞墙东。", "门掩黄昏满院风。"]'),
('song-ci-876','摊破浣溪沙・山花子','贺铸','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','锦鞯未弦瑟瑟徽。',56,'宋词/ci.song.2000.json','["锦鞯未弦瑟瑟徽。", "玉纤新拟凤双飞。", "缥缈烛烟花暮暗，就更衣。", "约略整环钗影动，迟回顾步佩声微。", "宛是春风胡蝶舞，带香归。"]'),
('song-ci-877','瑶台第一层','赵仲御','宋','宋词','song-ci','瑶台第一层','[]','嶰管声催。',120,'宋词/ci.song.2000.json','["嶰管声催。", "人报道、嫦娥步月来。", "凤灯鸾矩，寒轻廉箔，光泛楼台。", "万年春未老，更帝乡日月蓬莱。", "从仙仗，看星河银界，锦绣天街。", "欢陪。", "千官万骑，九霄人在五云堆。", "紫袍光里，星球宛转，花影徘徊。", "未央宫漏水，散异香、龙阙崔嵬。", "翠舆回。", "奏仙歌韶吹，宝殿尊罍。"]'),
('song-ci-878','蓦山溪','仲殊','宋','宋词','song-ci','蓦山溪','[]','清江平淡，疏雨和烟染。',102,'宋词/ci.song.2000.json','["清江平淡，疏雨和烟染。", "春在广寒宫，付江梅、先开素艳。", "年年第一，相见越溪东，云体态，雪精神，不把年华占。", "山亭水榭，别恨多销黯。", "又是主人来，更不辜、香心一点。", "题诗才思，清似玉壶冰，轻回顾，落尊前，桃杏声华减。"]'),
('song-ci-879','鹊踏枝・蝶恋花','仲殊','宋','宋词','song-ci','鹊踏枝・蝶恋花','[]','斜日平山寒已薄。',70,'宋词/ci.song.2000.json','["斜日平山寒已薄。", "雪过松梢，犹有残英落。", "晚色际天天似幕。", "一尊先与东风约。", "邀得红梅同宴乐。", "酒面融春，春满纤纤萼。", "客意为伊浑忘却。", "归船且傍花阴泊。"]'),
('song-ci-880','点绛唇','仲殊','宋','宋词','song-ci','点绛唇','[]','春遇瑶池，长空飞下残英片。',50,'宋词/ci.song.2000.json','["春遇瑶池，长空飞下残英片。", "素光围练。", "寒透笙歌院。", "莫把寿阳，妆信传书箭。", "掩香面。", "汉宫寻遍。", "月里还相见。"]'),
('song-ci-881','南歌子','仲殊','宋','宋词','song-ci','南歌子','[]','十里青山远，潮平陆带沙。',62,'宋词/ci.song.2000.json','["十里青山远，潮平陆带沙。", "数声啼鸟怨年华。", "又是凄凉时候、在天涯。", "白露收残暑，清风衬晚霞。", "绿杨堤畔闹荷花。", "记得年时沽酒、那人家。"]'),
('song-ci-882','减字木兰花','仲殊','宋','宋词','song-ci','减字木兰花','["\u94b1\u5858\u6c5f"]','谁将妙笔。',52,'宋词/ci.song.2000.json','["谁将妙笔。", "写就素缣三百匹。", "天下应无。", "此是钱塘江上图。", "一般奇绝。", "云淡天低秋夜月。", "费尽丹青。", "只这些儿画不成。"]'),
('song-ci-883','减字木兰花','仲殊','宋','宋词','song-ci','减字木兰花','[]','江南三月。',52,'宋词/ci.song.2000.json','["江南三月。", "犹有枝头千点雪。", "邀上芳尊。", "却占东君一半春。", "尊前眼底。", "南国风光都在此。", "移过江来。", "从此江南不复开。"]'),
('song-ci-884','南歌子','仲殊','宋','宋词','song-ci','南歌子','[]','解舞清平乐，如今说向谁。',62,'宋词/ci.song.2000.json','["解舞清平乐，如今说向谁。", "红炉片雪上钳锤。", "打就金毛狮子、也堪疑。", "木女明开眼，泥人暗皱眉。", "蟠桃已是著花迟。", "不向春风一笑、待何时。"]'),
('song-ci-885','踏莎行','仲殊','宋','宋词','song-ci','踏莎行','[]','浓润侵衣，暗香飘砌。',68,'宋词/ci.song.2000.json','["浓润侵衣，暗香飘砌。", "雨中花色添憔悴。", "凤鞋湿透立多时，不言不语厌厌地。", "眉上新愁，手中文字。", "因何不倩鳞鸿寄。", "想伊只诉薄情人，官中谁管闲公事。"]'),
('song-ci-886','金蕉叶','仲殊','宋','宋词','song-ci','金蕉叶','[]','丛霄逸韵祥烟渺。',73,'宋词/ci.song.2000.json','["丛霄逸韵祥烟渺。", "摇金翠、玲珑三岛。", "地控全吴，山横旧楚春来早。", "千里断云芳草。", "六朝遗恨连江表。", "都分付、倚楼吟啸。", "铁瓮城头，一声画角吹残照。", "带夜潮来到。"]'),
('song-ci-887','定风波','仲殊','宋','宋词','song-ci','定风波','[]','花戟云幡拥上方。',70,'宋词/ci.song.2000.json','["花戟云幡拥上方。", "画帘风细度春香。", "银色界前多远景。", "人静。", "铁城西面又斜阳。", "山色入江流不尽，古今一梦莫思量。", "故里无家归去懒。", "伤远。", "年华满眼多凄凉。"]'),
('song-ci-888','蝶恋花','仲殊','宋','宋词','song-ci','蝶恋花','[]','北固山前波浪远。',70,'宋词/ci.song.2000.json','["北固山前波浪远。", "铁瓮城头，画角残声短。", "促酒溅金催小宴。", "灯摇蜡焰香风软。", "落日烟霞晴满眼。", "欲仗丹青，巧笔彤牙管。", "解写伊川山色浅。", "谁能画得江天晚。"]'),
('song-ci-889','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，鼓角乱云中。',64,'宋词/ci.song.2000.json','["南徐好，鼓角乱云中。", "金地浮山星雨点，铁城横锁瓮三重。", "开国旧夸雄。", "春过后，佳气荡晴空。", "渌水画桥沽酒市，清江晚渡落花风。", "千古夕阳红。"]'),
('song-ci-890','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，城里小花山。',64,'宋词/ci.song.2000.json','["南徐好，城里小花山。", "淡薄融香松滴露，萧疏笼翠竹生烟。", "风月共闲闲。", "金晕暗，灯火小红莲。", "太尉昔年行乐地，都人今日散花天。", "桃李但无言。"]'),
('song-ci-891','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，桥下渌波平。',64,'宋词/ci.song.2000.json','["南徐好，桥下渌波平。", "画柱千年尝有鹤，垂杨三月未闻莺。", "行乐过清明。", "南北岸，花市管弦声。", "邀客上楼双榼酒，舣舟清夜两街灯。", "直上月亭亭。"]'),
('song-ci-892','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，溪上百花堆。',64,'宋词/ci.song.2000.json','["南徐好，溪上百花堆。", "宴罢歌声随水去，梦回春色入门来。", "芳草遍池台。", "文彩动，奎璧烂昭回。", "玉殿仪刑推旧德。", "金銮词赋少高才。", "丹诏起风雷。"]'),
('song-ci-893','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，春坞锁池亭。',64,'宋词/ci.song.2000.json','["南徐好，春坞锁池亭。", "山送云来长入梦，水浮花去不知名。", "烟草上东城。", "歌榭外，杨柳晚青青。", "收拾年华藏不住，暗传消息漏新声。", "无计奈流莺。"]'),
('song-ci-894','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，多景在楼前。',64,'宋词/ci.song.2000.json','["南徐好，多景在楼前。", "京口万家寒食日，淮南千里夕阳天。", "天际几重山。", "莺啼处，人倚画阑干。", "西寨烟深晴后色，东风春减夜来寒。", "花满过江船。"]'),
('song-ci-895','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，浮玉旧花宫。',64,'宋词/ci.song.2000.json','["南徐好，浮玉旧花宫。", "琢破琉璃闲世界，化城楼阁在虚空。", "香雾锁重重。", "天共水，高下混相通。", "云外月轮波底见，倚阑人在一光中。", "此景与谁同。"]'),
('song-ci-896','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，樽酒上西楼。',64,'宋词/ci.song.2000.json','["南徐好，樽酒上西楼。", "调鼎勋庸还世事，镇江旌节从仙游。", "楼下水空流。", "桃李在，花月更悠悠。", "侍燕歌终无旧梦，画眉灯暗至今愁。", "香冷舞衣秋。"]'),
('song-ci-897','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，桥下绿杨村。',64,'宋词/ci.song.2000.json','["南徐好，桥下绿杨村。", "两谢风流称郡守，二苏家世作州民。", "文彩动星辰。", "书万卷，今日富儿孙。", "三径客来消永昼，百壶酒尽过芳春。", "江月伴开尊。"]'),
('song-ci-898','南徐好','仲殊','宋','宋词','song-ci','南徐好','[]','南徐好，直下控淮津。',64,'宋词/ci.song.2000.json','["南徐好，直下控淮津。", "山放凝云低凤翅，潮生轻浪卷龙鳞。", "清洗古今愁。", "天尽处，风水接西滨。", "井里不传溪上信，杨花犹见渡头春。", "愁杀渡江人。"]'),
('song-ci-899','失调名','仲殊','宋','宋词','song-ci','失调名','[]','潇潇暮雨，梨花寒食。',10,'宋词/ci.song.2000.json','["潇潇暮雨，梨花寒食。"]'),
('song-ci-900','念奴娇','仲殊','宋','宋词','song-ci','念奴娇','[]','水枫叶下，乍湖光清浅。',120,'宋词/ci.song.2000.json','["水枫叶下，乍湖光清浅。", "凉生商素。", "西帝宸游罗翠盖，拥出三千宫女。", "绛采娇春，铅华掩昼，占断鸳鸯浦。", "歌声摇曳，浣沙人在何处。", "别岸孤袅一枝，广寒宫殿，冷落栖愁苦。", "雪艳冰肌羞淡泊，偷把胭脂匀注。", "媚脸笼霞，芳心泣露，不肯为云雨。", "金波影里，为谁长恁凝伫。"]'),
('song-ci-901','蓦山溪','仲殊','宋','宋词','song-ci','蓦山溪','[]','年芳已远，凉夏疏疏雨。',102,'宋词/ci.song.2000.json','["年芳已远，凉夏疏疏雨。", "菊占此时开，背佳期、清秋何处。", "滴成金豆，弹破栗文圆，临水槛，倚风亭，全胜东篱暮。", "茱萸未结，谁是多情侣。", "菖叶与葵花，也相饶、也□羞妒。", "主人著意，何必念登高，浮酒面，解烦襟，消尽当筵暑。"]'),
('song-ci-902','减字木兰花','仲殊','宋','宋词','song-ci','减字木兰花','[]','青条绿叶。',52,'宋词/ci.song.2000.json','["青条绿叶。", "结起蓬瀛连万叠。", "风引飘飘。", "下有红波引六鳌。", "五城烟敛。", "剪碎采云红点点。", "帖在山腰。", "旁有斑斑雪未消。"]'),
('song-ci-903','浣溪沙','仲殊','宋','宋词','song-ci','浣溪沙','[]','楚客才华为发扬。',48,'宋词/ci.song.2000.json','["楚客才华为发扬。", "深林著意不相忘。", "梦成燕国正芬芳。", "莫把品名闲议拟，且看青凤羽毛长。", "十分领取面前香。"]'),
('song-ci-904','醉花阴','仲殊','宋','宋词','song-ci','醉花阴','[]','轻红蔓引丝多少。',63,'宋词/ci.song.2000.json','["轻红蔓引丝多少。", "剪青兰叶巧。", "人向月中归，留下星钿，弹破真珠小。", "等闲不管春知道。", "多著绣帘围绕。", "只恐被东风，偷得馀香，分付闲花草。"]'),
('song-ci-905','西江月','仲殊','宋','宋词','song-ci','西江月','[]','味过华林芳蒂，色兼阳井沈朱。',58,'宋词/ci.song.2000.json','["味过华林芳蒂，色兼阳井沈朱。", "轻匀绛蜡裹团酥。", "不比人间甘露。", "神鼎十分火枣，龙盘三寸红珠。", "清含冰蜜洗云腴。", "只恐身轻飞去。"]'),
('song-ci-906','玉楼春','仲殊','宋','宋词','song-ci','玉楼春','[]','飞香漠漠帘帷暖。',64,'宋词/ci.song.2000.json','["飞香漠漠帘帷暖。", "一线水沈烟未断。", "红楼西畔小阑干，尽日倚阑人已远。", "黄梅雨入芭蕉晚。", "凤尾翠摇双叶短。", "旧年颜色旧年心，留到如今春不管。"]'),
('song-ci-907','虞美人','仲殊','宋','宋词','song-ci','虞美人','[]','一番雨过年芳浅。',68,'宋词/ci.song.2000.json','["一番雨过年芳浅。", "袅袅心情懒。", "章台人过马嘶声。", "小眉不盏恨盈盈。", "怨清明。", "烟柔露软湖东岸。", "恼乱春风惯。", "一声莺是故园莺。", "及至如今□闻处、又多情。"]'),
('song-ci-908','蓦山溪','仲殊','宋','宋词','song-ci','蓦山溪','[]','黄金线软，玉露声轻润。',102,'宋词/ci.song.2000.json','["黄金线软，玉露声轻润。", "青头破出芽，拂烟痕、一枝犹嫩。", "东风著意，不放舞间□，春渐暖，柔无力，依依怨和□。", "旗亭带晚，又是清明近。", "惹尽别离愁，约啼莺、深深与问。", "灞陵伤感，那更入阳关，扳折处，我无心，行人自多恨。"]'),
('song-ci-909','诉衷情','仲殊','宋','宋词','song-ci','诉衷情','[]','楚江南岸小青楼。',54,'宋词/ci.song.2000.json','["楚江南岸小青楼。", "楼前人檥舟。", "别来后庭花晚，花上梦悠悠。", "山不断，水空流，漫凝眸。", "建康宫殿，燕子来时，多少闲愁。"]'),
('song-ci-910','诉衷情','仲殊','宋','宋词','song-ci','诉衷情','[]','锺山影里看楼台。',54,'宋词/ci.song.2000.json','["锺山影里看楼台。", "江烟晚翠开。", "六朝旧时明月，清夜满秦淮。", "寂寞处，两潮回。", "黯愁怀。", "汀花雨细，水树风闲，又是秋来。"]'),
('song-ci-911','诉衷情','仲殊','宋','宋词','song-ci','诉衷情','["\u897f\u6e56"]','清波门外拥轻衣。',54,'宋词/ci.song.2000.json','["清波门外拥轻衣。", "杨花相送飞。", "西湖又还春晚，水树乱莺啼。", "闲院宇，小帘帏。", "晚初归。", "钟声已过，篆香才点，月到门时。"]'),
('song-ci-912','诉衷情','仲殊','宋','宋词','song-ci','诉衷情','[]','长桥春水拍堤沙。',54,'宋词/ci.song.2000.json','["长桥春水拍堤沙。", "疏雨带残霞。", "几声脆管何处，桥下有人家。", "宫树绿，晚烟斜。", "噪闲鸦。", "山光无尽，水风长在，满面杨花。"]'),
('song-ci-913','诉衷情','仲殊','宋','宋词','song-ci','诉衷情','[]','涌金门外小瀛洲。',54,'宋词/ci.song.2000.json','["涌金门外小瀛洲。", "寒食更风流。", "红船满湖歌吹，花外有高楼。", "晴日暖，淡烟浮。", "恣嬉游。", "三千粉黛，十二阑干，一片云头。"]'),
('song-ci-914','蝶恋花','仲殊','宋','宋词','song-ci','蝶恋花','[]','开到杏花寒食近。',70,'宋词/ci.song.2000.json','["开到杏花寒食近。", "人在花前，宿酒和春困。", "酒有尽时情不尽。", "日长只恁厌厌闷。", "经岁别离闲与问。", "花上啼莺，解道深深恨。", "可惜断云无定准。", "不能为寄蓝桥信。"]'),
('song-ci-915','柳梢青','仲殊','宋','宋词','song-ci','柳梢青','[]','岸草平沙。',61,'宋词/ci.song.2000.json','["岸草平沙。", "吴王故苑，柳袅烟斜。", "雨后寒轻，风前香软，春在梨花。", "行人一棹天涯。", "酒醒处，残阳乱鸦。", "门外秋千，墙头红粉，深院谁家。"]'),
('song-ci-916','夏云峰','仲殊','宋','宋词','song-ci','夏云峰','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','天阔云高，溪横水远。',148,'宋词/ci.song.2000.json','["天阔云高，溪横水远。", "晚日寒生轻晕。", "闲阶静、杨花渐少，朱门掩、莺声犹嫩。", "悔匆匆、过却清明，旋占得馀芳，已成幽恨。", "都几日阴沈，连宵慵困。", "起来韶华都尽。", "怨入双眉闲斗损。", "乍品得情怀，看承全近。", "深深态、无非自许。", "厌厌意、终羞人间。", "争知道、梦里蓬莱，待忘了馀香，时传音信。", "纵留得莺花，东风不住，也则眼前愁闷。"]'),
('song-ci-917','望江南・忆江南','仲殊','宋','宋词','song-ci','望江南・忆江南','[]','成都好，蚕市趁遨游。',64,'宋词/ci.song.2000.json','["成都好，蚕市趁遨游。", "夜放笙歌喧紫陌，春遨灯火上高楼。", "车马溢瀛洲。", "人散后，茧馆喜绸缪。", "柳叶已饶烟黛细，桑条何似玉纤柔。", "立马看风流。"]'),
('song-ci-918','失调名','仲殊','宋','宋词','song-ci','失调名','[]','椒觞献寿瑶觞满。',16,'宋词/ci.song.2000.json','["椒觞献寿瑶觞满。", "采幡儿、轻轻剪。"]'),
('song-ci-919','失调名','仲殊','宋','宋词','song-ci','失调名','[]','柏觞敛滟银幡小。',8,'宋词/ci.song.2000.json','["柏觞敛滟银幡小。"]'),
('song-ci-920','失调名','仲殊','宋','宋词','song-ci','失调名','[]','遥想天孙离别后，一宵欢会，暂停机杼。',18,'宋词/ci.song.2000.json','["遥想天孙离别后，一宵欢会，暂停机杼。"]'),
('song-ci-921','失调名','仲殊','宋','宋词','song-ci','失调名','[]','疏雨洗云轺，望极银河影里。',13,'宋词/ci.song.2000.json','["疏雨洗云轺，望极银河影里。"]'),
('song-ci-922','失调名','仲殊','宋','宋词','song-ci','失调名','[]','玉线金针，千般声笑，月下人家。',15,'宋词/ci.song.2000.json','["玉线金针，千般声笑，月下人家。"]'),
('song-ci-923','失调名','仲殊','宋','宋词','song-ci','失调名','[]','戏马风流，佩茱萸时节。',11,'宋词/ci.song.2000.json','["戏马风流，佩茱萸时节。"]'),
('song-ci-924','望江南・忆江南','仲殊','宋','宋词','song-ci','望江南・忆江南','[]','成都好，药市晏游闲。',64,'宋词/ci.song.2000.json','["成都好，药市晏游闲。", "步出五门鸣剑佩，别登三岛看神仙。", "缥缈结灵烟。", "云影里，歌吹暖霜天。", "何用菊花浮玉醴，愿求朱草化金丹。", "一粒定长年。"]'),
('song-ci-925','南柯子・南歌子','仲殊','宋','宋词','song-ci','南柯子・南歌子','[]','金甃蟠龙尾，莲开舞凤头。',64,'宋词/ci.song.2000.json','["金甃蟠龙尾，莲开舞凤头。", "凉生宫殿不因秋。", "门外莫寻尘世，卷地江流。", "霁色澄千里，潮声带两洲。", "月华轻泛浪花浮。", "今夜蓬莱归梦，十二琼楼。"]'),
('song-ci-926','减字木兰花','仲殊','宋','宋词','song-ci','减字木兰花','[]','山阴道士。',52,'宋词/ci.song.2000.json','["山阴道士。", "鹤目龟趺多秀气。", "右领将军。", "萧散精神一片云。", "东山太傅。", "落落龙骧兼虎步。", "潦倒支公。", "穷骨零丁少道风。"]'),
('song-ci-927','念奴娇','仲殊','宋','宋词','song-ci','念奴娇','[]','故园避暑，爱繁阴翳日，流霞供酌。',120,'宋词/ci.song.2000.json','["故园避暑，爱繁阴翳日，流霞供酌。", "竹影筛金泉漱玉，红映微花帘箔。", "素质生风，香肌无汗，绣扇长闲却。", "双鸾栖处，绿筠时下风箨。", "吹断舞影歌声，阳台人去，有当年池阁。", "佩结兰英凝念久，言语精神依约。", "燕别雕梁，归鸿紫塞，音信凭谁托。", "争知好景，为君长是萧索。"]'),
('song-ci-928','惜双双・惜分飞','仲殊','宋','宋词','song-ci','惜双双・惜分飞','[]','瘐领香前亲写得。',68,'宋词/ci.song.2000.json','["瘐领香前亲写得。", "子细看，粉匀无迹。", "月殿休寻觅。", "姑射人来，知是曾相识。", "不要青春闲用力。", "也曾寄、江南信息。", "著意应难摘。", "留与梨花，比并真颜色。"]'),
('song-ci-929','洞仙歌','仲殊','宋','宋词','song-ci','洞仙歌','[]','广寒晓驾，姑射寻仙侣。',115,'宋词/ci.song.2000.json','["广寒晓驾，姑射寻仙侣。", "偷被霜华送将去。", "过越岭、栖息南枝，匀妆面、凝酥轻聚。", "爱横管、孤度陇头声，尽拼得幽香，为君分付。", "水亭山驿，衰草斜阳，无限行人断肠处。", "尽为我、留得多情，何须待、春风相顾。", "任倒断、深思向梨花，也无奈寒食，几番春雨。"]'),
('song-ci-930','楚宫春慢','仲殊','宋','宋词','song-ci','楚宫春慢','[]','轻盈绛雪。',128,'宋词/ci.song.2000.json','["轻盈绛雪。", "乍团聚同心，千点珠结。", "画馆绣幄低飞，融融香彻。", "笑里精神放纵，断未许、年华偷歇。", "信任芳春都不管，淅淅南熏，别是一家风月。", "扁舟去后，回望处、娃宫凄凉凝咽。", "身似断云零落，深心难说。", "不与雕栏寸地，忍覰著、漂流离缺。", "尽目厌厌总无语，不及高唐梦里，相逢时节。"]'),
('song-ci-931','如梦令','吕本中','宋','宋词','song-ci','如梦令','[]','海雁桥边春苦。',40,'宋词/ci.song.2000.json','["海雁桥边春苦。", "几见落花飞絮。", "重到柳行西，懒问画楼何处。", "凝伫。", "凝伫。", "十顷荷花风雨。"]'),
('song-ci-932','宣州竹・虞美人','吕本中','宋','宋词','song-ci','宣州竹・虞美人','[]','小溪篷底湖风重。',66,'宋词/ci.song.2000.json','["小溪篷底湖风重。", "吹破凝酥动。", "一枝斜映庾门深。", "冷淡无言香泛、月华清。", "已经轻瘦谁为共。", "魂绕徐熙□。", "耻同桃李困春容。", "肯向毫端开发、两云中。"]'),
('song-ci-933','临江仙','毕良史','宋','宋词','song-ci','临江仙','[]','霜月穿帘乍白，苹风入坐偏凉。',68,'宋词/ci.song.2000.json','["霜月穿帘乍白，苹风入坐偏凉。", "麾灯促席诧时光。", "桃花歌扇小，杨柳舞衫长。", "别乘平分风月，词人剩引觥觞。", "莫将幽恨搅刚肠。", "尽添金掌露，频注玉猊香。"]'),
('song-ci-934','好事近','毕良史','宋','宋词','song-ci','好事近','[]','高会罢飞觞。',53,'宋词/ci.song.2000.json','["高会罢飞觞。", "方锦再移珍席。", "雷鼎乍烹甘液，试问侯苍璧。", "翠虬宝钏捧殷勤，明灭粲金碧。", "宾主放怀谈笑，满华堂春色。"]'),
('song-ci-935','小重山','沈晦','宋','宋词','song-ci','小重山','[]','湖上秋来莲荡空。',70,'宋词/ci.song.2000.json','["湖上秋来莲荡空。", "年华都付与，木芙蓉。", "采菱舟子两相逢。", "双媚靥，一笑与谁浓。", "斜日落溟濛。", "鸳鸯飞起处，水无踪。", "望湖楼上两三峰。", "人不见，林外数声钟。"]'),
('song-ci-936','点绛唇','郭章','宋','宋词','song-ci','点绛唇','[]','翠柏丹崖，碧云深锁神仙府。',50,'宋词/ci.song.2000.json','["翠柏丹崖，碧云深锁神仙府。", "势盘龙虎。", "楼观雄中土。", "我欲停时，又恐斜阳暮。", "黄尘路。", "客怀良苦。", "满目西山雨。"]'),
('song-ci-937','酹江月・念奴娇','胡世将','宋','宋词','song-ci','酹江月・念奴娇','[]','神州沈陆，问谁是、一范一韩人物。',120,'宋词/ci.song.2000.json','["神州沈陆，问谁是、一范一韩人物。", "北望长安应不见，抛却关西半壁。", "塞马晨嘶，胡笳夕引，赢得头如雪。", "三秦往事，只数汉家三杰。", "试看百二山河，奈君门万里，六师不发。", "阃外何人回首处，铁骑千群都灭。", "拜将台敧，怀贤阁杳，空指冲冠发。", "阑干拍遍，独对中天明月。"]'),
('song-ci-938','蝶恋花','赵鼎','宋','宋词','song-ci','蝶恋花','[]','一朵江梅春带雪。',70,'宋词/ci.song.2000.json','["一朵江梅春带雪。", "玉软云娇，姑射肌肤洁。", "照影凌波微步怯。", "暗香浮动黄昏月。", "谩道广平心似铁。", "词赋风流，不尽愁千结。", "望断江南音信绝。", "陇头行客空情切。"]'),
('song-ci-939','蝶恋花','赵鼎','宋','宋词','song-ci','蝶恋花','[]','尽日东风吹绿树。',70,'宋词/ci.song.2000.json','["尽日东风吹绿树。", "向晚轻寒，数点催花雨。", "年少凄凉天付与。", "更堪春思萦离绪。", "临水高楼携酒处。", "曾倚哀弦，歌断黄金缕。", "楼下水流何处去。", "凭栏目送苍烟暮。"]'),
('song-ci-940','虞美人','赵鼎','宋','宋词','song-ci','虞美人','[]','魂消目断关山路。',66,'宋词/ci.song.2000.json','["魂消目断关山路。", "曾送雕鞍去。", "而今留滞古陪京。", "还是一尊芳酒、送君行。", "吾庐好在条山曲。", "三径应芜没。", "诛茅为我补东篱。", "会待新春残腊、也来归。"]'),
('song-ci-941','怨春风・一斛珠','赵鼎','宋','宋词','song-ci','怨春风・一斛珠','[]','宝鉴菱花莹。',78,'宋词/ci.song.2000.json','["宝鉴菱花莹。", "孤鸾慵照影。", "鱼书蝶梦两浮沉，恨恨恨。", "结尽丁香，瘦如杨柳，雨疏云冷。", "宿醉厌厌病。", "罗巾空泪粉。", "欲将远意托湘弦，闷闷闷。", "香絮悠悠，画帘悄悄，日长春困。"]'),
('song-ci-942','点绛唇','赵鼎','宋','宋词','song-ci','点绛唇','[]','香冷金炉，梦回鸳帐馀香嫩。',50,'宋词/ci.song.2000.json','["香冷金炉，梦回鸳帐馀香嫩。", "更无人问。", "一枕江南恨。", "消瘦休文，顿觉春衫褪。", "清明近。", "杏花吹尽。", "薄暮东风紧。"]'),
('song-ci-943','人月圆','赵鼎','宋','宋词','song-ci','人月圆','[]','连环宝瑟深深愿，结尽一生愁。',59,'宋词/ci.song.2000.json','["连环宝瑟深深愿，结尽一生愁。", "人间天上，佳期胜赏，今夜中秋。", "雅歌妍态，嫦娥见了，应羡风流。", "芳尊美酒，年年岁岁，月满高楼。"]'),
('song-ci-944','河传','赵鼎','宋','宋词','song-ci','河传','[]','年年桃李。',71,'宋词/ci.song.2000.json','["年年桃李。", "渺关河一梦，飞花空委。", "鸿去燕来，锦字参差难寄。", "敛双眉、山对起。", "娇波泪落妆如洗。", "独倚高楼，日日春风里。", "江水际。", "天色无情，似送离怀千里。"]'),
('song-ci-945','燕归梁','赵鼎','宋','宋词','song-ci','燕归梁','[]','绰约彤霞降紫霄。',60,'宋词/ci.song.2000.json','["绰约彤霞降紫霄。", "是仙子风标。", "湘裙明佩响琼瑶。", "散馥郁、暗香飘。", "小春十月寒犹浅，妆粉弄梅梢。", "秦楼风月待吹箫。", "舞双鹤、醉蟠桃。"]'),
('song-ci-946','减字木兰花','赵鼎','宋','宋词','song-ci','减字木兰花','[]','笔端红翠。',52,'宋词/ci.song.2000.json','["笔端红翠。", "造化工夫春有意。", "云梦涵胸。", "好去蓬山十二重。", "天街追骑。", "催唤谪仙泥样醉。", "电扫云空。", "百斛明珠咳唾中。"]'),
('song-ci-947','好事近','赵鼎','宋','宋词','song-ci','好事近','[]','兰烛画堂深，歌吹已终瑶席。',53,'宋词/ci.song.2000.json','["兰烛画堂深，歌吹已终瑶席。", "碾破密云金缕，送蓬莱归客。", "看看宣诏未央宫，草诏侍宸极。", "拜赐一杯甘露，泛天边春色。"]'),
('song-ci-948','贺圣朝','赵鼎','宋','宋词','song-ci','贺圣朝','[]','断霞收尽黄昏雨。',58,'宋词/ci.song.2000.json','["断霞收尽黄昏雨。", "滴梧桐疏树。", "帘栊不卷夜沈沈，锁一庭风露。", "天涯人远，心期梦悄，苦长宵难度。", "知他窗外促织儿，有许多言语。"]'),
('song-ci-949','乌夜啼','赵鼎','宋','宋词','song-ci','乌夜啼','[]','檐花点滴秋清。',45,'宋词/ci.song.2000.json','["檐花点滴秋清。", "寸心惊。", "香断一炉沈水、一灯青。", "凉宵永。", "孤衾冷。", "梦难成。", "叶叶高梧敲恨、送残更。"]'),
('song-ci-950','浣溪沙','赵鼎','宋','宋词','song-ci','浣溪沙','[]','艳艳春娇入眼波。',48,'宋词/ci.song.2000.json','["艳艳春娇入眼波。", "劝人金盏缓声歌。", "不禁粉泪搵香罗。", "暮雨朝云相见少，落花流水别离多。", "寸肠争奈此情何。"]'),
('song-ci-951','画堂春','赵鼎','宋','宋词','song-ci','画堂春','[]','空笼帘影隔垂杨。',55,'宋词/ci.song.2000.json','["空笼帘影隔垂杨。", "梦回芳草池塘。", "杏花枝上蝶双双。", "春昼初长。", "强理云鬟临照，暗弹粉泪沾裳。", "自怜容艳惜流光。", "无限思量。"]'),
('song-ci-952','浪淘沙','赵鼎','宋','宋词','song-ci','浪淘沙','[]','归计信悠悠。',64,'宋词/ci.song.2000.json','["归计信悠悠。", "归去谁留。", "梦随江水绕沙洲。", "沙上孤鸿犹笑我，萍梗飘流。", "与世且沈浮。", "要便归休。", "一杯消尽一生愁。", "傥有人来闲论事，我会摇头。"]'),
('song-ci-953','水调歌头','赵鼎','宋','宋词','song-ci','水调歌头','[]','屋下疏流水，屋上列青山。',114,'宋词/ci.song.2000.json','["屋下疏流水，屋上列青山。", "先生跨鹤何处，窈窕白云间。", "采药当年三径，只有长松绿竹，霜吹晚萧然。", "举酒高台上，彷佛揖群仙。", "转银汉，飞宝鉴，溢清寒。", "金波万顷不动，人在玉壶宽。", "我唱君须起舞，要把嫦娥留住，相送一杯残。", "醉矣拂衣去，一笑渺人寰。"]'),
('song-ci-954','双翠羽','赵鼎','宋','宋词','song-ci','双翠羽','[]','小园曲径，度疏林深处，幽兰微馥。',120,'宋词/ci.song.2000.json','["小园曲径，度疏林深处，幽兰微馥。", "竹坞无人双翠羽，飞触珊珊寒玉。", "更欲题诗，晚来孤兴，却恐伤幽独。", "不如花下，一尊芳酒相属。", "慨念故国风流，杨花春梦短，黄粱初熟。", "卷白千觞须劝我，洗此胸中荣辱。", "醉揖南山，一声清啸，休把离骚读。", "迟留归去，月明犹挂乔木。"]'),
('song-ci-955','河传','赵鼎','宋','宋词','song-ci','河传','[]','秋光向晚。',75,'宋词/ci.song.2000.json','["秋光向晚。", "叹羁游坐见。", "年华将换。", "一纸素书，拟托南来征雁。", "奈雪深、天更远。", "东窗皓月今宵满。", "浅酌芳尊，暂倩嫦娥伴。", "应念夜长，旅枕孤衾不暖。", "便莫教、清影转。"]'),
('song-ci-956','满江红','赵鼎','宋','宋词','song-ci','满江红','["\u957f\u6c5f"]','惨结秋阴，西风送、霏霏雨湿。',117,'宋词/ci.song.2000.json','["惨结秋阴，西风送、霏霏雨湿。", "凄望眼、征鸿几字，暮投沙碛。", "试问乡关何处是，水云浩荡迷南北。", "但一抹、寒青有无中，遥山色。", "天涯路，江上客。", "肠欲断，头应白。", "空搔首兴欢，暮年离拆。", "须信道消忧除是酒，奈酒行有尽情无极。", "便挽取、长江入尊罍，浇胸臆。"]'),
('song-ci-957','鹧鸪天','赵鼎','宋','宋词','song-ci','鹧鸪天','[]','客路那知岁序移。',64,'宋词/ci.song.2000.json','["客路那知岁序移。", "忽惊春到小桃枝。", "天涯海角悲凉地，记得当年全盛时。", "花弄影，月流辉。", "水精宫殿五云飞。", "分明一觉华胥梦，回首东风泪满衣。"]'),
('song-ci-958','浣溪沙','赵鼎','宋','宋词','song-ci','浣溪沙','[]','惜别怀归老不禁。',56,'宋词/ci.song.2000.json','["惜别怀归老不禁。", "一年春事柳阴阴。", "日下长安何处是，碧云深。", "已恨梅花疏远信，休传桃叶怨遗音。", "一醉东风分首去，两惊心。"]'),
('song-ci-959','如梦令','赵鼎','宋','宋词','song-ci','如梦令','[]','烟雨满江风细。',40,'宋词/ci.song.2000.json','["烟雨满江风细。", "江上危楼独倚。", "歌罢楚云空，楼下依前流水。", "迢递。", "迢递。", "目送孤鸿千里。"]'),
('song-ci-960','好事近','赵鼎','宋','宋词','song-ci','好事近','[]','杨柳曲江头，曾记彩舟良夕。',53,'宋词/ci.song.2000.json','["杨柳曲江头，曾记彩舟良夕。", "一枕楚台残梦，似行云无迹。", "青山迢递水悠悠，何处问消息。", "还是一年春暮，倚东风独立。"]'),
('song-ci-961','点绛唇','赵鼎','宋','宋词','song-ci','点绛唇','[]','惜别伤离，此生此念无重数。',50,'宋词/ci.song.2000.json','["惜别伤离，此生此念无重数。", "故人何处。", "还送春归去。", "美酒一杯，谁解歌金缕。", "无情绪。", "淡烟疏雨。", "花落空庭暮。"]'),
('song-ci-962','相思令・相思儿令','赵鼎','宋','宋词','song-ci','相思令・相思儿令','[]','归去来。',44,'宋词/ci.song.2000.json','["归去来。", "归去来。", "昨夜东风吹梦回。", "家山安在哉。", "酒一杯。", "复一杯。", "准拟愁怀待酒开。", "愁多肠九回。"]'),
('song-ci-963','望海潮','赵鼎','宋','宋词','song-ci','望海潮','[]','双峰遥促，回波奔注，茫茫溅雨飞沙。',129,'宋词/ci.song.2000.json','["双峰遥促，回波奔注，茫茫溅雨飞沙。", "霜凛剑戈，风生阵马，如闻万鼓齐挝。", "儿戏笑夫差。", "漫水犀强弩，一战鱼虾。", "依旧群龙，怒卷银汉下天涯。", "雷驱电炽雄夸。", "似云垂鹏背，雪喷鲸牙。", "须臾变灭，天容水色，琼田万顷无瑕。", "俗眼但惊嗟。", "试望中彷佛，三岛烟霞。", "旧隐依然，几时归去泛灵槎。"]'),
('song-ci-964','花心动','赵鼎','宋','宋词','song-ci','花心动','[]','江月初升，听悲风、萧瑟满山零叶。',126,'宋词/ci.song.2000.json','["江月初升，听悲风、萧瑟满山零叶。", "夜久酒阑，火冷灯青，奈此愁怀千结。", "绿琴三叹朱弦绝，与谁唱、阳春白雪。", "但遐想、穷年坐对，断编遗册。", "西北搀枪未灭。", "千万乡关，梦遥吴越。", "慨念少年，横槊风流，醉瞻海涵天阔。", "老来身世疏篷底，忍憔悴、看人颜色。", "更何似、归与枕流漱石。"]'),
('song-ci-965','洞仙歌','赵鼎','宋','宋词','song-ci','洞仙歌','[]','空山雨过，月色浮新酿。',101,'宋词/ci.song.2000.json','["空山雨过，月色浮新酿。", "把盏无人共心赏。", "漫悲吟、独自拈断霜须，还就寝、秋入孤衾渐爽。", "可怜窗外竹，不怕西风，一夜潇潇弄疏响。", "奈此九回肠，万斛清愁，人何处、邈如天样。", "纵陇水、秦云阻归音，便不许时闲，梦中寻访。"]'),
('song-ci-966','乌夜啼','赵鼎','宋','宋词','song-ci','乌夜啼','[]','雨馀风露凄然。',45,'宋词/ci.song.2000.json','["雨馀风露凄然。", "月流天。", "还是年时今夜、照关山。", "收别泪。", "持杯起。", "问婵娟。", "问我扁舟流荡、几时还。"]'),
('song-ci-967','满庭芳','赵鼎','宋','宋词','song-ci','满庭芳','[]','靡靡流光，凄凄风露，小园草木初凋。',118,'宋词/ci.song.2000.json','["靡靡流光，凄凄风露，小园草木初凋。", "杳然尘影，爽气界天高。", "爱此佳名重九，随宜对、秋菊持醪。", "登临处，哀蝉断响，燕雁度云霄。", "闲谣。", "情缅邈，相寻万化，人世徒劳。", "念胸中百虑，何物能消。", "欲致颓龄不老，和金茎、一醉陶陶。", "君休问，千年事往，聊与永今朝。"]'),
('song-ci-968','好事近','赵鼎','宋','宋词','song-ci','好事近','[]','春色遍天涯，寒谷未知消息。',53,'宋词/ci.song.2000.json','["春色遍天涯，寒谷未知消息。", "且共一尊芳酒，看东风飞雪。", "太平遗老洞霄翁，相对两华发。", "一任醉魂飞去，访琼瑶宫阙。"]'),
('song-ci-969','好事近','赵鼎','宋','宋词','song-ci','好事近','[]','羁旅转飞蓬，投老未知休息。',53,'宋词/ci.song.2000.json','["羁旅转飞蓬，投老未知休息。", "却念故园春事，舞残红飞雪。", "危楼高处望天涯，云海寄穷发。", "只有旧时凉月，照清伊双阙。"]'),
('song-ci-970','好事近','赵鼎','宋','宋词','song-ci','好事近','[]','一炷鼻端香，方寸浪平风息。',53,'宋词/ci.song.2000.json','["一炷鼻端香，方寸浪平风息。", "汲取玉池春水，点红炉微雪。", "年来都以酒相妨，进退只毫发。", "却道醉乡深处，是三山神阙。"]'),
('song-ci-971','好事近','赵鼎','宋','宋词','song-ci','好事近','[]','烟雾锁青冥，直上九关一息。',53,'宋词/ci.song.2000.json','["烟雾锁青冥，直上九关一息。", "姑射有人相挽，莹肌肤冰雪。", "骑鲸却下大荒来，天风乱吹发。", "慨念故人非是，漫尘埃城阙。"]');
